'use server'

import { createClient } from '@supabase/supabase-js'

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
const supabase = createClient(supabaseUrl, supabaseKey)

export async function checkAndAwardBadges(userId: string) {
    const awardedBadges: any[] = []

    try {
        // 1. Get user's current badges
        const { data: userBadges } = await supabase
            .from('user_badges')
            .select('badge_id, badges(condition)')
            .eq('user_id', userId)

        const existingConditions = new Set(
            userBadges?.map(ub => (ub.badges as any)?.condition).filter(Boolean) || []
        )

        // 2. Fetch all available badges to know their IDs and conditions
        const { data: allBadges } = await supabase.from('badges').select('*')
        if (!allBadges) return []

        const newAwards = []

        // --- Condition Checkers ---

        // Check "10 Partidos" (10_reviews)
        if (!existingConditions.has('10_reviews')) {
            const { count } = await supabase
                .from('match_logs')
                .select('*', { count: 'exact', head: true })
                .eq('user_id', userId)

            if (count && count >= 10) {
                const badge = allBadges.find(b => b.condition === '10_reviews')
                if (badge) newAwards.push(badge)
            }
        }

        // Check "Voz de la Hinchada" (50_live_chat)
        if (!existingConditions.has('50_live_chat')) {
            const { count } = await supabase
                .from('partido_comments')
                .select('*', { count: 'exact', head: true })
                .eq('user_id', userId)

            if (count && count >= 50) {
                const badge = allBadges.find(b => b.condition === '50_live_chat')
                if (badge) newAwards.push(badge)
            }
        }
        
        // Check "Prodista" (10_prode_exactos)
        if (!existingConditions.has('10_prode_exactos')) {
             const { data: ranking } = await supabase
                .from('ranking_prode')
                .select('aciertos_exactos')
                .eq('user_id', userId)
                
             const stats = ranking?.reduce((acc, curr) => acc + (curr.aciertos_exactos || 0), 0) || 0;
             if (stats >= 10) {
                 const badge = allBadges.find(b => b.condition === '10_prode_exactos')
                 if (badge) newAwards.push(badge)
             }
        }

        // --- Award Badges ---
        for (const badge of newAwards) {
            // Insert into user_badges
            const { error: insertError } = await supabase
                .from('user_badges')
                .insert({ user_id: userId, badge_id: badge.id })

            if (!insertError && badge.xp_reward > 0) {
                const { error: rpcError } = await supabase.rpc('increment_profile_xp', {
                    p_user_id: userId,
                    p_amount: badge.xp_reward
                })

                if (rpcError) {
                    const { data: profile } = await supabase
                        .from('profiles')
                        .select('xp')
                        .eq('id', userId)
                        .single()
                    if (profile) {
                        await supabase
                            .from('profiles')
                            .update({ xp: profile.xp + badge.xp_reward })
                            .eq('id', userId)
                    }
                }

                awardedBadges.push(badge)
            }
        }

        return awardedBadges
    } catch (error) {
        console.error('Error in checkAndAwardBadges:', error)
        return []
    }
}

// src/app/actions/football.ts
'use server'

import { getStandings, getTopScorers, getFixtures, getFixtureById, getRounds, getFixturesByRound } from '@/lib/api'
import { scrapeFixtures, scrapeStandings, scrapeTopScorers } from '@/lib/scraper'
import { fetchPublicFixtures, fetchPublicStandings, fetchPublicScorers } from '@/lib/football-data'
import { LIGAS_MAP, CURRENT_SEASONS } from '@/lib/constants'
import type { ApiLeagueResponse, ApiFixture } from '@/types/api'
import type { Partido } from '@/types'

// Determine correct season for API-Football based on league region
const EUROPEAN_LEAGUES = ['La Liga', 'Premier League', 'Serie A', 'Bundesliga', 'Ligue 1', 'Champions League']
const SA_LEAGUES = ['Liga Profesional', 'Primera Nacional', 'Copa Libertadores', 'Copa Sudamericana', 'Brasileirão']

function getSeasonForLeague(ligaName: string): number {
    if (ligaName === 'MLS') return CURRENT_SEASONS.MLS
    if (ligaName === 'Brasileirão') return CURRENT_SEASONS.BRAZIL
    if (EUROPEAN_LEAGUES.includes(ligaName)) return CURRENT_SEASONS.EUROPE
    return CURRENT_SEASONS.ARGENTINA
}

export async function fetchStandingsAction(ligaName: string) {
    // 1. Try football-data.org first (New preferred public source)
    try {
        const data = await fetchPublicStandings(ligaName)
        if (data && data.length > 0) return data
    } catch (e) {
        console.error('Error fetching from football-data:', e)
    }

    // 2. Try scraper second (current season, free)
    try {
        const scraped = await scrapeStandings(ligaName)
        if (scraped && scraped.length > 0) return scraped
    } catch {
        // Silent fallback to API-Football
    }

    // Fallback to API-Football
    const leagueId = LIGAS_MAP[ligaName]
    if (!leagueId) throw new Error('Liga no soportada')

    const season = getSeasonForLeague(ligaName)
    const data = await getStandings(leagueId, season) as unknown as ApiLeagueResponse[]

    if (Array.isArray(data) && data.length > 0 && data[0]?.league?.standings) {
        return data[0].league.standings[0]
    }

    return []
}

export async function fetchTopScorersAction(ligaName: string) {
    // 1. Try football-data.org first
    try {
        const data = await fetchPublicScorers(ligaName)
        if (data && data.length > 0) return data
    } catch (e) {
        console.error('Error fetching scorers from football-data:', e)
    }

    // 2. Try scraper second
    try {
        const scraped = await scrapeTopScorers(ligaName)
        if (scraped && Array.isArray(scraped) && scraped.length > 0) return scraped
    } catch {
        // Silent fallback
    }

    // Fallback to API-Football
    const leagueId = LIGAS_MAP[ligaName]
    if (!leagueId) return []

    const season = getSeasonForLeague(ligaName)
    const data = await getTopScorers(leagueId, season)
    return data || []
}

export async function fetchFixturesAction(ligaName: string) {
    // 1. Try football-data.org first
    try {
        const data = await fetchPublicFixtures(ligaName)
        if (data && data.length > 0) {
            return data.sort((a, b) =>
                new Date(a.fecha_inicio).getTime() - new Date(b.fecha_inicio).getTime()
            )
        }
    } catch (e) {
        console.error('Error fetching fixtures from football-data:', e)
    }

    // 2. Try scraper second
    try {
        const scraped = await scrapeFixtures(ligaName)
        if (scraped && scraped.length > 0) {
            return scraped.sort((a, b) =>
                new Date(a.fecha_inicio).getTime() - new Date(b.fecha_inicio).getTime()
            )
        }
    } catch {
        // Silent fallback
    }

    // Fallback to API-Football
    const leagueId = LIGAS_MAP[ligaName]
    if (!leagueId) return []

    const season = getSeasonForLeague(ligaName)

    const today = new Date()
    const past = new Date(today)
    past.setDate(today.getDate() - 15)
    const future = new Date(today)
    future.setDate(today.getDate() + 15)

    const from = past.toISOString().split('T')[0]
    const to = future.toISOString().split('T')[0]

    let data = await getFixtures(leagueId, season, from, to)

    // If no fixtures in current date range, fetch last rounds
    if (!data || data.length === 0) {
        const rounds = await getRounds(leagueId, season)
        if (rounds && rounds.length > 0) {
            const lastRounds = rounds.slice(-3)
            const roundPromises = lastRounds.map(round =>
                getFixturesByRound(leagueId, season, round).catch(() => null)
            )
            const roundResults = await Promise.all(roundPromises)
            data = roundResults
                .filter((r): r is ApiFixture[] => r !== null)
                .flat()
        }
    }

    if (!data) return []

    return data
        .map(item => adaptApiFixtureToPartido(item))
        .sort((a, b) => new Date(b.fecha_inicio).getTime() - new Date(a.fecha_inicio).getTime())
}

export async function fetchFixtureByIdAction(id: number): Promise<Partido | null> {
    // 1. Attempt to find it quickly in public data (Football-Data API)
    try {
        const publicFixtures = await fetchPublicFixtures('Liga Profesional')
        if (publicFixtures) {
            const match = publicFixtures.find(f => f.fixture_id === id)
            if (match) return match
        }
    } catch {}

    // 2. Attempt to find it in the robust scraped data cache
    try {
        const scraped = await scrapeFixtures('Liga Profesional')
        if (scraped) {
            const match = scraped.find(f => f.fixture_id === id)
            if (match) return match
        }
    } catch {}

    // 3. Absolute fallback to API-Football fetching
    try {
        const data = await getFixtureById(id)
        if (data) return adaptApiFixtureToPartido(data)
    } catch (e) {
        console.error('API-Football fallback failure for ID', id, e)
    }
    
    return null
}

export async function fetchPlayerByIdAction(id: number, season: number = 2024) {
    const { getPlayerById } = await import('@/lib/api')
    return getPlayerById(id, season)
}


function adaptApiFixtureToPartido(item: ApiFixture): Partido {
    return {
        id: item.fixture.id,
        liga: item.league.name,
        equipo_local: item.teams.home.name,
        equipo_visitante: item.teams.away.name,
        fecha_inicio: item.fixture.date,
        estado: mapStatusToState(item.fixture.status.short),
        goles_local: item.goals.home ?? undefined,
        goles_visitante: item.goals.away ?? undefined,
        logo_local: item.teams.home.logo,
        logo_visitante: item.teams.away.logo,
        fixture_id: item.fixture.id
    }
}

// Admin: Update match score
export async function updateMatchScoreAction(partidoId: number, golesLocal: number, golesVisitante: number) {
    const { createClient } = await import('@supabase/supabase-js')
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
    const supabase = createClient(supabaseUrl, supabaseKey)

    const { error } = await supabase
        .from('partidos')
        .update({
            goles_local: golesLocal,
            goles_visitante: golesVisitante,
            estado: 'FINALIZADO',
        })
        .eq('id', partidoId)

    if (error) throw new Error(error.message)
    return { success: true }
}

/**
 * Fetch fixtures AND sync them to Supabase (for Prode).
 */
export async function fetchFixturesWithSyncAction(ligaName: string): Promise<Partido[]> {
    const { syncPartidosToSupabase } = await import('./syncPartidos')
    const scraped = await fetchFixturesAction(ligaName)
    if (!scraped || scraped.length === 0) return []

    try {
        const synced = await syncPartidosToSupabase(scraped)
        if (synced && synced.length > 0) {
            return synced.sort((a, b) =>
                new Date(a.fecha_inicio).getTime() - new Date(b.fecha_inicio).getTime()
            )
        }
    } catch {
        // Fallback: return scraped data without Supabase UUIDs
    }

    return scraped
}

function mapStatusToState(status: string): 'PREVIA' | 'EN_JUEGO' | 'FINALIZADO' {
    if (['NS', 'TBD'].includes(status)) return 'PREVIA'
    if (['FT', 'AET', 'PEN'].includes(status)) return 'FINALIZADO'
    return 'EN_JUEGO'
}

'use server'

export async function fetchTyCNewsAction() {
    try {
        const controller = new AbortController()
        const timeoutId = setTimeout(() => controller.abort(), 8000)

        const res = await fetch('https://www.tycsports.com/rss/futbol.xml', {
            signal: controller.signal,
            next: { revalidate: 300 } // Cachear por 5 minutos
        })

        clearTimeout(timeoutId)

        if (!res.ok) throw new Error(`TyC RSS failed with status ${res.status}`)

        const xmlText = await res.text()

        if (!xmlText.includes('<item>')) {
             throw new Error('Invalid RSS format: No items found')
        }

        // Un parseo de XML muy básico pero eficiente para no instalar dependencias
        const items = xmlText.split('<item>').slice(1) // Ignorar el header del channel

        const parsedItems = items.map(item => {
            const title = item.match(/<title><!\[CDATA\[(.*?)\]\]><\/title>/)?.[1] || item.match(/<title>(.*?)<\/title>/)?.[1] || 'Sin Título'
            const link = item.match(/<link>(.*?)<\/link>/)?.[1] || '#'
            const descriptionCdata = item.match(/<description><!\[CDATA\[(.*?)\]\]><\/description>/)?.[1] || item.match(/<description>(.*?)<\/description>/)?.[1] || ''
            const pubDate = item.match(/<pubDate>(.*?)<\/pubDate>/)?.[1] || new Date().toUTCString()

            // TyC usa enclosure para la imagen
            const enclosureMatch = item.match(/<enclosure[^>]+url="([^"]+)"/)
            const thumbnail = enclosureMatch ? enclosureMatch[1] : ''

            return {
                title: title.trim(),
                link: link.trim(),
                description: descriptionCdata.replace(/<[^>]*>?/gm, '').trim(),
                pubDate,
                thumbnail
            }
        })

        if (parsedItems.length === 0) {
            throw new Error('Parsed items array is empty')
        }

        return parsedItems
    } catch (e: any) {
        console.error("Error in fetchTyCNewsAction:", e.message || e)
        throw new Error(`Failed to fetch news: ${e.message || 'Unknown error'}`)
    }
}

// src/app/actions/syncPartidos.ts
'use server'

import { createClient } from '@supabase/supabase-js'
import type { Partido } from '@/types'
import { scrapeSofascoreLiveEvents, normalizeTeamName } from '@/lib/scraper_sofascore'

// Use service role to bypass RLS for upserts
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!

const supabaseAdmin = createClient(supabaseUrl, supabaseKey, {
    auth: { autoRefreshToken: false, persistSession: false }
})

/**
 * Upserts partidos from the scraper into Supabase using fixture_id as the conflict key.
 * Returns the partidos with their Supabase UUIDs.
 */
export async function syncPartidosToSupabase(
    scrapedPartidos: Omit<Partido, 'created_at'>[]
): Promise<Partido[]> {
    if (!scrapedPartidos || scrapedPartidos.length === 0) return []

    const rows = scrapedPartidos
        .map(p => {
            // Prefer fixture_id if explicit, otherwise try to parse id as a number
            const fixtureId = p.fixture_id
                ? (typeof p.fixture_id === 'number' ? p.fixture_id : parseInt(String(p.fixture_id)))
                : (typeof p.id === 'number' ? p.id : parseInt(String(p.id)))

            // Skip entries where we can't get a valid numeric fixture_id
            if (isNaN(fixtureId) || fixtureId <= 0) return null

            return {
                fixture_id: fixtureId,
                liga: p.liga,
                equipo_local: p.equipo_local,
                equipo_visitante: p.equipo_visitante,
                fecha_inicio: p.fecha_inicio,
                estado: p.estado || 'PREVIA',
                goles_local: p.goles_local ?? null,
                goles_visitante: p.goles_visitante ?? null,
                logo_local: p.logo_local || '',
                logo_visitante: p.logo_visitante || '',
            }
        })
        .filter((r): r is NonNullable<typeof r> => r !== null)

    const BATCH_SIZE = 50
    const allUpserted: Partido[] = []

    for (let i = 0; i < rows.length; i += BATCH_SIZE) {
        const batch = rows.slice(i, i + BATCH_SIZE)

        const { data, error } = await supabaseAdmin
            .from('partidos')
            .upsert(batch, { onConflict: 'fixture_id' })
            .select('*')

        if (error) {
            console.error('[SyncPartidos] Upsert error:', error.message)
            break
        }

        if (data) {
            allUpserted.push(...data as Partido[])
        }
    }

    if (allUpserted.length > 0) {
        return allUpserted
    }

    const fixtureIds = rows.map(r => r.fixture_id)
    const { data: existing } = await supabaseAdmin
        .from('partidos')
        .select('*')
        .in('fixture_id', fixtureIds)

    return (existing as Partido[]) || []
}

/**
 * Fetches live scores from SofaScore and updates matches in the database
 * that are currently 'EN_JUEGO' or 'PREVIA' happening today.
 */
export async function syncLivePartidosToSupabase() {
    const liveEvents = await scrapeSofascoreLiveEvents()
    if (!liveEvents || liveEvents.length === 0) return { updated: 0 }

    // Get active matches from Supabase
    const { data: activeMatches } = await supabaseAdmin
        .from('partidos')
        .select('id, equipo_local, equipo_visitante, estado, goles_local, goles_visitante')
        .in('estado', ['PREVIA', 'EN_JUEGO'])

    if (!activeMatches || activeMatches.length === 0) return { updated: 0 }

    const updates: any[] = []

    for (const match of activeMatches) {
        const normLocalDb = normalizeTeamName(match.equipo_local)
        const normVisitanteDb = normalizeTeamName(match.equipo_visitante)

        // Find matching live event
        const liveEvent = liveEvents.find(e => {
            const normLocalLive = normalizeTeamName(e.homeTeam.name)
            const normShortLocalLive = normalizeTeamName(e.homeTeam.shortName || '')
            const normVisitanteLive = normalizeTeamName(e.awayTeam.name)
            const normShortVisitanteLive = normalizeTeamName(e.awayTeam.shortName || '')

            // Match if either long or short names match
            const homeMatches = normLocalDb.includes(normLocalLive) || normLocalLive.includes(normLocalDb) ||
                (normShortLocalLive && (normLocalDb.includes(normShortLocalLive) || normShortLocalLive.includes(normLocalDb)))

            const awayMatches = normVisitanteDb.includes(normVisitanteLive) || normVisitanteLive.includes(normVisitanteDb) ||
                (normShortVisitanteLive && (normVisitanteDb.includes(normShortVisitanteLive) || normShortVisitanteLive.includes(normVisitanteDb)))

            return homeMatches && awayMatches
        })

        if (liveEvent) {
            let newState = match.estado
            const statusCode = liveEvent.status.code

            // Map SofaScore status codes to FutLog states
            // > 0 usually means in progress, 100 is ended
            if (statusCode === 100) newState = 'FINALIZADO'
            else if (statusCode > 0 && statusCode < 100) newState = 'EN_JUEGO'

            const newGolesLocal = liveEvent.homeScore.current ?? liveEvent.homeScore.display ?? match.goles_local
            const newGolesVisitante = liveEvent.awayScore.current ?? liveEvent.awayScore.display ?? match.goles_visitante

            if (
                match.estado !== newState ||
                match.goles_local !== newGolesLocal ||
                match.goles_visitante !== newGolesVisitante
            ) {
                updates.push({
                    id: match.id,
                    estado: newState,
                    goles_local: newGolesLocal,
                    goles_visitante: newGolesVisitante,
                })
            }
        }
    }

    if (updates.length > 0) {
        for (const update of updates) {
            await supabaseAdmin
                .from('partidos')
                .update({
                    estado: update.estado,
                    goles_local: update.goles_local,
                    goles_visitante: update.goles_visitante
                })
                .eq('id', update.id)
        }
    }

    return { updated: updates.length }
}

import { NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import { getFixturesByDate } from '@/lib/api'
import { LIGAS_MAP, CURRENT_SEASONS } from '@/lib/constants'
import type { ApiFixture } from '@/types/api'

// Inicializar Supabase Admin client (bypass RLS)
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!

const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey, {
    auth: {
        autoRefreshToken: false,
        persistSession: false
    }
})

export const dynamic = 'force-dynamic' // No cachear

export async function GET(request: Request) {
    try {
        // 1. Validar autorización
        const authHeader = request.headers.get('authorization')
        if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
        }

        const today = new Date().toISOString().split('T')[0] // 'YYYY-MM-DD'
        let updatedCount = 0
        const errors: string[] = []

        // 2. Iterar por cada liga configurada
        for (const [nombreLiga, idLiga] of Object.entries(LIGAS_MAP)) {
            const season = nombreLiga === 'Liga Profesional' || nombreLiga === 'Primera Nacional'
                ? CURRENT_SEASONS.ARGENTINA
                : CURRENT_SEASONS.EUROPE

            console.log(`Buscando partidos para ${nombreLiga} fecha ${today}...`)

            const fixtures = await getFixturesByDate(idLiga, season, today)

            if (!fixtures || fixtures.length === 0) {
                console.log(`No hay partidos para ${nombreLiga} hoy.`)
                continue
            }

            // 3. Procesar partidos finalizados (FT, AET, PEN)
            const finishedFixtures = fixtures.filter((f: ApiFixture) =>
                ['FT', 'AET', 'PEN'].includes(f.fixture.status.short)
            )

            for (const fixture of finishedFixtures) {
                try {
                    // Intentar actualizar por fixture_id o matching inteligente
                    const { data: existingMatch } = await supabaseAdmin
                        .from('partidos')
                        .select('id, fixture_id')
                        .or(`fixture_id.eq.${fixture.fixture.id},and(equipo_local.ilike.%${fixture.teams.home.name}%,equipo_visitante.ilike.%${fixture.teams.away.name}%)`)
                        .maybeSingle()

                    if (existingMatch) {
                        // Actualizar marcador y estado
                        const { error } = await supabaseAdmin
                            .from('partidos')
                            .update({
                                goles_local: fixture.goals.home,
                                goles_visitante: fixture.goals.away,
                                estado: 'FINALIZADO',
                                fixture_id: fixture.fixture.id // Self-healing: guardar ID si no estaba
                            })
                            .eq('id', existingMatch.id)

                        if (!error) {
                            updatedCount++
                            console.log(`Partido actualizado: ${fixture.teams.home.name} vs ${fixture.teams.away.name}`)
                        } else {
                            errors.push(`Error actualizando ${fixture.fixture.id}: ${error.message}`)
                        }
                    }
                } catch (err: any) {
                    if (err instanceof Error) {
                        errors.push(`Error procesando fixture ${fixture.fixture.id}: ${err.message}`)
                    }
                }
            }
        }

        return NextResponse.json({
            success: true,
            updated: updatedCount,
            errors: errors.length > 0 ? errors : undefined
        })

    } catch (error) {
        console.error('Cron Error:', error)
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 })
    }
}

// src/app/api/partido/[id]/events/route.ts
import { NextRequest, NextResponse } from 'next/server'

const API_KEY = process.env.API_FOOTBALL_KEY
const API_URL = 'https://v3.football.api-sports.io'

interface FixtureEvent {
    time: { elapsed: number; extra: number | null }
    team: { id: number; name: string; logo: string }
    player: { id: number; name: string }
    assist: { id: number | null; name: string | null }
    type: string      // "Goal", "Card", "subst", "Var"
    detail: string    // "Normal Goal", "Yellow Card", "Red Card", "Substitution 1", etc.
    comments: string | null
}

export async function GET(
    request: NextRequest,
    { params }: { params: Promise<{ id: string }> }
) {
    const { id } = await params

    if (!API_KEY || id.startsWith('mock-')) {
        if (id.startsWith('mock-')) {
            const events = [
                { minuto: 12, tipo: 'gol', jugador: 'Lionel Messi', asistencia: 'Pedri', equipo: 'FC Barcelona', detalle: 'Normal Goal' },
                { minuto: 45, tipo: 'amarilla', jugador: 'Vinicius Jr', equipo: 'Real Madrid', detalle: 'Yellow Card' },
            ]

            if (id.includes('live') || id.includes('fin')) {
                events.push(
                    { minuto: 67, tipo: 'gol', jugador: 'Robert Lewandowski', asistencia: 'Gündogan', equipo: 'FC Barcelona', detalle: 'Normal Goal' },
                    { minuto: 82, tipo: 'roja', jugador: 'Sergio Ramos', equipo: 'Real Madrid', detalle: 'Red Card' }
                )
            }

            return NextResponse.json({ events: timelineFromMock(events) })
        }
        return NextResponse.json({ events: [] })
    }

    try {
        const res = await fetch(`${API_URL}/fixtures/events?fixture=${id}`, {
            headers: {
                'x-apisports-key': API_KEY,
                'x-rapidapi-host': 'v3.football.api-sports.io',
            },
            next: { revalidate: 120 },
        })

        if (!res.ok) {
            return NextResponse.json({ events: [] })
        }

        const data = await res.json()
        const events: FixtureEvent[] = data.response || []

        // Transform to clean format
        const timeline = events.map(e => ({
            minuto: e.time.elapsed + (e.time.extra ? `+${e.time.extra}` : ''),
            tipo: mapEventType(e.type, e.detail),
            jugador: e.player?.name || '',
            asistencia: e.assist?.name || null,
            equipo: e.team?.name || '',
            equipoLogo: e.team?.logo || '',
            detalle: e.detail,
            comentario: e.comments,
        }))

        return NextResponse.json({ events: timeline })
    } catch {
        return NextResponse.json({ events: [] })
    }
}

function timelineFromMock(events: any[]) {
    return events.map(e => ({
        ...e,
        equipoLogo: e.equipo.includes('Madrid') ? 'https://media.api-sports.io/football/teams/541.png' : 'https://media.api-sports.io/football/teams/529.png',
        comentario: null
    }))
}

function mapEventType(type: string, detail: string): string {
    if (type === 'Goal') {
        if (detail.includes('Penalty')) return 'penalty'
        if (detail.includes('Own')) return 'gol_en_contra'
        return 'gol'
    }
    if (type === 'Card') {
        if (detail.includes('Red')) return 'roja'
        if (detail.includes('Second')) return 'amarilla_roja'
        return 'amarilla'
    }
    if (type === 'subst') return 'cambio'
    if (type === 'Var') return 'var'
    return 'otro'
}

import { NextResponse } from 'next/server'

export async function POST(request: Request) {
    try {
        const { userId, title, message, url, type, data } = await request.json()

        if (!userId) {
            return NextResponse.json({ error: 'Missing userId' }, { status: 400 })
        }

        const appId = process.env.NEXT_PUBLIC_ONESIGNAL_APP_ID
        const restApiKey = process.env.ONESIGNAL_REST_API_KEY

        if (!appId || !restApiKey) {
            return NextResponse.json({
                error: 'OneSignal configuration missing (App ID or REST API Key)',
                details: { appId: !!appId, restApiKey: !!restApiKey }
            }, { status: 500 })
        }

        const body = {
            app_id: appId,
            include_external_user_ids: [userId],
            headings: { en: title || 'FutLog' },
            contents: { en: message || '¡Tenés una nueva notificación!' },
            data: {
                url: url || '/',
                type: type || 'test',
                ...data
            }
        }

        const response = await fetch('https://onesignal.com/api/v1/notifications', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json; charset=utf-8',
                'Authorization': `Basic ${restApiKey}`
            },
            body: JSON.stringify(body)
        })

        const result = await response.json()

        if (!response.ok) {
            throw new Error(result.errors?.[0] || 'Unknown OneSignal error')
        }

        return NextResponse.json({ success: true, result })
    } catch (error: any) {
        console.error('Error sending test notification:', error)
        return NextResponse.json({ error: error.message || 'Internal Server Error' }, { status: 500 })
    }
}

