  }

  // Determinar si estamos en modo votación (formaciones cargadas)
  const isVotingMode = equipos.length > 0 && estado === 'FINALIZADO'

  // Cargar datos del partido (desde API o DB)
  useEffect(() => {
    const fetchPartido = async () => {
      try {
        setLoading(true)
