// src/app/votar/page.tsx
'use client'

import { useState, useEffect, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { PartidoCard } from '@/components/PartidoCard'
import { DesktopNav } from '@/components/DesktopNav'
import { NavBar } from '@/components/NavBar'
import { ErrorMessage } from '@/components/ErrorMessage'
import { LIGAS, type Liga } from '@/lib/constants'
import { PartidoCardSkeleton } from '@/components/skeletons/PartidoCardSkeleton'
import type { Partido } from '@/types'

export default function VotarPage() {
  const router = useRouter()
  const { user } = useAuth()
  const [partidos, setPartidos] = useState<Partido[]>([])
  const [filtroLiga, setFiltroLiga] = useState<Liga>('Todos')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  // 📊 Fetch partidos con manejo de errores
  const fetchPartidos = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)

      let query = supabase
        .from('partidos')
        .select('*')
        // Solo partidos en juego o finalizados recientemente para votar
        .in('estado', ['EN_JUEGO', 'FINALIZADO'])
        .order('fecha_inicio', { ascending: false })
        .limit(20) // Evitar historial infinito

      if (filtroLiga !== 'Todos') {
        query = query.eq('liga', filtroLiga)
      }

      const { data, error: fetchError } = await query

      if (fetchError) throw fetchError

      setPartidos(data || [])
    } catch (err: any) {
      console.error('Error cargando partidos:', err)
      setError('No pudimos cargar los partidos habilitados para votación.')
    } finally {
      setLoading(false)
    }
  }, [filtroLiga])

  useEffect(() => {
    fetchPartidos()
  }, [fetchPartidos])

  if (loading) {
    return (
      <main className="min-h-screen bg-[var(--background)] pb-24 md:pt-20">
        <DesktopNav />
        <div className="max-w-4xl mx-auto px-6 py-6">
          <h1 className="text-2xl font-bold mb-6 text-[var(--foreground)]">Votar Figura del Partido ✋</h1>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {Array(4).fill(0).map((_, idx) => (
              <PartidoCardSkeleton key={idx} />
            ))}
          </div>
        </div>
        <NavBar />
      </main>
    )
  }

  return (
    <main className="min-h-screen bg-[var(--background)] pb-24 md:pt-20 transition-colors duration-300">
      <DesktopNav />
      {/* Header */}
      <div className="px-6 py-8">
        <div className="max-w-4xl mx-auto">
          <h1 className="text-2xl md:text-3xl font-bold tracking-tight mb-2">
            ✋ Votación de Figuras
          </h1>
          <p className="text-sm text-[var(--text-muted)] font-medium">
            Elegí el partido y votá a la figura. Solo partidos en vivo o terminados.
          </p>
          <div className="mt-6 flex items-start gap-4 px-5 py-4 bg-[var(--accent)]/5 border border-[var(--accent)]/10 rounded-2xl">
            <span className="text-[var(--accent)] text-lg">ℹ️</span>
            <p className="text-[11px] text-[var(--text-muted)] font-medium leading-relaxed">
              Mostrando los últimos 20 partidos finalizados.
              <br />
              Usá la <strong>búsqueda</strong> para encontrar encuentros anteriores.
            </p>
          </div>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-6">
        {/* Filtros de Liga */}
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-10">
          {LIGAS.map((liga) => (
            <button
              key={liga}
              onClick={() => setFiltroLiga(liga)}
              className={`px-5 py-2.5 rounded-xl text-xs font-bold capitalize tracking-tight
                           transition-all whitespace-nowrap border
                           ${filtroLiga === liga
                  ? 'bg-[var(--accent)] text-white border-[var(--accent)] shadow-lg shadow-purple-500/20'
                  : 'bg-[var(--card-bg)] text-[var(--text-muted)] hover:text-[var(--foreground)] border-[var(--card-border)]'
                }`}
            >
              {liga}
            </button>
          ))}
        </div>

        {/* Lista de Partidos */}
        <div>
          {/* Error State */}
          {error && (
            <ErrorMessage
              message={error}
              onRetry={() => fetchPartidos()}
            />
          )}

          {/* Empty State */}
          {!loading && !error && partidos.length === 0 && (
            <div className="text-center py-20 bg-[var(--card-bg)] rounded-[2rem] border border-[var(--card-border)] shadow-xl">
              <div className="text-6xl mb-4">⌛</div>
              <p className="text-[var(--foreground)] font-black italic capitalize tracking-tighter text-xl mb-2">No hay partidos para votar</p>
              <p className="text-[var(--text-muted)] text-sm font-medium max-w-xs mx-auto">
                La votación se habilita cuando los partidos comienzan o terminan.
              </p>
              <button
                onClick={() => router.push('/')}
                className="mt-6 text-[var(--accent)] font-black capitalize italic text-sm tracking-widest hover:underline"
              >
                Ver próximos partidos
              </button>
            </div>
          )}

          {/* Partidos Grid */}
          {!loading && !error && partidos.length > 0 && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {partidos.map((partido) => (
                <div key={partido.id} onClick={() => router.push(`/partido/${partido.id}`)} className="cursor-pointer group flex flex-col">
                  <PartidoCard partido={partido} />
                  <div className="mt-3 text-center">
                    <span className="text-[10px] font-black capitalize tracking-[0.2em] text-[var(--accent)] group-hover:underline">Tocá para votar ✋</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
      <NavBar />
    </main>
  )
}

// src/components/ActivityHeatmap.tsx
'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { motion } from 'framer-motion'

interface Props {
  userId: string
}

export function ActivityHeatmap({ userId }: Props) {
  const [activity, setActivity] = useState<Record<string, number>>({})
  const [loading, setLoading] = useState(true)
  const supabase = createClient()

  useEffect(() => {
    const fetchActivity = async () => {
      const oneYearAgo = new Date()
      oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1)

      const { data } = await supabase
        .from('match_logs')
        .select('watched_at')
        .eq('user_id', userId)
        .gte('watched_at', oneYearAgo.toISOString())

      if (data) {
        const counts: Record<string, number> = {}
        data.forEach(log => {
          const date = new Date(log.watched_at).toISOString().split('T')[0]
          counts[date] = (counts[date] || 0) + 1
        })
        setActivity(counts)
      }
      setLoading(false)
    }

    fetchActivity()
  }, [userId])

  const buildWeekGrid = () => {
    const grid: string[][] = []
    const today = new Date()

    // Start from 52 weeks ago
    const start = new Date(today)
    start.setDate(today.getDate() - (52 * 7))
    // Adjust to nearest Sunday
    start.setDate(start.getDate() - start.getDay())

    const current = new Date(start)
    for (let w = 0; w <= 52; w++) {
      const week: string[] = []
      for (let d = 0; d < 7; d++) {
        week.push(current.toISOString().split('T')[0])
        current.setDate(current.getDate() + 1)
        if (current > today) break
      }
      grid.push(week)
      if (current > today) break
    }
    return grid
  }

  if (loading) return <div className="h-24 bg-[var(--card-bg)] animate-pulse rounded-2xl" />

  const grid = buildWeekGrid()

  const getColor = (count: number) => {
    if (count === 0) return 'var(--card-border)'
    if (count === 1) return '#166534' // green-800
    if (count <= 3) return '#22c55e' // green-500
    return '#4ade80' // green-400
  }

  return (
    <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-6">
      <h3 className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] mb-4 flex items-center gap-2">
        📊 Actividad de Visionado (Último año)
      </h3>
      <div className="overflow-x-auto no-scrollbar pb-2">
        <div className="flex gap-1 min-w-max">
          {grid.map((week, wi) => (
            <div key={wi} className="flex flex-col gap-1">
              {week.map(day => {
                const count = activity[day] || 0
                return (
                  <motion.div
                    key={day}
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ delay: (wi * 0.01) }}
                    title={`${day}: ${count} partido${count !== 1 ? 's' : ''}`}
                    className="w-2.5 h-2.5 rounded-[2px] transition-colors hover:ring-1 hover:ring-[var(--accent)] cursor-help"
                    style={{ backgroundColor: getColor(count) }}
                  />
                )
              })}
            </div>
          ))}
        </div>
      </div>
      <div className="flex items-center justify-end gap-2 mt-3 text-[9px] font-bold text-[var(--text-muted)]">
        <span>Menos</span>
        <div className="flex gap-1">
          {[0, 1, 3, 5].map(v => (
            <div key={v} className="w-2 h-2 rounded-[1px]" style={{ backgroundColor: getColor(v) }} />
          ))}
        </div>
        <span>Más</span>
      </div>
    </div>
  )
}

// src/components/AdvancedStats.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { CollapsibleSection } from './CollapsibleSection'

interface TeamStats {
    name: string
    logo: string
    possession: string | number
    shots: string | number
    shots_on_target: string | number
    corners: string | number
    fouls: string | number
    yellow_cards: string | number
    red_cards: string | number
    offsides: string | number
    passes_total: string | number
    passes_accurate: string | number
    expected_goals: string | number
}

interface StatsData {
    local: TeamStats
    visitante: TeamStats
}

interface AdvancedStatsProps {
    fixtureId: number | string
}

interface StatRow {
    label: string
    icon: string
    local: number
    visitante: number
    format?: 'percent' | 'number' | 'xg'
}

export function AdvancedStats({ fixtureId }: AdvancedStatsProps) {
    const [data, setData] = useState<StatsData | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const res = await fetch(`/api/partido/${fixtureId}/statistics`)
                const json = await res.json()
                setData(json.stats)
            } catch (err) {
                console.error('Error loading stats:', err)
            } finally {
                setLoading(false)
            }
        }
        fetchStats()
    }, [fixtureId])

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4" style={{ borderRadius: 'var(--radius)' }}>
                <div className="flex items-center gap-2 mb-3">
                    <span>📊</span>
                    <h3 className="text-xs font-bold text-[var(--text-muted)] capitalize">Estadísticas Avanzadas</h3>
                </div>
                <div className="space-y-3">
                    {[1, 2, 3, 4, 5].map(i => (
                        <div key={i} className="h-6 bg-[var(--background)] rounded animate-pulse" />
                    ))}
                </div>
            </div>
        )
    }

    if (!data) return null

    const parseNum = (v: string | number): number => {
        if (typeof v === 'number') return v
        const n = parseFloat(String(v).replace('%', ''))
        return isNaN(n) ? 0 : n
    }

    const rows: StatRow[] = [
        { label: 'Posesión', icon: '🎯', local: parseNum(data.local.possession), visitante: parseNum(data.visitante.possession), format: 'percent' },
        { label: 'xG', icon: '📈', local: parseNum(data.local.expected_goals), visitante: parseNum(data.visitante.expected_goals), format: 'xg' },
        { label: 'Tiros', icon: '🥅', local: parseNum(data.local.shots), visitante: parseNum(data.visitante.shots) },
        { label: 'Al arco', icon: '🎯', local: parseNum(data.local.shots_on_target), visitante: parseNum(data.visitante.shots_on_target) },
        { label: 'Corners', icon: '🏁', local: parseNum(data.local.corners), visitante: parseNum(data.visitante.corners) },
        { label: 'Pases', icon: '📋', local: parseNum(data.local.passes_total), visitante: parseNum(data.visitante.passes_total) },
        { label: 'Pases prec.', icon: '✅', local: parseNum(data.local.passes_accurate), visitante: parseNum(data.visitante.passes_accurate) },
        { label: 'Faltas', icon: '⚠️', local: parseNum(data.local.fouls), visitante: parseNum(data.visitante.fouls) },
        { label: 'Offsides', icon: '🚩', local: parseNum(data.local.offsides), visitante: parseNum(data.visitante.offsides) },
    ]

    // Filter out rows where both values are 0
    const activeRows = rows.filter(r => r.local > 0 || r.visitante > 0)

    if (activeRows.length === 0) return null

    return (
        <CollapsibleSection title="Estadísticas Avanzadas" icon={<span className="text-xl">📊</span>} defaultOpen={false}>

            {/* Team names header */}
            <div className="flex items-center justify-between px-4 py-2 bg-[var(--background)]">
                <div className="flex items-center gap-2">
                    {data.local.logo && (
                        <img src={data.local.logo} alt="" className="w-5 h-5 object-contain" />
                    )}
                    <span className="text-[10px] font-bold truncate max-w-[80px]">{data.local.name}</span>
                </div>
                <div className="flex items-center gap-2">
                    <span className="text-[10px] font-bold truncate max-w-[80px]">{data.visitante.name}</span>
                    {data.visitante.logo && (
                        <img src={data.visitante.logo} alt="" className="w-5 h-5 object-contain" />
                    )}
                </div>
            </div>

            {/* Stats rows */}
            <div className="px-4 py-2 space-y-3">
                {activeRows.map((row, idx) => {
                    const total = row.local + row.visitante
                    const localPct = total > 0 ? (row.local / total) * 100 : 50
                    const visitantePct = total > 0 ? (row.visitante / total) * 100 : 50

                    const formatValue = (v: number) => {
                        if (row.format === 'percent') return `${v}%`
                        if (row.format === 'xg') return v.toFixed(2)
                        return String(v)
                    }

                    const localWins = row.local > row.visitante
                    const visitanteWins = row.visitante > row.local

                    return (
                        <motion.div
                            key={row.label}
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: idx * 0.05 }}
                        >
                            {/* Label */}
                            <div className="flex items-center justify-between mb-1">
                                <span className={`text-[11px] font-bold tabular-nums ${localWins ? 'text-[#16a34a]' : 'text-[var(--text-muted)]'}`}>
                                    {formatValue(row.local)}
                                </span>
                                <span className="text-[10px] text-[var(--text-muted)] font-medium">
                                    {row.icon} {row.label}
                                </span>
                                <span className={`text-[11px] font-bold tabular-nums ${visitanteWins ? 'text-[#2563eb]' : 'text-[var(--text-muted)]'}`}>
                                    {formatValue(row.visitante)}
                                </span>
                            </div>

                            {/* Bar */}
                            <div className="flex h-1.5 gap-0.5 border border-black/5 bg-black/5">
                                <motion.div
                                    initial={{ width: '50%' }}
                                    animate={{ width: `${localPct}%` }}
                                    transition={{ duration: 0.6, delay: idx * 0.05 }}
                                    className=""
                                    style={{ backgroundColor: localWins ? '#16a34a' : 'var(--card-border)' }}
                                />
                                <motion.div
                                    initial={{ width: '50%' }}
                                    animate={{ width: `${visitantePct}%` }}
                                    transition={{ duration: 0.6, delay: idx * 0.05 }}
                                    className=""
                                    style={{ backgroundColor: visitanteWins ? '#2563eb' : 'var(--card-border)' }}
                                />
                            </div>
                        </motion.div>
                    )
                })}
            </div>
        </CollapsibleSection>
    )
}

