'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Sparkles, TrendingUp, AlertCircle, Shield, Swords } from 'lucide-react'

interface AiPredictionWidgetProps {
    partidoId: string | number
    equipoLocal: string
    equipoVisitante: string
}

export function AiPredictionWidget({ partidoId, equipoLocal, equipoVisitante }: AiPredictionWidgetProps) {
    const [loading, setLoading] = useState(true)
    const [prediction, setPrediction] = useState<{
        localWin: number
        draw: number
        awayWin: number
        text: string
        keyFactor: string
        winner: 'local' | 'visitante' | 'empate'
    } | null>(null)

    useEffect(() => {
        // Generate a consistent pseudo-random prediction based on the match ID string
        const generatePrediction = () => {
            const seed = String(partidoId).split('').reduce((acc, char) => acc + char.charCodeAt(0), 0)

            // Determine probabilities (making sure they add up to 100)
            let localWin = 30 + (seed % 40)
            const awayWin = 15 + ((seed * 2) % 35)
            let draw = 100 - localWin - awayWin

            // Ensure no negative or crazy numbers
            if (draw < 10) {
                draw = 15
                localWin -= 5
            }

            const maxProb = Math.max(localWin, draw, awayWin)
            const winner = maxProb === localWin ? 'local' : maxProb === awayWin ? 'visitante' : 'empate'

            const analysisTemplates = [
                `${equipoLocal} llega con una racha sólida en casa, pero ${equipoVisitante} tiene el mejor contraataque de la liga.`,
                `Un duelo muy táctico. ${equipoVisitante} intentará dominar la posesión, mientras que ${equipoLocal} buscará golpear rápido.`,
                `Las estadísticas históricas favorecen ligeramente a ${winner === 'local' ? equipoLocal : equipoVisitante}, especialmente en el juego aéreo.`,
                `Ambos equipos necesitan sumar. La clave estará en el mediocampo y quien logre imponer su ritmo durante los primeros 45 minutos.`,
                `${winner === 'local' ? equipoLocal : equipoVisitante} tiene una ligera ventaja estadística debido a su recentísimo poderío goleador.`
            ]

            const factorTemplates = [
                "Posesión y control del mediocampo",
                "Efectividad en pelotas paradas",
                "Rendimiento de los arqueros",
                "Transiciones defensa-ataque",
                "Presión alta en los primeros minutos"
            ]

            setPrediction({
                localWin,
                draw,
                awayWin,
                winner,
                text: analysisTemplates[seed % analysisTemplates.length],
                keyFactor: factorTemplates[(seed * 3) % factorTemplates.length]
            })
            setLoading(false)
        }

        // Simulate API delay for realism
        const timer = setTimeout(generatePrediction, 1200)
        return () => clearTimeout(timer)
    }, [partidoId, equipoLocal, equipoVisitante])

    return (
        <div className="bg-[var(--card-bg)] rounded-xl border border-[#2563eb]/30 shadow-[0_4px_24px_rgba(139,92,246,0.06)] overflow-hidden relative">
            {/* Premium Glow effect behind the widget */}
            <div className="absolute -top-10 -right-10 w-32 h-32 bg-[#2563eb]/10 blur-3xl rounded-full pointer-events-none" />

            <div className="px-5 py-4 border-b border-[var(--card-border)] flex items-center justify-between relative z-10">
                <div className="flex items-center gap-2 text-[#2563eb]">
                    <div className="p-1.5 bg-[#2563eb]/10 rounded-lg">
                        <Sparkles size={18} />
                    </div>
                    <span className="font-black tracking-wide text-sm">PREDICCIÓN IA</span>
                </div>
                <span className="text-[10px] capitalize font-bold text-[var(--text-muted)] bg-[var(--background)] px-2 py-0.5 rounded-full border border-[var(--card-border)]">
                    BETA V1.2
                </span>
            </div>

            <div className="p-5 relative z-10">
                <AnimatePresence mode="wait">
                    {loading ? (
                        <motion.div
                            key="loading"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="flex flex-col items-center justify-center py-6 gap-3"
                        >
                            <div className="relative">
                                <Sparkles className="text-[#2563eb] animate-pulse" size={28} />
                                <div className="absolute inset-0 bg-[#2563eb] blur-xl opacity-20 animate-pulse" />
                            </div>
                            <p className="text-sm text-[var(--text-muted)] font-medium animate-pulse">
                                Analizando estadísticas históricas y rachas...
                            </p>
                        </motion.div>
                    ) : prediction ? (
                        <motion.div
                            key="result"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="space-y-6"
                        >
                            {/* Text Analysis */}
                            <div className="bg-[#2563eb]/5 rounded-xl p-4 border border-[#2563eb]/10">
                                <p className="text-sm leading-relaxed text-[var(--foreground)] font-medium">
                                    {prediction.text}
                                </p>
                                <div className="mt-3 flex items-center gap-2 text-xs text-[var(--text-muted)]">
                                    <AlertCircle size={14} className="text-[#2563eb]" />
                                    <span>Factor clave: <strong className="text-[var(--foreground)]">{prediction.keyFactor}</strong></span>
                                </div>
                            </div>

                            {/* Probabilities Bar */}
                            <div>
                                <div className="flex justify-between text-xs font-bold mb-2 capitalize tracking-wide">
                                    <div className="flex items-center gap-1.5 w-1/3">
                                        <Shield size={12} className="text-[var(--accent-blue)]" />
                                        <span className="truncate">{equipoLocal}</span>
                                    </div>
                                    <div className="text-center text-[var(--text-muted)] w-1/3">Empate</div>
                                    <div className="flex items-center justify-end gap-1.5 w-1/3 text-right">
                                        <span className="truncate">{equipoVisitante}</span>
                                        <Swords size={12} className="text-[#ff6b6b]" />
                                    </div>
                                </div>

                                <div className="h-3 flex rounded-full overflow-hidden border border-[var(--card-border)] bg-[var(--background)]">
                                    <motion.div
                                        initial={{ width: 0 }}
                                        animate={{ width: `${prediction.localWin}%` }}
                                        transition={{ duration: 1, delay: 0.2, type: 'spring' }}
                                        className="h-full bg-[var(--accent-blue)] flex items-center justify-start px-2 overflow-hidden"
                                    />
                                    <motion.div
                                        initial={{ width: 0 }}
                                        animate={{ width: `${prediction.draw}%` }}
                                        transition={{ duration: 1, delay: 0.2, type: 'spring' }}
                                        className="h-full bg-[var(--text-muted)] opacity-50 flex items-center justify-center overflow-hidden"
                                    />
                                    <motion.div
                                        initial={{ width: 0 }}
                                        animate={{ width: `${prediction.awayWin}%` }}
                                        transition={{ duration: 1, delay: 0.2, type: 'spring' }}
                                        className="h-full bg-[#ff6b6b] flex items-center justify-end px-2 overflow-hidden"
                                    />
                                </div>

                                <div className="flex justify-between text-xs font-black mt-2">
                                    <span className="w-1/3 text-[var(--accent-blue)]">{prediction.localWin}%</span>
                                    <span className="w-1/3 text-center text-[var(--text-muted)]">{prediction.draw}%</span>
                                    <span className="w-1/3 text-right text-[#ff6b6b]">{prediction.awayWin}%</span>
                                </div>
                            </div>
                        </motion.div>
                    ) : null}
                </AnimatePresence>
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState } from 'react'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/lib/supabase'
import { AutoShareModal } from '@/components/AutoShareModal'

export function AutoShareListener() {
    const { user } = useAuth()
    const [modalState, setModalState] = useState<{
        isOpen: boolean;
        type: 'prode_exact' | 'badge_unlock';
        title: string;
        subtitle: string;
        achievementData: any;
    }>({
        isOpen: false,
        type: 'badge_unlock',
        title: '',
        subtitle: '',
        achievementData: {}
    })

    useEffect(() => {
        if (!user) return

        // Listen for new badge unlocks
        const badgeChannel = supabase
            .channel('public:user_badges')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'user_badges',
                    filter: `user_id=eq.${user.id}`
                },
                async (payload) => {
                    // Fetch badge details
                    const { data: badgeData } = await supabase
                        .from('badges')
                        .select('*')
                        .eq('id', payload.new.badge_id)
                        .single()

                    if (badgeData) {
                        setModalState({
                            isOpen: true,
                            type: 'badge_unlock',
                            title: '¡Nueva Insignia!',
                            subtitle: badgeData.description,
                            achievementData: {
                                badgeIcon: badgeData.icon,
                                badgeName: badgeData.name
                            }
                        })
                    }
                }
            )
            .subscribe()

        // Listen for new prode exact hits.
        // The trigger evaluates and inserts a record in ranking_prode or updates it.
        // It's tricky to catch *exactly* when an exact hit happens just from DB inserts unless we have an audit log or notifications table.
        // If we use the user_notifications table, we can catch it!

        const notificationChannel = supabase
            .channel('public:user_notifications')
            .on(
                'postgres_changes',
                {
                    event: 'INSERT',
                    schema: 'public',
                    table: 'user_notifications',
                    filter: `user_id=eq.${user.id}`
                },
                (payload) => {
                    const type = payload.new.type
                    const data = payload.new.data || {}

                    if (type === 'PRODE_RESULT' && data.puntos === 8) {
                        setModalState({
                            isOpen: true,
                            type: 'prode_exact',
                            title: '¡Pleno Exacto!',
                            subtitle: 'Adivinaste el resultado exacto del partido.',
                            achievementData: {
                                matchDetails: data.partido_str || 'Partido',
                                pointsText: '8'
                            }
                        })
                    }
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(badgeChannel)
            supabase.removeChannel(notificationChannel)
        }
    }, [user])

    return (
        <AutoShareModal
            isOpen={modalState.isOpen}
            onClose={() => setModalState(prev => ({ ...prev, isOpen: false }))}
            type={modalState.type}
            title={modalState.title}
            subtitle={modalState.subtitle}
            achievementData={modalState.achievementData}
        />
    )
}

import { useState, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Button } from '@/components/ui/Button'
import { toPng } from 'html-to-image'

interface AutoShareModalProps {
    isOpen: boolean
    onClose: () => void
    type: 'prode_exact' | 'badge_unlock'
    title: string
    subtitle: string
    achievementData: {
        badgeIcon?: string
        badgeName?: string
        matchDetails?: string
        pointsIcon?: string
        pointsText?: string
    }
}

export function AutoShareModal({ isOpen, onClose, type, title, subtitle, achievementData }: AutoShareModalProps) {
    const cardRef = useRef<HTMLDivElement>(null)
    const [isGenerating, setIsGenerating] = useState(false)
    const [generatedImage, setGeneratedImage] = useState<string | null>(null)

    useEffect(() => {
        if (isOpen) {
            setGeneratedImage(null) // Reset image on open
            // Short delay to ensure DOM is fully rendered with animations
            const timer = setTimeout(() => {
                generateImage()
            }, 500)
            return () => clearTimeout(timer)
        }
    }, [isOpen])

    const generateImage = async () => {
        if (!cardRef.current) return

        try {
            setIsGenerating(true)
            const imgData = await toPng(cardRef.current, {
                pixelRatio: 2, // High resolution
                backgroundColor: '#0f172a', // force dark background for consistent share cards
                style: { margin: '0' }
            })

            setGeneratedImage(imgData)
        } catch (error) {
            console.error('Error generating share preview:', error)
        } finally {
            setIsGenerating(false)
        }
    }

    const handleNativeShare = async () => {
        const shareData = {
            title: '¡Mirá mi logro en FutLog!',
            text: subtitle,
            url: window.location.origin
        }

        if (navigator.share && generatedImage) {
            try {
                // Convert base64 to File for native sharing
                const res = await fetch(generatedImage)
                const blob = await res.blob()
                const file = new File([blob], 'futlog_achievement.png', { type: 'image/png' })

                if (navigator.canShare && navigator.canShare({ files: [file] })) {
                    await navigator.share({
                        ...shareData,
                        files: [file]
                    })
                } else {
                    // Fallback to text link share
                    await navigator.share(shareData)
                }
            } catch (err: any) {
                if (err.name !== 'AbortError') {
                    console.error('Error sharing:', err)
                }
            }
        } else {
            // Fallback clipboard
            navigator.clipboard.writeText(`${shareData.title}\n${shareData.text}\n${shareData.url}`)
            alert('Enlace copiado al portapapeles')
        }
    }

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4"
                    onClick={onClose}
                >
                    <motion.div
                        initial={{ scale: 0.9, y: 20 }}
                        animate={{ scale: 1, y: 0 }}
                        exit={{ scale: 0.9, y: 20 }}
                        onClick={(e) => e.stopPropagation()}
                        className="bg-[var(--card-bg)] rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl border border-[var(--card-border)] relative"
                    >
                        {/* Close button */}
                        <button
                            onClick={onClose}
                            className="absolute top-3 right-3 w-8 h-8 bg-black/20 rounded-full flex items-center justify-center text-white/70 hover:text-white z-20"
                        >
                            ✕
                        </button>

                        {/* Hidden preview structure for html2canvas generation */}
                        {!generatedImage && (
                            <div
                                ref={cardRef}
                                className="absolute top-[-9999px] left-[-9999px] w-[400px] h-[500px] bg-gradient-to-br from-[#0f172a] to-[#1e293b] p-8 flex flex-col items-center justify-center text-white text-center rounded-3xl border border-[#334155]"
                            >
                                <div className="text-6xl mb-4">
                                    {type === 'badge_unlock' ? achievementData.badgeIcon : '🎯'}
                                </div>
                                <h2 className="text-3xl font-black mb-2 leading-tight bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">
                                    {title}
                                </h2>
                                <p className="text-lg opacity-80 font-medium mb-8 px-4">
                                    {subtitle}
                                </p>

                                <div className="bg-black/30 backdrop-blur-md rounded-2xl p-6 w-full border border-white/10">
                                    {type === 'prode_exact' && (
                                        <>
                                            <p className="text-sm font-bold opacity-60 capitalize mb-2">Partido</p>
                                            <p className="font-bold text-xl">{achievementData.matchDetails}</p>
                                            <div className="mt-4 flex justify-center items-center gap-2 text-emerald-400 font-bold bg-emerald-400/10 py-2 rounded-xl">
                                                <span>+</span>{achievementData.pointsText} PTS
                                            </div>
                                        </>
                                    )}
                                    {type === 'badge_unlock' && (
                                        <>
                                            <p className="text-sm font-bold opacity-60 capitalize mb-2">Nueva Insignia</p>
                                            <p className="font-bold text-2xl text-amber-400">{achievementData.badgeName}</p>
                                        </>
                                    )}
                                </div>

                                <div className="mt-auto pt-8 flex items-center justify-center gap-3 w-full opacity-60">
                                    <span className="text-emerald-500 font-black text-xl">FutLog</span>
                                </div>
                            </div>
                        )}

                        <div className="p-6 text-center">
                            {/* Visual Header */}
                            <div className="mb-6 relative">
                                <div className="absolute inset-0 bg-gradient-to-t from-[var(--card-bg)] to-transparent z-10 bottom-0 top-1/2" />
                                {generatedImage ? (
                                    <img
                                        src={generatedImage}
                                        alt="Tu logro"
                                        className="w-full h-auto rounded-xl shadow-lg border border-[var(--card-border)]"
                                    />
                                ) : (
                                    <div className="w-full aspect-[4/5] bg-[var(--hover-bg)] animate-pulse rounded-xl flex items-center justify-center border border-[var(--card-border)]">
                                        <div className="text-sm text-[var(--text-muted)] font-bold">
                                            Generando imagen...
                                        </div>
                                    </div>
                                )}
                            </div>

                            <h3 className="text-xl font-black mb-2">{title}</h3>
                            <p className="text-sm text-[var(--text-muted)] mb-6">
                                {subtitle}
                            </p>

                            <div className="space-y-3">
                                <Button
                                    onClick={handleNativeShare}
                                    fullWidth
                                    disabled={!generatedImage || isGenerating}
                                    className="bg-gradient-to-r from-green-500 to-emerald-600 border-none flex items-center justify-center gap-2"
                                >
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="18" cy="5" r="3"></circle><circle cx="6" cy="12" r="3"></circle><circle cx="18" cy="19" r="3"></circle><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"></line><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"></line></svg>
                                    Compartir Logro
                                </Button>
                                <Button
                                    onClick={onClose}
                                    variant="outline"
                                    fullWidth
                                >
                                    Cerrar
                                </Button>
                            </div>
                        </div>
                    </motion.div>
                </motion.div>
            )}
        </AnimatePresence>
    )
}

// src/components/BadgeDisplay.tsx
'use client'

import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Lock, ChevronDown, ChevronUp, Sparkles } from 'lucide-react'
import confetti from 'canvas-confetti'
import { BADGES, getUnlockedBadges, getBadgeProgress, getNextBadges, type Badge, type BadgeStats } from '@/lib/badges'

interface BadgeDisplayProps {
    stats: BadgeStats
    compact?: boolean
}

export function BadgeDisplay({ stats, compact = false }: BadgeDisplayProps) {
    const [showAll, setShowAll] = useState(false)
    const [lastUnlockedCount, setLastUnlockedCount] = useState<number | null>(null)
    const unlocked = getUnlockedBadges(stats)
    const nextBadges = getNextBadges(stats)
    const unlockedIds = new Set(unlocked.map(b => b.id))

    useEffect(() => {
        if (lastUnlockedCount !== null && unlocked.length > lastUnlockedCount) {
            // New badge unlocked!
            confetti({
                particleCount: 150,
                spread: 70,
                origin: { y: 0.6 },
                colors: ['#f59e0b', '#16a34a', '#2563eb']
            })
        }
        setLastUnlockedCount(unlocked.length)
    }, [unlocked.length])

    if (compact) {
        // Compact mode: just show unlocked badge icons in a row
        return (
            <div className="flex flex-wrap gap-1.5">
                {unlocked.length === 0 ? (
                    <span className="text-xs text-[var(--text-muted)]">Sin logros aún</span>
                ) : (
                    unlocked.map(badge => (
                        <span
                            key={badge.id}
                            title={`${badge.name}: ${badge.description}`}
                            className="text-lg cursor-default hover:scale-125 transition-transform"
                        >
                            {badge.icon}
                        </span>
                    ))
                )}
            </div>
        )
    }

    const displayBadges = showAll ? BADGES : [...unlocked, ...nextBadges.filter(b => !unlockedIds.has(b.id))].slice(0, 8)

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4" style={{ borderRadius: 'var(--radius)' }}>
            <div className="flex items-center justify-between mb-4 border-b border-[var(--card-border)] pb-2 border-dashed">
                <h3 className="text-[10px] font-black capitalize tracking-widest flex items-center gap-2">
                    🏅 Logros
                    <span className="text-[9px] font-bold text-[var(--text-muted)] border border-[var(--card-border)] px-1.5 py-0.5 ml-1">
                        {unlocked.length}/{BADGES.length}
                    </span>
                </h3>
                {BADGES.length > 8 && (
                    <button
                        onClick={() => setShowAll(!showAll)}
                        className="text-[9px] font-black capitalize text-[var(--accent)] hover:underline flex items-center gap-1"
                    >
                        {showAll ? 'Menos' : 'Ver todos'}
                    </button>
                )}
            </div>

            <div className="grid grid-cols-2 gap-2">
                {displayBadges.map((badge) => {
                    const isUnlocked = unlockedIds.has(badge.id)
                    const progress = getBadgeProgress(badge, stats)

                    return (
                        <div
                            key={badge.id}
                            className={`relative flex items-center gap-2 p-2 border transition-all ${isUnlocked
                                ? 'bg-[var(--background)] border-[var(--foreground)]/20'
                                : 'bg-[var(--background)] border-[var(--card-border)] opacity-40'
                                }`}
                            style={{ borderRadius: 'var(--radius)' }}
                        >
                            <div className={`text-xl shrink-0 ${!isUnlocked ? 'grayscale brightness-50' : ''}`}>
                                {isUnlocked ? badge.icon : '🔒'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <div className="text-[10px] font-black capitalize tracking-tighter truncate">{badge.name}</div>
                                <div className="text-[8px] text-[var(--text-muted)] font-bold truncate leading-tight">{badge.description}</div>
                                {!isUnlocked && (
                                    <div className="mt-1">
                                        <div className="h-1 bg-[var(--card-border)] overflow-hidden">
                                            <div
                                                className="h-full bg-[var(--foreground)] transition-all duration-500"
                                                style={{ width: `${progress}%` }}
                                            />
                                        </div>
                                    </div>
                                )}
                            </div>
                            {isUnlocked && (
                                <div className="absolute -top-1 -right-1 w-3.5 h-3.5 bg-[var(--foreground)] border border-[var(--background)] flex items-center justify-center">
                                    <span className="text-[var(--background)] text-[8px] font-black">✓</span>
                                </div>
                            )}
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

'use client'

import { useState, useRef, useEffect } from 'react'
import { motion } from 'framer-motion'
import { Download, Share2, Save, Trash2, UserPlus, Info, Sparkles } from 'lucide-react'
import html2canvas from 'html2canvas'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'

interface PlayerPos {
    id: number
    name: string
    x: number // percent
    y: number // percent
    label: string
}

const TACTICS: Record<string, PlayerPos[]> = {
    '4-3-3': [
        { id: 1, name: '', x: 50, y: 85, label: 'GK' },
        { id: 2, name: '', x: 20, y: 70, label: 'DF' },
        { id: 3, name: '', x: 40, y: 72, label: 'DF' },
        { id: 4, name: '', x: 60, y: 72, label: 'DF' },
        { id: 5, name: '', x: 80, y: 70, label: 'DF' },
        { id: 6, name: '', x: 30, y: 50, label: 'MF' },
        { id: 7, name: '', x: 50, y: 55, label: 'MF' },
        { id: 8, name: '', x: 70, y: 50, label: 'MF' },
        { id: 9, name: '', x: 20, y: 30, label: 'FW' },
        { id: 10, name: '', x: 50, y: 25, label: 'FW' },
        { id: 11, name: '', x: 80, y: 30, label: 'FW' },
    ],
    '4-4-2': [
        { id: 1, name: '', x: 50, y: 85, label: 'GK' },
        { id: 2, name: '', x: 20, y: 70, label: 'DF' },
        { id: 3, name: '', x: 40, y: 72, label: 'DF' },
        { id: 4, name: '', x: 60, y: 72, label: 'DF' },
        { id: 5, name: '', x: 80, y: 70, label: 'DF' },
        { id: 6, name: '', x: 15, y: 50, label: 'MF' },
        { id: 7, name: '', x: 38, y: 50, label: 'MF' },
        { id: 8, name: '', x: 62, y: 50, label: 'MF' },
        { id: 9, name: '', x: 85, y: 50, label: 'MF' },
        { id: 10, name: '', x: 35, y: 25, label: 'FW' },
        { id: 11, name: '', x: 65, y: 25, label: 'FW' },
    ]
}

export function BuildXI() {
    const { user } = useAuth()
    const pitchRef = useRef<HTMLDivElement>(null)
    const [tactic, setTactic] = useState('4-3-3')
    const [players, setPlayers] = useState<PlayerPos[]>(TACTICS['4-3-3'])
    const [selectedId, setSelectedId] = useState<number | null>(null)
    const [lineupName, setLineupName] = useState('Mi XI Ideal')
    const [exporting, setExporting] = useState(false)
    const [saving, setSaving] = useState(false)
    const [suggestedPlayers, setSuggestedPlayers] = useState<{ name: string, rating: number }[]>([])

    useEffect(() => {
        fetchSuggestedPlayers()
    }, [])

    const fetchSuggestedPlayers = async () => {
        try {
            // Fetch all ratings and group manually for simplicity without RPC
            const { data } = await supabase
                .from('match_log_player_ratings')
                .select('player_name, rating')
                .order('rating', { ascending: false })
                .limit(100)

            if (data) {
                const grouped: Record<string, { total: number, count: number }> = {}
                data.forEach(r => {
                    const name = r.player_name.trim()
                    if (!grouped[name]) grouped[name] = { total: 0, count: 0 }
                    grouped[name].total += r.rating
                    grouped[name].count += 1
                })

                const sorted = Object.entries(grouped)
                    .map(([name, stats]) => ({
                        name,
                        rating: Number((stats.total / stats.count).toFixed(1))
                    }))
                    .sort((a, b) => b.rating - a.rating)
                    .slice(0, 15)

                setSuggestedPlayers(sorted)
            }
        } catch (err) {
            console.error('Error fetching suggested players:', err)
        }
    }

    const selectSuggested = (name: string) => {
        if (selectedId !== null) {
            handlePlayerNameChange(selectedId, name)
            // Auto select next empty slot if possible, or just deselect
            setSelectedId(null)
        }
    }

    const handlePlayerNameChange = (id: number, name: string) => {
        setPlayers(prev => prev.map(p => p.id === id ? { ...p, name } : p))
    }

    const exportAsImage = async () => {
        if (!pitchRef.current) return
        setExporting(true)
        try {
            const canvas = await html2canvas(pitchRef.current, {
                scale: window.devicePixelRatio || 2,
                useCORS: true,
                allowTaint: true,
                backgroundColor: '#1a4d1a',
                logging: false,
                onclone: (clonedDoc) => {
                    const el = clonedDoc.body.querySelector('[ref="pitchRef"]') as HTMLElement
                    if (el) el.style.borderRadius = '0'
                }
            })

            const image = canvas.toDataURL('image/png')
            const link = document.createElement('a')
            link.href = image
            link.download = `futlog-lineup-${Date.now()}.png`
            document.body.appendChild(link)
            link.click()
            document.body.removeChild(link)

            alert('¡Imagen generada! Si no se descarga automáticamente, probá manteniendo presionada la imagen para guardarla.')
        } catch (err) {
            console.error('Error exporting image:', err)
            alert('Error al generar la imagen. Intentá tomar una captura de pantalla.')
        } finally {
            setExporting(false)
        }
    }

    const saveLineup = async () => {
        if (!user) return
        setSaving(true)
        try {
            const playersJson: Record<string, string> = {}
            players.forEach(p => playersJson[p.id.toString()] = p.name)

            const { error } = await supabase.from('user_lineups').insert({
                user_id: user.id,
                name: lineupName,
                tactic: tactic,
                players: playersJson
            })

            if (error) throw error

            alert('Formación guardada correctamente')
        } catch (err: any) {
            console.error('Error saving lineup:', err)
            alert('Error al guardar: ' + err.message)
        } finally {
            setSaving(false)
        }
    }

    return (
        <div className="max-w-xl mx-auto space-y-6 pb-20 mt-4">
            {/* Controls */}
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-6 shadow-sm">
                <div className="flex flex-col gap-4">
                    <div>
                        <label className="text-[10px] font-black text-[var(--text-muted)] capitalize tracking-widest mb-2 block">
                            NOMBRE DEL EQUIPO
                        </label>
                        <input
                            type="text"
                            className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-xl px-4 py-3 text-sm font-bold focus:border-[var(--accent)] transition-all"
                            value={lineupName}
                            onChange={(e) => setLineupName(e.target.value)}
                        />
                    </div>

                    <div className="flex items-center justify-between gap-4">
                        <div className="flex-1">
                            <label className="text-[10px] font-black text-[var(--text-muted)] capitalize tracking-widest mb-2 block">
                                TÁCTICA
                            </label>
                            <div className="flex gap-2">
                                {Object.keys(TACTICS).map(t => (
                                    <button
                                        key={t}
                                        onClick={() => {
                                            setTactic(t)
                                            setPlayers(TACTICS[t])
                                        }}
                                        className={`flex-1 py-2 rounded-xl text-xs font-bold border transition-all
                                            ${tactic === t ? 'bg-[var(--accent)] text-white border-[var(--accent)]' : 'bg-[var(--background)] border-[var(--card-border)] text-[var(--text-muted)]'}`}
                                    >
                                        {t}
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Suggested Players Carousel */}
            {suggestedPlayers.length > 0 && (
                <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-4 shadow-sm overflow-hidden">
                    <div className="flex items-center justify-between mb-3 px-1">
                        <label className="text-[10px] font-black text-[var(--accent-green)] capitalize tracking-widest flex items-center gap-1.5">
                            <Sparkles size={12} /> Jugadores Sugeridos
                        </label>
                        <span className="text-[10px] text-[var(--text-muted)] font-bold italic">Basado en tus ratings</span>
                    </div>
                    <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1 px-1">
                        {suggestedPlayers.map((p, i) => (
                            <button
                                key={i}
                                onClick={() => selectSuggested(p.name)}
                                className={`flex flex-col items-center gap-1.5 p-2 rounded-2xl min-w-[80px] transition-all border
                                    ${selectedId !== null ? 'hover:border-[var(--accent)] hover:bg-[var(--hover-bg)] cursor-pointer' : 'opacity-70 cursor-default'}
                                    bg-[var(--background)] border-[var(--card-border)]`}
                            >
                                <div className="w-10 h-10 bg-[var(--hover-bg)] rounded-full flex items-center justify-center text-lg shadow-inner">
                                    👤
                                </div>
                                <div className="text-center">
                                    <p className="text-[9px] font-black truncate w-16 capitalize tracking-tighter">{p.name}</p>
                                    <p className="text-[10px] font-bold text-[var(--accent-yellow)]">★ {p.rating}</p>
                                </div>
                            </button>
                        ))}
                    </div>
                    {selectedId === null && (
                        <p className="text-[9px] text-[var(--text-muted)] text-center mt-3 opacity-60">
                            Tocá una posición en la cancha para habilitar las sugerencias.
                        </p>
                    )}
                </div>
            )}

            {/* Pitch */}
            <div className="relative group">
                <div
                    ref={pitchRef}
                    className="relative aspect-[3/4] w-full bg-[#1a4d1a] rounded-[2rem] overflow-hidden border-4 border-[#2d5a2d] shadow-2xl"
                    style={{
                        backgroundImage: `
                            linear-gradient(to bottom, #1a4d1a 0%, #245e24 100%),
                            repeating-linear-gradient(to bottom, transparent, transparent 10%, rgba(0,0,0,0.05) 10.1%, rgba(0,0,0,0.05) 20%)
                        `
                    }}
                >
                    {/* Pitch Lines */}
                    <div className="absolute inset-4 border-2 border-white/20 rounded-xl pointer-events-none" />
                    <div className="absolute top-4 left-1/2 -translate-x-1/2 w-32 h-16 border-b-2 border-x-2 border-white/20 pointer-events-none" />
                    <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-32 h-16 border-t-2 border-x-2 border-white/20 pointer-events-none" />
                    <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-white/20 pointer-events-none" />
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-24 h-24 border-2 border-white/20 rounded-full pointer-events-none" />

                    {/* Branding */}
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-10 pointer-events-none rotate-[-45deg]">
                        <span className="text-6xl font-black text-white italic tracking-tighter">FutLog</span>
                    </div>

                    {/* Players */}
                    {players.map((p) => (
                        <motion.div
                            key={p.id}
                            initial={false}
                            animate={{ left: `${p.x}%`, top: `${p.y}%` }}
                            className="absolute -translate-x-1/2 -translate-y-1/2 flex flex-col items-center gap-1 z-20"
                        >
                            <button
                                onClick={() => setSelectedId(selectedId === p.id ? null : p.id)}
                                className={`w-10 h-10 sm:w-12 sm:h-12 rounded-full border-2 flex items-center justify-center shadow-lg transition-all
                                    ${selectedId === p.id ? 'bg-[#ff6b6b] border-white scale-125' : 'bg-white border-[#1a4d1a] text-[#1a4d1a]'}`}
                            >
                                {selectedId === p.id ? <UserPlus size={18} /> : <span className="text-[10px] font-black">{p.label}</span>}
                            </button>

                            <div className="relative">
                                <input
                                    type="text"
                                    placeholder="Nombre..."
                                    className={`bg-black/60 backdrop-blur-md text-white border border-white/20 rounded-lg px-2 py-1 text-[10px] w-24 text-center focus:outline-none focus:border-white transition-all
                                        ${p.name ? 'opacity-100' : 'opacity-40 hover:opacity-100'}`}
                                    value={p.name}
                                    onChange={(e) => handlePlayerNameChange(p.id, e.target.value)}
                                />
                            </div>
                        </motion.div>
                    ))}

                    <div className="absolute bottom-6 right-6 opacity-30 pointer-events-none flex items-center gap-2">
                        <span className="text-[8px] font-black text-white tracking-widest capitalize">Diseñado en FutLog.app</span>
                    </div>
                </div>

                {/* Floating Hint */}
                <div className="absolute -top-3 -right-3 bg-[var(--accent)] text-white p-2 rounded-full shadow-lg hidden sm:block">
                    <Info size={14} />
                </div>
            </div>

            {/* Actions */}
            <div className="grid grid-cols-2 gap-3">
                <button
                    onClick={saveLineup}
                    disabled={saving || !user}
                    className="flex items-center justify-center gap-2 bg-[var(--card-bg)] border border-[var(--card-border)] text-[var(--foreground)] font-bold py-4 rounded-3xl hover:bg-[var(--hover-bg)] transition-all shadow-sm"
                >
                    <Save size={18} /> {saving ? 'Guardando...' : 'Guardar'}
                </button>
                <button
                    onClick={exportAsImage}
                    disabled={exporting}
                    className="flex items-center justify-center gap-2 bg-[#00A651] text-white font-bold py-4 rounded-3xl shadow-lg shadow-[#00A651]/20 hover:brightness-110 active:scale-95 transition-all"
                >
                    <Download size={18} /> {exporting ? 'Generando...' : 'Descargar'}
                </button>
            </div>

            {!user && (
                <div className="bg-amber-500/10 border border-amber-500/30 rounded-2xl p-4 flex gap-3 items-center">
                    <span className="text-xl">⚠️</span>
                    <p className="text-xs text-amber-500 font-medium">
                        Deberías <a href="/login" className="underline font-bold">iniciar sesión</a> para guardar tu XI ideal en tu perfil.
                    </p>
                </div>
            )}
        </div>
    )
}

// src/components/CanchaFormacion.tsx
'use client'

import { memo, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import Link from 'next/link'

interface JugadorAPI {
    id: number
    nombre: string
    numero: number
    posicion: string
}

interface CanchaFormacionProps {
    jugadores: JugadorAPI[]
    nombreEquipo: string
    votos: Record<number, number>
    onVotar: (jugadorId: number, nota: number) => void
    partidoFinalizado: boolean
}

// Color según la nota (estilo SofaScore)
function getNotaColor(nota: number): string {
    if (nota >= 8) return 'bg-[#16a34a]'
    if (nota >= 6) return 'bg-[#22c55e]'
    if (nota >= 5) return 'bg-[#d97706]'
    if (nota >= 4) return 'bg-[#ea580c]'
    return 'bg-[#dc2626]'
}

function getNotaBgHover(nota: number): string {
    if (nota >= 8) return 'hover:bg-[#16a34a]'
    if (nota >= 6) return 'hover:bg-[#22c55e]'
    if (nota >= 5) return 'hover:bg-[#d97706]'
    if (nota >= 4) return 'hover:bg-[#ea580c]'
    return 'hover:bg-[#dc2626]'
}

export const CanchaFormacion = memo(({
    jugadores,
    nombreEquipo,
    votos,
    onVotar,
    partidoFinalizado
}: CanchaFormacionProps) => {
    const [jugadorSeleccionado, setJugadorSeleccionado] = useState<JugadorAPI | null>(null)
    const [animatingVote, setAnimatingVote] = useState<number | null>(null)

    // Agrupar jugadores por posición
    const arqueros = jugadores.filter(j => j.posicion === 'ARQ')
    const defensores = jugadores.filter(j => j.posicion === 'DEF')
    const mediocampistas = jugadores.filter(j => j.posicion === 'MED')
    const delanteros = jugadores.filter(j => j.posicion === 'DEL')

    const handleJugadorClick = (jugador: JugadorAPI) => {
        if (partidoFinalizado) {
            setJugadorSeleccionado(jugador)
        }
    }

    const handleVotar = (nota: number) => {
        if (jugadorSeleccionado) {
            setAnimatingVote(jugadorSeleccionado.id)
            onVotar(jugadorSeleccionado.id, nota)
            setJugadorSeleccionado(null)
            setTimeout(() => setAnimatingVote(null), 600)
        }
    }

    const JugadorBall = ({ jugador }: { jugador: JugadorAPI }) => {
        const tieneVoto = (votos[jugador.id] || 0) > 0
        const isAnimating = animatingVote === jugador.id
        const nota = votos[jugador.id]

        return (
            <button
                onClick={() => handleJugadorClick(jugador)}
                disabled={!partidoFinalizado}
                className={`relative flex flex-col items-center group transition-all duration-300
                   ${partidoFinalizado ? 'cursor-pointer hover:scale-105 active:scale-95' : 'cursor-default'}`}
            >
                {/* Círculo del jugador */}
                <div className={`w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center
                        border-2 transition-all duration-300 relative overflow-hidden
                        ${tieneVoto
                        ? 'bg-[var(--foreground)] border-white text-white shadow-md'
                        : 'bg-[var(--card-bg)] border-[var(--card-border)] group-hover:border-[var(--accent)]'
                    }
                    ${isAnimating ? 'scale-110' : ''}`}>

                    <span className={`font-black text-lg sm:text-xl relative z-10 transition-colors
                        ${tieneVoto ? 'text-white' : 'text-[var(--foreground)]'}`}>
                        {jugador.numero}
                    </span>
                </div>

                {/* Nombre - Simple Tag */}
                <div className="mt-1 bg-[var(--background)] px-2 py-0.5 border border-[var(--card-border)] text-[9px] sm:text-[10px] font-bold text-[var(--foreground)]
                        whitespace-nowrap max-w-[80px] truncate capitalize tracking-tighter shadow-sm">
                    {jugador.nombre.split(' ').pop()}
                </div>

                {/* Badge de voto - Square/Boxy */}
                {tieneVoto && (
                    <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        className={`absolute -top-1 -right-1 w-6 h-6 
                          flex items-center justify-center text-[10px] font-black text-white
                          border border-white shadow-sm z-20 transition-all duration-300 ${getNotaColor(nota)}
                          ${isAnimating ? 'scale-125' : ''}`}
                        style={{ borderRadius: '2px' }}>
                        {nota}
                    </motion.div>
                )}
            </button>
        )
    }

    return (
        <div className="relative">
            {/* Cancha */}
            <div className="bg-[#3a4d33] border-2 border-[#2a3a23] relative overflow-hidden"
                style={{ borderRadius: 'var(--radius)' }}>
