import React, { useState, useEffect } from 'react'
import { Trophy, X, ChevronRight, Zap, Target, Star, Gift } from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { hapticFeedback } from '@/lib/helpers'

interface ChallengesFABProps {
    inline?: boolean
}

export const ChallengesFAB = ({ inline = false }: ChallengesFABProps) => {
    const [isOpen, setIsOpen] = useState(false)
    const [activeTab, setActiveTab] = useState<'daily' | 'weekly'>('daily')

    const toggleOpen = () => {
        hapticFeedback(isOpen ? 2 : 10)
        setIsOpen(!isOpen)
    }

    useEffect(() => {
        const handleOpen = () => setIsOpen(true)
        document.addEventListener('open-challenges', handleOpen)
        return () => document.removeEventListener('open-challenges', handleOpen)
    }, [])

    return (
        <>
            {inline ? (
                <button
                    onClick={toggleOpen}
                    className="w-full text-left py-3 px-1 border-b border-[var(--card-border)] last:border-0 flex items-center justify-between group transition-colors hover:bg-[var(--hover-bg)]"
                >
                    <div className="flex items-center gap-3">
                        <Trophy size={16} className="text-[var(--text-muted)] group-hover:text-[var(--foreground)] transition-colors" />
                        <span className="text-xs font-bold capitalize tracking-tight text-[var(--foreground)]">Desafíos & XP</span>
                    </div>
                    <span className="text-[10px] text-[var(--text-muted)] font-medium capitalize">Misiones Semanales</span>
                </button>
            ) : (
                <button
                    onClick={toggleOpen}
                    className={`fixed bottom-[88px] right-3 z-40 flex items-center gap-1.5 px-3 py-2 shadow-md border transition-all active:scale-95 text-[10px] font-bold capitalize tracking-tight
                        ${isOpen
                            ? 'bg-red-500 text-white border-red-500/20'
                            : 'bg-[var(--card-bg)]/90 backdrop-blur-md border-[var(--card-border)] text-[var(--text-muted)] hover:text-[var(--foreground)] hover:border-[var(--accent)]'
                        }`}
                    style={{ borderRadius: 'var(--radius)' }}
                >
                    {isOpen ? <X size={14} /> : <><Trophy size={14} /> Desafíos</>}
                </button>
            )}

            {/* Bottom Sheet for Mobile / Content Overlay */}
            <AnimatePresence>
                {isOpen && (
                    <>
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={toggleOpen}
                            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 block"
                        />
                        <motion.div
                            initial={{ y: '100%' }}
                            animate={{ y: 0 }}
                            exit={{ y: '100%' }}
                            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                            className="fixed bottom-0 left-0 right-0 bg-[var(--card-bg)] rounded-t-3xl z-[60] max-h-[85vh] overflow-hidden flex flex-col shadow-2xl border-t border-white/10"
                        >
                            {/* Handle bar */}
                            <div className="w-12 h-1.5 bg-[var(--card-border)] rounded-full mx-auto my-4 opacity-50" />

                            <div className="px-6 pb-4">
                                <div className="flex items-center justify-between mb-6">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-yellow-400/20 rounded-xl flex items-center justify-center">
                                            <Trophy className="text-yellow-400 w-6 h-6" />
                                        </div>
                                        <div>
                                            <h2 className="text-xl font-bold tracking-tight">Desafíos</h2>
                                            <p className="text-[10px] text-[var(--text-muted)] font-medium capitalize tracking-tight">Gana XP y sube de nivel</p>
                                        </div>
                                    </div>
                                    <button onClick={toggleOpen} className="w-8 h-8 rounded-full bg-[var(--card-border)]/30 flex items-center justify-center">
                                        <X size={16} />
                                    </button>
                                </div>

                                {/* Tabs */}
                                <div className="flex p-1 bg-[var(--card-border)]/20 rounded-2xl mb-6">
                                    <button
                                        onClick={() => setActiveTab('daily')}
                                        className={`flex-1 flex items-center justify-center gap-2 py-3 px-4 text-xs font-bold capitalize transition-all rounded-xl
                                            ${activeTab === 'daily' ? 'bg-[var(--card-bg)] text-[var(--accent-green)] shadow-sm' : 'text-[var(--text-muted)]'}`}
                                    >
                                        <Zap size={14} className={activeTab === 'daily' ? 'text-yellow-400' : ''} />
                                        Diarios
                                    </button>
                                    <button
                                        onClick={() => setActiveTab('weekly')}
                                        className={`flex-1 flex items-center justify-center gap-2 py-2.5 px-4 text-xs font-black capitalize transition-all rounded-xl
                                            ${activeTab === 'weekly' ? 'bg-[var(--card-bg)] text-[#8b5cf6] shadow-sm' : 'text-[var(--text-muted)]'}`}
                                    >
                                        <Target size={14} className={activeTab === 'weekly' ? 'text-[#8b5cf6]' : ''} />
                                        Semanales
                                    </button>
                                </div>

                                {/* List */}
                                <div className="space-y-4 pb-10 overflow-y-auto max-h-[50vh] pr-2 no-scrollbar">
                                    {activeTab === 'daily' ? (
                                        <div className="space-y-3">
                                            <ChallengeItem
                                                icon={<Star className="text-yellow-400" />}
                                                title="Califica 3 partidos"
                                                subtitle="Evalúa tu experiencia en la cancha"
                                                progress={2}
                                                total={3}
                                                xp={50}
                                                color="#10b981"
                                            />
                                            <ChallengeItem
                                                icon={<Zap className="text-blue-400" />}
                                                title="Vota en 1 encuesta"
                                                subtitle="Danos tu opinión del partido"
                                                progress={0}
                                                total={1}
                                                xp={30}
                                                color="#3b82f6"
                                            />
                                        </div>
                                    ) : (
                                        <div className="space-y-3">
                                            <ChallengeItem
                                                icon={<Target className="text-red-400" />}
                                                title="Sube al Top 10"
                                                subtitle="En el ranking semanal"
                                                progress={15}
                                                total={10}
                                                xp={250}
                                                color="#ef4444"
                                                isGoal
                                            />
                                            <ChallengeItem
                                                icon={<Gift className="text-purple-400" />}
                                                title="Crea un grupo"
                                                subtitle="Invita a tus amigos"
                                                progress={0}
                                                total={1}
                                                xp={100}
                                                color="#a855f7"
                                            />
                                        </div>
                                    )}
                                </div>
                            </div>
                        </motion.div>
                    </>
                )}
            </AnimatePresence>
        </>
    )
}

const ChallengeItem = ({ icon, title, subtitle, progress, total, xp, color, isGoal = false }: any) => {
    const percentage = Math.min((progress / total) * 100, 100)
    const isCompleted = progress >= total

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-4 flex gap-4 items-center">
            <div className="w-12 h-12 rounded-xl flex items-center justify-center text-xl grayscale-[0.5] bg-opacity-10" style={{ backgroundColor: color + '20' }}>
                {icon}
            </div>
            <div className="flex-1">
                <div className="flex justify-between items-start mb-1">
                    <h4 className="font-bold text-sm leading-tight">{title}</h4>
                    <span className="text-[10px] font-bold text-[var(--accent-green)]">+{xp} XP</span>
                </div>
                <p className="text-[10px] text-[var(--text-muted)] font-medium mb-3">{subtitle}</p>

                <div className="w-full h-1.5 bg-[var(--card-border)]/50 rounded-full overflow-hidden">
                    <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${percentage}%` }}
                        className="h-full rounded-full"
                        style={{ backgroundColor: color }}
                    />
                </div>
                <div className="flex justify-between mt-1">
                    <span className="text-[8px] font-bold text-[var(--text-muted)]">{progress}/{total} {isGoal ? 'POS' : 'LISTO'}</span>
                    {isCompleted && <span className="text-[8px] font-bold text-[var(--accent-green)] capitalize">Completado</span>}
                </div>
            </div>
            <div className="flex flex-col items-center justify-center p-2 rounded-xl bg-[var(--card-border)]/20 min-w-[50px] border border-white/5">
                <ChevronRight size={18} className="text-[var(--text-muted)]" />
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { BarChart2, Plus, X, Check } from 'lucide-react'

interface Poll {
    id: string
    question: string
    options: string[]
    active: boolean
}

interface VoteCount {
    option_index: number
    count: number
}

export function ChatPoll({ partidoId }: { partidoId: string }) {
    const { user } = useAuth()
    const [poll, setPoll] = useState<Poll | null>(null)
    const [votes, setVotes] = useState<VoteCount[]>([])
    const [userVote, setUserVote] = useState<number | null>(null)
    const [showCreate, setShowCreate] = useState(false)
    const [newQuestion, setNewQuestion] = useState('')
    const [newOptions, setNewOptions] = useState(['', ''])

    useEffect(() => {
        if (!partidoId) return
        fetchPoll()

        const pollSub = supabase
            .channel(`poll-${partidoId}`)
            .on('postgres_changes' as any, { event: '*', table: 'chat_polls', filter: `partido_id=eq.${partidoId}` }, fetchPoll)
            .on('postgres_changes' as any, { event: '*', table: 'chat_poll_votes' }, fetchVotes)
            .subscribe()

        return () => { supabase.removeChannel(pollSub) }
    }, [partidoId])

    const fetchPoll = async () => {
        const { data, error } = await supabase
            .from('chat_polls')
            .select('*')
            .eq('partido_id', partidoId)
            .eq('active', true)
            .order('created_at', { ascending: false })
            .limit(1)
            .maybeSingle()

        if (data) {
            setPoll(data)
            fetchVotes()
            if (user) fetchUserVote(data.id)
        } else {
            setPoll(null)
        }
    }

    const fetchVotes = async () => {
        if (!poll) return
        const { data, error } = await supabase
            .from('chat_poll_votes')
            .select('option_index')
            .eq('poll_id', poll.id)

        if (data) {
            const counts: Record<number, number> = {}
            data.forEach(v => {
                counts[v.option_index] = (counts[v.option_index] || 0) + 1
            })
            setVotes(Object.entries(counts).map(([idx, count]) => ({
                option_index: parseInt(idx),
                count
            })))
        }
    }

    const fetchUserVote = async (pollId: string) => {
        if (!user) return
        const { data } = await supabase
            .from('chat_poll_votes')
            .select('option_index')
            .eq('poll_id', pollId)
            .eq('user_id', user.id)
            .maybeSingle()

        if (data) setUserVote(data.option_index)
    }

    const handleVote = async (idx: number) => {
        if (!user || !poll) return
        const { error } = await supabase
            .from('chat_poll_votes')
            .upsert({
                poll_id: poll.id,
                user_id: user.id,
                option_index: idx
            })

        if (!error) {
            setUserVote(idx)
            fetchVotes()
        }
    }

    const handleCreatePoll = async () => {
        if (!user || !newQuestion || newOptions.some(o => !o.trim())) return

        // Deactivate previous poll
        await supabase.from('chat_polls').update({ active: false }).eq('partido_id', partidoId)

        const { error } = await supabase.from('chat_polls').insert({
            partido_id: partidoId,
            created_by: user.id,
            question: newQuestion,
            options: newOptions.filter(o => o.trim() !== '')
        })

        if (!error) {
            setShowCreate(false)
            setNewQuestion('')
            setNewOptions(['', ''])
            fetchPoll()
        }
    }

    const totalVotes = votes.reduce((acc, v) => acc + v.count, 0)

    if (showCreate) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4 rounded-2xl mb-4">
                <div className="flex justify-between items-center mb-4">
                    <h4 className="font-bold text-sm">Nueva Encuesta</h4>
                    <button onClick={() => setShowCreate(false)}><X size={16} /></button>
                </div>
                <input
                    type="text"
                    placeholder="Pregunta (ej: ¿Quién gana?)"
                    className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-xl px-3 py-2 text-sm mb-3"
                    value={newQuestion}
                    onChange={e => setNewQuestion(e.target.value)}
                />
                <div className="space-y-2 mb-4">
                    {newOptions.map((opt, i) => (
                        <input
                            key={i}
                            type="text"
                            placeholder={`Opción ${i + 1}`}
                            className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-xl px-3 py-2 text-sm"
                            value={opt}
                            onChange={e => {
                                const copy = [...newOptions]
                                copy[i] = e.target.value
                                setNewOptions(copy)
                            }}
                        />
                    ))}
                    {newOptions.length < 4 && (
                        <button
                            onClick={() => setNewOptions([...newOptions, ''])}
                            className="text-[10px] font-bold text-[var(--accent)]"
                        >
                            + AGREGAR OPCIÓN
                        </button>
                    )}
                </div>
                <button
                    onClick={handleCreatePoll}
                    className="w-full bg-[var(--accent)] text-white font-bold py-2 rounded-xl text-sm"
                >
                    Lanzar Encuesta
                </button>
            </div>
        )
    }

    if (!poll) {
        return (
            <button
                onClick={() => setShowCreate(true)}
                className="flex items-center gap-2 text-xs font-bold text-[var(--text-muted)] hover:text-[var(--accent)] transition-colors p-2"
            >
                <Plus size={14} /> Lanzar encuesta en vivo
            </button>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4 rounded-2xl mb-4 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 right-0 p-2 opacity-10">
                <BarChart2 size={40} />
            </div>

            <h4 className="font-black text-sm mb-4 pr-10 capitalize tracking-tight">
                🔥 {poll.question}
            </h4>

            <div className="space-y-2.5">
                {poll.options.map((opt, i) => {
                    const voteData = votes.find(v => v.option_index === i)
                    const count = voteData?.count || 0
                    const percent = totalVotes > 0 ? (count / totalVotes) * 100 : 0
                    const isSelected = userVote === i

                    return (
                        <div key={i} className="relative">
                            <button
                                onClick={() => handleVote(i)}
                                disabled={!user}
                                className={`w-full relative z-10 p-3 rounded-xl border transition-all text-left flex justify-between items-center group
                                    ${isSelected ? 'border-[var(--accent)] bg-[var(--accent)]/5' : 'border-[var(--card-border)] bg-[var(--background)]/50 hover:bg-[var(--background)]'}`}
                            >
                                <span className={`text-xs font-bold ${isSelected ? 'text-[var(--accent)]' : 'text-[var(--foreground)]'}`}>
                                    {opt}
                                </span>
                                {totalVotes > 0 && (
                                    <span className="text-[10px] font-black opacity-60">
                                        {Math.round(percent)}%
                                    </span>
                                )}
                                {isSelected && (
                                    <span className="absolute -left-1 top-1/2 -translate-y-1/2 w-2 h-4 bg-[var(--accent)] rounded-r-full" />
                                )}
                            </button>
                            <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${percent}%` }}
                                className={`absolute inset-0 h-full rounded-xl pointer-events-none opacity-10
                                    ${isSelected ? 'bg-[var(--accent)]' : 'bg-[var(--text-muted)]'}`}
                            />
                        </div>
                    )
                })}
            </div>

            <div className="mt-4 flex justify-between items-center">
                <span className="text-[10px] font-bold text-[var(--text-muted)] capitalize tracking-widest">
                    {totalVotes} {totalVotes === 1 ? 'VOTO' : 'VOTOS'}
                </span>
                <button
                    onClick={() => setShowCreate(true)}
                    className="text-[10px] font-bold text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                >
                    NUEVA
                </button>
            </div>
        </div>
    )
}

// src/components/ClubRanking.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'

interface ClubData {
    equipo: string
    avg_rating: number
    total_logs: number
    logo?: string
}

export function ClubRanking() {
    const [clubs, setClubs] = useState<ClubData[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchRanking = async () => {
            try {
                // Get match logs grouped by equipo_local and equipo_visitante teams
                const { data: logs } = await supabase
                    .from('match_logs')
                    .select('equipo_local, equipo_visitante, rating, logo_local, logo_visitante')

                if (!logs || logs.length === 0) {
                    setLoading(false)
                    return
                }

                // Aggregate ratings per team
                const teamMap = new Map<string, { total: number; count: number; logo?: string }>()

                logs.forEach(log => {
                    // Local team
                    if (log.equipo_local) {
                        const current = teamMap.get(log.equipo_local) || { total: 0, count: 0 }
                        current.total += log.rating || 0
                        current.count++
                        if (log.logo_local) current.logo = log.logo_local
                        teamMap.set(log.equipo_local, current)
                    }

                    // Visitante team
                    if (log.equipo_visitante) {
                        const current = teamMap.get(log.equipo_visitante) || { total: 0, count: 0 }
                        current.total += log.rating || 0
                        current.count++
                        if (log.logo_visitante) current.logo = log.logo_visitante
                        teamMap.set(log.equipo_visitante, current)
                    }
                })

                // Convert to array and sort
                const ranking: ClubData[] = Array.from(teamMap.entries())
                    .filter(([_, data]) => data.count >= 2) // Min 2 logs
                    .map(([equipo, data]) => ({
                        equipo,
                        avg_rating: data.total / data.count,
                        total_logs: data.count,
                        logo: data.logo,
                    }))
                    .sort((a, b) => b.avg_rating - a.avg_rating)
                    .slice(0, 20) // Top 20

                setClubs(ranking)
            } catch (err) {
                console.error('Error fetching club ranking:', err)
            } finally {
                setLoading(false)
            }
        }

        fetchRanking()
    }, [])

    const getMedal = (index: number) => {
        if (index === 0) return '🥇'
        if (index === 1) return '🥈'
        if (index === 2) return '🥉'
        return `${index + 1}`
    }

    const getRatingColor = (rating: number) => {
        if (rating >= 8) return '#10b981'
        if (rating >= 6) return '#fbbf24'
        if (rating >= 4) return '#f59e0b'
        return '#ef4444'
    }

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-6">
                <div className="animate-pulse space-y-3">
                    {[1, 2, 3, 4, 5].map(i => (
                        <div key={i} className="h-12 bg-[var(--background)] rounded-xl" />
                    ))}
                </div>
            </div>
        )
    }

    if (clubs.length === 0) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-8 text-center">
                <p className="text-3xl mb-2">🏆</p>
                <p className="text-xs text-[var(--text-muted)] italic">
                    Todavía no hay suficientes reseñas
                </p>
            </div>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl overflow-hidden shadow-sm">
            <div className="p-4 border-b border-[var(--card-border)]">
                <h3 className="text-sm font-bold text-[var(--foreground)] flex items-center justify-between">
                    Ranking de Clubes
                    <span className="text-[10px] text-[var(--text-muted)] font-normal">Top 20</span>
                </h3>
            </div>

            <table className="w-full text-left border-collapse">
                <thead className="bg-[var(--background)]">
                    <tr className="border-b border-[var(--card-border)]">
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)] w-10 text-center">#</th>
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)]">Equipo</th>
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)] text-right">Logs</th>
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)] text-center">Rating</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-[var(--card-border)]">
                    {clubs.map((club, idx) => (
                        <tr key={club.equipo} className="hover:bg-[var(--background)] transition-colors">
                            <td className="px-4 py-3 text-sm font-medium text-center text-[var(--text-muted)] w-10">
                                {idx + 1}
                            </td>
                            <td className="px-4 py-3">
                                <div className="flex items-center gap-3">
                                    {club.logo && (
                                        <img src={club.logo} alt="" className="w-6 h-6 object-contain" />
                                    )}
                                    <span className="text-sm font-semibold truncate max-w-[120px]">{club.equipo}</span>
                                </div>
                            </td>
                            <td className="px-4 py-3 text-xs text-[var(--text-muted)] text-right">
                                {club.total_logs}
                            </td>
                            <td className="px-4 py-3 text-center">
                                <span
                                    className="inline-block px-2 py-1 text-xs font-bold text-white rounded-lg shadow-sm"
                                    style={{ backgroundColor: getRatingColor(club.avg_rating) }}
                                >
                                    {club.avg_rating.toFixed(1)}
                                </span>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    )
}

// src/components/CommentSection.tsx
'use client'

import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { LoadingSpinner } from './LoadingSpinner'
import { Heart, Reply } from 'lucide-react'
import type { Comentario } from '@/types'
import { Button } from './ui/Button'

interface CommentSectionProps {
    partidoId: string | number
}

export function CommentSection({ partidoId }: CommentSectionProps) {
    const { user } = useAuth()
    const router = useRouter()
    const [comments, setComments] = useState<Comentario[]>([])
    const [newComment, setNewComment] = useState('')
    const [loading, setLoading] = useState(true)
    const [sending, setSending] = useState(false)
    const [replyTo, setReplyTo] = useState<{ username: string; id: string } | null>(null)
    const scrollRef = useRef<HTMLDivElement>(null)
    const inputRef = useRef<HTMLInputElement>(null)

    const partidoIdStr = String(partidoId)

    // Cargar comentarios iniciales
    useEffect(() => {
        const fetchComments = async () => {
            try {
                const { data, error } = await supabase
                    .from('comentarios')
                    .select(`
                        *,
                        profile:profiles(username, avatar_url),
                        likes_count:comentario_likes(count)
                    `)
                    .eq('partido_id', partidoIdStr)
                    .order('created_at', { ascending: true })

                if (error) {
                    console.error('Error fetching comments:', error)
                } else if (data) {
                    const processedComments = data.map((c: any) => ({
                        ...c,
                        likes_count: c.likes_count[0]?.count || 0,
                    }))

                    if (user) {
                        const { data: userLikes } = await supabase
                            .from('comentario_likes')
                            .select('comentario_id')
                            .eq('user_id', user.id)

                        const likedIds = new Set(userLikes?.map(l => l.comentario_id) || [])
                        processedComments.forEach(c => c.is_liked = likedIds.has(c.id))
                    }

                    setComments(processedComments)
                    scrollToBottom()
                }
            } catch (err: any) {
                console.error('Error in fetchComments:', err)
            } finally {
                setLoading(false)
            }
        }

        fetchComments()

        // Suscripción a nuevos comentarios
        const channel = supabase
            .channel(`partido:${partidoIdStr}`)
            .on('postgres_changes', {
                event: 'INSERT',
                schema: 'public',
                table: 'comentarios',
                filter: `partido_id=eq.${partidoIdStr}`
            }, async (payload) => {
                const { data } = await supabase
                    .from('comentarios')
                    .select(`*, profile:profiles(username, avatar_url)`)
                    .eq('id', payload.new.id)
                    .single()

                if (data) {
                    setComments(prev => [...prev, data])
                    scrollToBottom()
                }
            })
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [partidoIdStr])

    const scrollToBottom = () => {
        setTimeout(() => {
            scrollRef.current?.scrollIntoView({ behavior: 'smooth' })
        }, 100)
    }

    const handleReply = (username: string, commentId: string) => {
        setReplyTo({ username, id: commentId })
        inputRef.current?.focus()
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!user || !newComment.trim() || sending) return

        setSending(true)
        try {
            // Prepend reply mention if replying
            const mensaje = replyTo
                ? `@${replyTo.username} ${newComment.trim()}`
                : newComment.trim()

            const { error } = await supabase
                .from('comentarios')
                .insert({
                    partido_id: partidoIdStr,
                    user_id: user.id,
                    mensaje: newComment.trim(),
                    parent_id: replyTo?.id || null
                })

            if (error) throw error
            setNewComment('')
            setReplyTo(null)
        } catch (error) {
            console.error('Error enviando comentario:', error)
        } finally {
            setSending(false)
        }
    }

    const toggleCommentLike = async (commentId: string) => {
        if (!user) return

        const comment = comments.find(c => c.id === commentId)
        if (!comment) return

        const wasLiked = comment.is_liked

        // Optimistic update
        setComments(prev => prev.map(c =>
            c.id === commentId
                ? { ...c, is_liked: !wasLiked, likes_count: (c.likes_count || 0) + (wasLiked ? -1 : 1) }
                : c
        ))

        try {
            if (wasLiked) {
                await supabase
                    .from('comentario_likes')
                    .delete()
                    .eq('comentario_id', commentId)
                    .eq('user_id', user.id)
            } else {
                await supabase
                    .from('comentario_likes')
                    .insert({ comentario_id: commentId, user_id: user.id })
            }
        } catch {
            // Revert
            setComments(prev => prev.map(c =>
                c.id === commentId
                    ? { ...c, is_liked: wasLiked, likes_count: (c.likes_count || 0) + (wasLiked ? 1 : -1) }
                    : c
            ))
        }
    }

    const formatTime = (dateStr: string) => {
        const date = new Date(dateStr)
        const now = new Date()
        const diff = Math.floor((now.getTime() - date.getTime()) / 60000)

        if (diff < 1) return 'Ahora'
        if (diff < 60) return `Hace ${diff} min`
        if (diff < 1440) return `Hace ${Math.floor(diff / 60)} h`
        return date.toLocaleDateString()
    }

    // Render UI (Teaser for Unauthenticated Users)
    if (!user) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden mb-6 relative" style={{ borderRadius: 'var(--radius)' }}>
                {/* Header */}
                <div className="p-4 border-b border-[var(--card-border)] bg-[var(--card-bg)]">
                    <h3 className="text-xs font-black capitalize tracking-widest flex items-center gap-2">
                        💬 Reseñas
                        <span className="bg-[var(--background)] border border-[var(--card-border)] text-[9px] px-2 py-0.5 text-[var(--text-muted)]" style={{ borderRadius: 'var(--radius)' }}>
                            ...
                        </span>
                    </h3>
                </div>

                {/* Blurred Content Teaser */}
                <div className="h-[250px] relative p-4 space-y-4 bg-[var(--background)] overflow-hidden cursor-pointer" onClick={() => router.push('/login')}>
                    <div className="absolute inset-0 z-10 bg-black/5 backdrop-blur-[3px]" />
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none">
                        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-5 max-w-[280px] text-center transform scale-105 pointer-events-auto" style={{ borderRadius: 'var(--radius)' }}>
                            <h4 className="font-black text-sm capitalize italic tracking-tighter mb-2 text-[var(--foreground)]">Análisis de los hinchas</h4>
                            <p className="text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-4">Iniciá sesión para leer las reseñas.</p>
                            <Button fullWidth onClick={() => router.push('/login')}>
                                Iniciar sesión
                            </Button>
                        </div>
                    </div>

                    {/* Fake Comments for visual effect */}
                    <div className="flex gap-3 opacity-40 blur-[2px]">
                        <div className="w-8 h-8 rounded-full bg-blue-500/20" />
                        <div>
                            <div className="h-3 w-24 bg-[var(--border)] rounded mb-2" />
                            <div className="h-4 w-48 bg-[var(--border)] rounded" />
                        </div>
                    </div>

                    <div className="text-center absolute bottom-4 left-0 right-0 z-20 pointer-events-none opacity-50 blur-[1px]">
                        <p className="text-[10px] font-black capitalize tracking-widest text-[#16a34a]">Ver más mensajes...</p>
                    </div>
                </div>

                {/* Disabled Input */}
                <div className="p-4 bg-[var(--card-bg)] border-t border-[var(--card-border)] opacity-50 relative pointer-events-none">
                    <input
                        type="text"
                        disabled
                        placeholder="INICIA SESIÓN PARA COMENTAR..."
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] pl-4 pr-12 py-3 text-xs font-black capitalize tracking-widest focus:outline-none"
                        style={{ borderRadius: 'var(--radius)' }}
                    />
                </div>
            </div>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden mb-6" style={{ borderRadius: 'var(--radius)' }}>
            {/* Header */}
            <div className="p-4 border-b border-[var(--card-border)] bg-[var(--card-bg)]">
                <h3 className="text-xs font-black capitalize tracking-widest flex items-center gap-2">
                    💬 Reseñas
                    <span className="bg-[var(--background)] border border-[var(--card-border)] text-[9px] font-black px-2 py-0.5 text-[var(--text-muted)]" style={{ borderRadius: 'var(--radius)' }}>
                        {comments.length}
                    </span>
                </h3>
            </div>

            {/* Lista de Comentarios */}
            <div className="h-[350px] overflow-y-auto p-4 space-y-3 bg-[var(--background)]">
                {loading ? (
                    <div className="flex justify-center py-4">
                        <LoadingSpinner />
                    </div>
                ) : comments.length === 0 ? (
                    <div className="text-center py-12 text-[var(--text-muted)] text-sm">
                        <p>Sé el primero en comentar 👇</p>
                    </div>
                ) : (
                    comments
                        .filter(c => !c.parent_id) // Root comments
                        .map((comment) => {
                            const replies = comments.filter(r => r.parent_id === comment.id)

                            return (
                                <div key={comment.id} className="space-y-3">
                                    <CommentItem
                                        comment={comment}
                                        user={user}
                                        onReply={handleReply}
                                        onLike={toggleCommentLike}
                                        formatTime={formatTime}
                                    />

                                    {/* Replies */}
                                    {replies.length > 0 && (
                                        <div className="ml-8 space-y-3 border-l-2 border-[var(--hover-bg)] pl-4">
                                            {replies.map(reply => (
                                                <CommentItem
                                                    key={reply.id}
                                                    comment={reply}
                                                    user={user}
                                                    onReply={handleReply}
                                                    onLike={toggleCommentLike}
                                                    formatTime={formatTime}
                                                    isReply
                                                />
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )
                        })
                )}
                <div ref={scrollRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-[var(--card-bg)] border-t border-[var(--card-border)]">
                {/* Reply indicator */}
                {replyTo && (
                    <div className="flex items-center justify-between mb-2 px-2 py-1.5 bg-[#16a34a]/5 border border-[#16a34a]/20" style={{ borderRadius: 'var(--radius)' }}>
                        <span className="text-[10px] text-[#16a34a] font-black capitalize tracking-widest">
                            ↩ Respondiendo a @{replyTo.username}
                        </span>
                        <button
                            onClick={() => setReplyTo(null)}
                            className="text-[10px] text-[var(--text-muted)] hover:text-[var(--foreground)]"
                        >
                            ✕
                        </button>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="relative">
                    <input
                        ref={inputRef}
                        type="text"
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                        placeholder={replyTo ? `RESPONDER A @${replyTo.username.toUpperCase()}...` : 'ESCRIBIR RESEÑA...'}
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] pl-4 pr-12 py-3 text-xs font-black capitalize tracking-widest focus:outline-none focus:border-[#16a34a] transition-colors placeholder-[var(--text-muted)] text-[var(--foreground)]"
                        style={{ borderRadius: 'var(--radius)' }}
                        maxLength={500}
                    />
                    <button
                        type="submit"
                        disabled={!newComment.trim() || sending}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 text-[#16a34a] disabled:text-[var(--text-muted)] disabled:cursor-not-allowed hover:scale-110 transition-transform"
                    >
                        ➤
                    </button>
                </form>
            </div>
        </div>
    )
}

function CommentItem({
    comment,
    user,
    onReply,
    onLike,
    formatTime,
    isReply = false
}: {
    comment: Comentario
    user: any
    onReply: (username: string, id: string) => void
    onLike: (id: string) => void
    formatTime: (date: string) => string
    isReply?: boolean
}) {
    return (
        <div className="flex gap-3 animate-fade-in group">
            {/* Avatar */}
            <div
                className={`bg-[var(--hover-bg)] border border-[var(--card-border)] flex items-center justify-center flex-shrink-0 text-[10px] font-black overflow-hidden hover:ring-2 hover:ring-[#16a34a]/50 transition-all ${isReply ? 'w-6 h-6' : 'w-8 h-8'}`}
                onClick={(e) => {
                    e.stopPropagation()
                    if (comment.user_id) window.location.href = `/perfil/${comment.user_id}`
                }}
                style={{ borderRadius: 'var(--radius)' }}
            >
                {comment.profile?.avatar_url ? (
                    <img src={comment.profile.avatar_url} alt="" className="w-full h-full object-cover" />
                ) : (
                    comment.profile?.username?.charAt(0).toUpperCase() || '👤'
                )}
            </div>

            <div className="flex-1 min-w-0">
                <div className="flex items-baseline gap-2 mb-0.5">
                    <span
                        className="text-[11px] font-black text-[var(--foreground)] cursor-pointer hover:text-[#16a34a] hover:underline transition-colors capitalize italic tracking-tighter"
                        onClick={(e) => {
                            e.stopPropagation()
                            if (comment.user_id) window.location.href = `/perfil/${comment.user_id}`
                        }}
                    >
                        {comment.profile?.username || 'Usuario'}
                    </span>
                    <span className="text-[9px] font-black capitalize tracking-widest text-[var(--text-muted)]">
                        {formatTime(comment.created_at)}
                    </span>
                </div>

                <p className="text-sm text-[var(--foreground)] break-words leading-relaxed opacity-90">
                    {comment.mensaje}
                </p>

                <div className="flex items-center gap-3 mt-1.5">
                    {/* Reply button */}
                    {user && !isReply && (
                        <button
                            onClick={() => onReply(comment.profile?.username || 'Usuario', comment.id)}
                            className="text-[9px] font-black capitalize tracking-widest text-[var(--text-muted)] hover:text-[#16a34a] flex items-center gap-1 transition-colors"
                        >
                            <Reply size={10} />
                            Responder
                        </button>
                    )}

                    {/* Like button */}
                    <button
                        onClick={() => onLike(comment.id)}
                        className={`text-[10px] flex items-center gap-1 transition-all ${comment.is_liked ? 'text-red-500 font-bold' : 'text-[var(--text-muted)] hover:text-red-500'}`}
                    >
                        <Heart size={10} fill={comment.is_liked ? 'currentColor' : 'none'} />
                        {comment.likes_count || 0}
                    </button>
                </div>
            </div>
        </div>
    )
}

// src/components/CommunityHighlights.tsx
// Shows best-rated matches + popular reviews on the Home page
'use client'

import { useState, useEffect } from 'react'
import Link from 'next/link'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { TeamLogo } from '@/components/TeamLogo'
import { Star, TrendingUp, MessageSquare } from 'lucide-react'

interface TopMatch {
    equipo_local: string
    equipo_visitante: string
    logo_local?: string
    logo_visitante?: string
    goles_local?: number
    goles_visitante?: number
    liga?: string
    avg_rating: number
    total_logs: number
}

interface PopularReview {
    id: string
    equipo_local: string
    equipo_visitante: string
    goles_local?: number
    goles_visitante?: number
    rating_partido: number
    review_text: string
    mood?: string
    username: string
    avatar_url?: string
    likes_count: number
}

const MOOD_MAP: Record<string, string> = {
    euforia: '🤩', contento: '😊', indiferente: '😐',
    caliente: '😤', destruido: '😢', locura: '🤯',
}

export function CommunityHighlights() {
    const [topMatches, setTopMatches] = useState<TopMatch[]>([])
    const [popularReviews, setPopularReviews] = useState<PopularReview[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchHighlights = async () => {
            try {
                // Fetch top-rated matches (aggregate from match_logs)
                const { data: logsData } = await supabase
                    .from('match_logs')
                    .select('equipo_local, equipo_visitante, logo_local, logo_visitante, goles_local, goles_visitante, liga, rating_partido')
                    .eq('is_private', false)
                    .gte('created_at', new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString())
                    .order('created_at', { ascending: false })
                    .limit(100)

                if (logsData && logsData.length > 0) {
                    // Group by match (local vs visitante) and compute averages
                    const matchMap = new Map<string, { entries: typeof logsData; sum: number }>()

                    for (const log of logsData) {
                        const key = `${log.equipo_local}-${log.equipo_visitante}`
                        const existing = matchMap.get(key) || { entries: [], sum: 0 }
                        existing.entries.push(log)
                        existing.sum += log.rating_partido
                        matchMap.set(key, existing)
                    }

                    const ranked = Array.from(matchMap.entries())
                        .filter(([_, v]) => v.entries.length >= 2) // At least 2 logs
                        .map(([_, v]) => {
                            const first = v.entries[0]
                            return {
                                equipo_local: first.equipo_local,
                                equipo_visitante: first.equipo_visitante,
                                logo_local: first.logo_local,
                                logo_visitante: first.logo_visitante,
                                goles_local: first.goles_local,
                                goles_visitante: first.goles_visitante,
                                liga: first.liga,
                                avg_rating: Math.round((v.sum / v.entries.length) * 10) / 10,
                                total_logs: v.entries.length,
                            }
                        })
                        .sort((a, b) => b.avg_rating - a.avg_rating)
                        .slice(0, 3)

                    setTopMatches(ranked)
                }

                // Fetch popular reviews (most recent with text)
                const { data: reviewsData } = await supabase
                    .from('match_logs')
                    .select('id, equipo_local, equipo_visitante, goles_local, goles_visitante, rating_partido, review_text, mood, user_id')
                    .eq('is_private', false)
                    .not('review_text', 'is', null)
                    .order('created_at', { ascending: false })
                    .limit(10)

                if (reviewsData && reviewsData.length > 0) {
                    // Fetch usernames for these reviews
                    const userIds = [...new Set(reviewsData.map(r => r.user_id))]
                    const { data: profiles } = await supabase
                        .from('profiles')
                        .select('id, username, avatar_url')
                        .in('id', userIds)

                    const profileMap = new Map(profiles?.map(p => [p.id, p]) || [])

                    const reviews: PopularReview[] = reviewsData
                        .filter(r => r.review_text && r.review_text.length > 10)
                        .slice(0, 3)
                        .map(r => ({
                            id: r.id,
                            equipo_local: r.equipo_local,
                            equipo_visitante: r.equipo_visitante,
                            goles_local: r.goles_local,
                            goles_visitante: r.goles_visitante,
                            rating_partido: r.rating_partido,
                            review_text: r.review_text!,
                            mood: r.mood,
                            username: profileMap.get(r.user_id)?.username || 'Anónimo',
                            avatar_url: profileMap.get(r.user_id)?.avatar_url,
                            likes_count: 0,
                        }))

                    setPopularReviews(reviews)
                }
            } catch (err) {
                console.error('Error fetching community highlights:', err)
            } finally {
                setLoading(false)
            }
        }

        fetchHighlights()
    }, [])

    if (loading) {
        return (
            <div className="space-y-4 animate-pulse">
                <div className="h-32 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl" />
            </div>
        )
    }

    // Fallback Mock State if no data
    if (topMatches.length === 0 && popularReviews.length === 0) {
        return (
            <div className="space-y-4 opacity-70">
                <span className="text-[10px] font-black capitalize text-[var(--accent)] tracking-widest block text-center">Datos de Ejemplo</span>

                {/* Mock Top Matches */}
                <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl overflow-hidden shadow-sm pointer-events-none">
                    <div className="px-4 py-3 border-b border-[var(--card-border)] flex items-center gap-2">
                        <TrendingUp size={14} className="text-[var(--accent)]" />
                        <h3 className="text-xs font-black capitalize tracking-widest">Partidos mejor calificados</h3>
                    </div>
                    <div className="divide-y divide-[var(--card-border)]">
                        <div className="flex items-center gap-3 p-3">
                            <span className="text-sm font-black text-[var(--text-muted)] w-5 text-center">1</span>
                            <div className="flex-1 min-w-0">
                                <div className="text-xs font-bold truncate">Boca Juniors 1-1 River Plate</div>
                                <div className="text-[10px] text-[var(--text-muted)]">Liga Profesional</div>
                            </div>
                            <div className="flex items-center gap-1 bg-[#f59e0b]/10 text-[#f59e0b] px-2 py-1 rounded-full border border-[#f59e0b]/20">
                                <Star size={10} className="fill-[#f59e0b]" />
                                <span className="text-xs font-black">9.5</span>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Mock Popular Reviews */}
                <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl overflow-hidden shadow-sm pointer-events-none">
                    <div className="px-4 py-3 border-b border-[var(--card-border)] flex items-center gap-2">
                        <MessageSquare size={14} className="text-[var(--accent-blue)]" />
                        <h3 className="text-xs font-black capitalize tracking-widest">Reseñas de la comunidad</h3>
                    </div>
                    <div className="p-3">
                        <div className="flex items-center gap-2 mb-2">
                            <span className="text-[10px] font-bold text-[var(--text-muted)]">UsuarioEjemplo</span>
                            <span className="text-[10px] text-[var(--text-muted)]">·</span>
                            <span className="text-[10px] font-medium">Boca Juniors 1-1 River Plate</span>
                        </div>
                        <p className="text-xs text-[var(--foreground)] line-clamp-2 leading-relaxed">
                            "Un partido increíble, de ida y vuelta constante. Los dos equipos dejaron todo en la cancha."
                        </p>
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="space-y-4">
            {/* Top Rated Matches */}
            {topMatches.length > 0 && (
                <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl overflow-hidden shadow-sm">
                    <div className="px-4 py-3 border-b border-[var(--card-border)] flex items-center gap-2">
                        <TrendingUp size={14} className="text-[var(--accent)]" />
                        <h3 className="text-xs font-black capitalize tracking-widest">Partidos mejor calificados</h3>
                    </div>
                    <div className="divide-y divide-[var(--card-border)]">
                        {topMatches.map((match, i) => (
                            <motion.div
                                key={`${match.equipo_local}-${match.equipo_visitante}`}
                                initial={{ opacity: 0, x: -10 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: i * 0.1 }}
                                className="flex items-center gap-3 p-3"
                            >
                                <span className="text-sm font-black text-[var(--text-muted)] w-5 text-center">
                                    {i + 1}
                                </span>
                                <div className="flex items-center -space-x-2 shrink-0">
                                    <TeamLogo src={match.logo_local} teamName={match.equipo_local} size={22} className="ring-2 ring-[var(--card-bg)]" />
