                            </motion.div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    )
}

// src/components/CommunityRating.tsx
'use client'

import { useState, useEffect } from 'react'
import { Users, Star } from 'lucide-react'
import { supabase } from '@/lib/supabase'

interface CommunityRatingProps {
    partidoId: string | number
    equipoLocal: string
    equipoVisitante: string
    equipos?: any[] // Optional so it doesn't break if not passed
    compact?: boolean
}

export function CommunityRating({ partidoId, equipoLocal, equipoVisitante, equipos = [], compact = false }: CommunityRatingProps) {
    const [stats, setStats] = useState({
        total_reviews: 0,
        avg_rating: 0,
        avg_arbitro: 0,
        avg_atmosfera: 0,
        avg_dt: 0,
        top_estrella: '',
        top_villano: '',
        playerRatings: [] as { id: number, name: string, avg: number, votes: number }[]
    })
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchCommunityStats = async () => {
            try {
                const { data } = await supabase
                    .from('match_logs')
                    .select('rating_partido, rating_arbitro, rating_atmosfera, rating_dt, jugador_estrella, jugador_villano')
                    .eq('partido_id', String(partidoId))
                    .eq('is_private', false)

                if (data && data.length > 0) {
                    const total = data.length
                    const avgRating = data.reduce((acc, l) => acc + l.rating_partido, 0) / total
                    const avgArbitro = data.filter(l => l.rating_arbitro).reduce((acc, l) => acc + (l.rating_arbitro || 0), 0) / (data.filter(l => l.rating_arbitro).length || 1)
                    const avgAtmosfera = data.filter(l => l.rating_atmosfera).reduce((acc, l) => acc + (l.rating_atmosfera || 0), 0) / (data.filter(l => l.rating_atmosfera).length || 1)
                    const avgDt = data.filter(l => l.rating_dt).reduce((acc, l) => acc + (l.rating_dt || 0), 0) / (data.filter(l => l.rating_dt).length || 1)

                    // Count most mentioned estrella/villano
                    const estrellaCount: Record<string, number> = {}
                    const villanoCount: Record<string, number> = {}
                    data.forEach(l => {
                        if (l.jugador_estrella) estrellaCount[l.jugador_estrella] = (estrellaCount[l.jugador_estrella] || 0) + 1
                        if (l.jugador_villano) villanoCount[l.jugador_villano] = (villanoCount[l.jugador_villano] || 0) + 1
                    })

                    const topEstrella = Object.entries(estrellaCount).sort((a, b) => b[1] - a[1])[0]?.[0] || ''
                    const topVillano = Object.entries(villanoCount).sort((a, b) => b[1] - a[1])[0]?.[0] || ''

                    // Fetch numeric player ratings (1-10) from votaciones
                    const { data: votosData } = await supabase
                        .from('votaciones')
                        .select('jugador_id, nota')
                        .eq('partido_id', String(partidoId))
                    
                    let aggregatedPlayers: { id: number, name: string, avg: number, votes: number }[] = []

                    if (votosData && votosData.length > 0 && equipos.length > 0) {
                        // Map jugadorId to name
                        const playerMap = new Map<number, string>()
                        equipos.forEach(eq => {
                            eq.titulares?.forEach((t: any) => playerMap.set(t.id, t.nombre))
                            eq.suplentes?.forEach((t: any) => playerMap.set(t.id, t.nombre))
                        })

                        const playerScores: Record<number, { total: number, count: number }> = {}
                        votosData.forEach(voto => {
                            if (!playerScores[voto.jugador_id]) playerScores[voto.jugador_id] = { total: 0, count: 0 }
                            playerScores[voto.jugador_id].total += voto.nota
                            playerScores[voto.jugador_id].count += 1
                        })

                        aggregatedPlayers = Object.entries(playerScores)
                            .filter(([id, data]) => playerMap.has(Number(id)))
                            .map(([id, data]) => ({
                                id: Number(id),
                                name: playerMap.get(Number(id)) || 'Desconocido',
                                avg: data.total / data.count,
                                votes: data.count
                            }))
                            .sort((a, b) => b.avg - a.avg) // Best first
                    }

                    setStats({
                        total_reviews: total,
                        avg_rating: avgRating,
                        avg_arbitro: avgArbitro,
                        avg_atmosfera: avgAtmosfera,
                        avg_dt: avgDt,
                        top_estrella: topEstrella,
                        top_villano: topVillano,
                        playerRatings: aggregatedPlayers
                    })
                }
            } catch {
                console.log('Community stats no disponibles')
            } finally {
                setLoading(false)
            }
        }

        fetchCommunityStats()
    }, [partidoId])

    if (loading || stats.total_reviews === 0) return null

    if (compact) {
        return (
            <div className="flex items-center gap-3 px-3 py-1.5 bg-[var(--background)] rounded-full border border-[var(--card-border)] shadow-sm">
                <div className="text-sm font-black text-[#f59e0b] flex items-center gap-1">
                    <Star size={14} fill="#f59e0b" />
                    {stats.avg_rating.toFixed(1)}
                </div>
                <div className="w-px h-3 bg-[var(--card-border)]" />
                <div className="flex items-center gap-1.5 text-[10px] text-[var(--text-muted)] font-black uppercase tracking-widest">
                    <Users size={12} className="text-[#6366f1]" />
                    {stats.total_reviews} reseñas
                </div>
            </div>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-4">
            <div className="flex items-center gap-2 mb-3">
                <Users size={14} className="text-[#6366f1]" />
                <h3 className="text-sm font-bold">Rating de la comunidad</h3>
                <span className="text-[10px] text-[var(--text-muted)]">{stats.total_reviews} reseñas</span>
            </div>

            {/* Main community rating */}
            <div className="flex items-center gap-3 mb-3">
                <div className="text-3xl font-black text-[#f59e0b]">{stats.avg_rating.toFixed(1)}</div>
                <div className="flex-1">
                    <div className="flex gap-0.5 mb-1">
                        {[1, 2, 3, 4, 5].map(star => (
                            <Star
                                key={star}
                                size={14}
                                fill={star <= Math.round(stats.avg_rating) ? '#f59e0b' : 'none'}
                                stroke={star <= Math.round(stats.avg_rating) ? '#f59e0b' : 'var(--text-muted)'}
                            />
                        ))}
                    </div>
                    <div className="text-[10px] text-[var(--text-muted)]">
                        Basado en {stats.total_reviews} opiniones
                    </div>
                </div>
            </div>

            {/* Sub-ratings */}
            <div className="grid grid-cols-3 gap-2 mb-3">
                {stats.avg_arbitro > 0 && (
                    <div className="text-center p-2 rounded-lg bg-[var(--background)]">
                        <div className="text-xs font-bold">{stats.avg_arbitro.toFixed(1)}</div>
                        <div className="text-[9px] text-[var(--text-muted)]">🟨 Árbitro</div>
                    </div>
                )}
                {stats.avg_atmosfera > 0 && (
                    <div className="text-center p-2 rounded-lg bg-[var(--background)]">
                        <div className="text-xs font-bold">{stats.avg_atmosfera.toFixed(1)}</div>
                        <div className="text-[9px] text-[var(--text-muted)]">🏟️ Atmósfera</div>
                    </div>
                )}
                {stats.avg_dt > 0 && (
                    <div className="text-center p-2 rounded-lg bg-[var(--background)]">
                        <div className="text-xs font-bold">{stats.avg_dt.toFixed(1)}</div>
                        <div className="text-[9px] text-[var(--text-muted)]">🧥 DT</div>
                    </div>
                )}
            </div>

            {/* Top estrella/villano */}
            {(stats.top_estrella || stats.top_villano) && (
                <div className="flex gap-2">
                    {stats.top_estrella && (
                        <span className="flex-1 text-center text-[10px] px-2 py-1.5 rounded-lg bg-[#f59e0b]/10 text-[#f59e0b] font-medium">
                            ⭐ {stats.top_estrella}
                        </span>
                    )}
                    {stats.top_villano && (
                        <span className="flex-1 text-center text-[10px] px-2 py-1.5 rounded-lg bg-red-500/10 text-red-400 font-medium">
                            😈 {stats.top_villano}
                        </span>
                    )}
                </div>
            )}

            {/* Top Players Table 1-10 */}
            {stats.playerRatings.length > 0 && (
                <div className="mt-6 border-t border-[var(--card-border)] pt-4">
                    <h4 className="text-xs font-bold mb-3">Rendimiento (1-10)</h4>
                    
                    <div className="grid grid-cols-2 gap-4">
                        {/* Mejores */}
                        <div className="space-y-2">
                            <h5 className="text-[10px] font-black text-[var(--accent-green)] uppercase tracking-widest pl-1 mb-2">El Podio</h5>
                            {stats.playerRatings.slice(0, 3).map(p => (
                                <div key={p.id} className="flex items-center justify-between text-xs bg-[var(--background)] px-2 py-1.5 rounded-md border border-[var(--card-border)]">
                                    <span className="truncate max-w-[80px] font-medium capitalize" title={p.name}>{p.name.split(' ').pop()}</span>
                                    <div className="flex items-center gap-1.5">
                                        <span className={`px-1.5 py-0.5 rounded font-bold text-[10px] ${p.avg >= 6 ? 'bg-green-500/20 text-green-600 dark:text-green-400' : 'bg-yellow-500/20 text-yellow-600 dark:text-yellow-400'}`}>
                                            {p.avg.toFixed(1)}
                                        </span>
                                    </div>
                                </div>
                            ))}
                        </div>
                        
                        {/* Peores */}
                        <div className="space-y-2">
                            <h5 className="text-[10px] font-black text-red-500 uppercase tracking-widest pl-1 mb-2">Bajo Lupa</h5>
                            {[...stats.playerRatings].reverse().slice(0, 3).filter(p => p.avg < 5).map(p => (
                                <div key={p.id} className="flex items-center justify-between text-xs bg-[var(--background)] px-2 py-1.5 rounded-md border border-[var(--card-border)]">
                                    <span className="truncate max-w-[80px] font-medium capitalize" title={p.name}>{p.name.split(' ').pop()}</span>
                                    <div className="flex items-center gap-1.5">
                                        <span className="px-1.5 py-0.5 rounded font-bold text-[10px] bg-red-500/20 text-red-600 dark:text-red-400">
                                            {p.avg.toFixed(1)}
                                        </span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                    <p className="text-[9px] text-[var(--text-muted)] mt-2 text-center opacity-70">
                        Top 3 mejores y peores (nota media global)
                    </p>
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Trophy, Star, TrendingUp, Users, MessageSquare } from 'lucide-react'
import { supabase } from '@/lib/supabase'
import { TeamLogo } from '@/components/TeamLogo'
import { hapticFeedback } from '@/lib/helpers'

interface ComunidadContentProps {
    ligaExterna: string
}

interface RankedItem {
    name: string
    id?: string
    logo?: string
    rating: number
    count: number
}

export function ComunidadContent({ ligaExterna }: ComunidadContentProps) {
    const [topTeams, setTopTeams] = useState<RankedItem[]>([])
    const [topPlayers, setTopPlayers] = useState<RankedItem[]>([])
    const [loading, setLoading] = useState(true)
    const [activeSection, setActiveSection] = useState<'teams' | 'players' | 'projections'>('teams')

    useEffect(() => {
        const fetchComunidadData = async () => {
            setLoading(true)
            try {
                // 1. Fetch Top Teams from match_logs
                const { data: logs } = await supabase
                    .from('match_logs')
                    .select('equipo_local, equipo_visitante, logo_local, logo_visitante, rating_partido')
                    .eq('liga', ligaExterna)

                if (logs) {
                    const teamMap = new Map<string, { total: number; count: number; logo?: string }>()
                    logs.forEach(log => {
                        const rating = Number(log.rating_partido) || 0
                        if (log.equipo_local) {
                            const cur = teamMap.get(log.equipo_local) || { total: 0, count: 0 }
                            cur.total += rating
                            cur.count++
                            if (log.logo_local) cur.logo = log.logo_local
                            teamMap.set(log.equipo_local, cur)
                        }
                        if (log.equipo_visitante) {
                            const cur = teamMap.get(log.equipo_visitante) || { total: 0, count: 0 }
                            cur.total += rating
                            cur.count++
                            if (log.logo_visitante) cur.logo = log.logo_visitante
                            teamMap.set(log.equipo_visitante, cur)
                        }
                    })
                    const sortedTeams = Array.from(teamMap.entries())
                        .map(([name, data]) => ({
                            name,
                            logo: data.logo,
                            rating: data.total / data.count,
                            count: data.count
                        }))
                        .sort((a, b) => b.rating - a.rating)
                        .slice(0, 5)
                    setTopTeams(sortedTeams)
                }

                // 2. Fetch Top Players from match_log_player_ratings joined with match_logs
                // Note: Using !inner filter for liga
                const { data: playerRatings } = await supabase
                    .from('match_log_player_ratings')
                    .select(`
                        player_name,
                        rating,
                        match_logs!inner(liga)
                    `)
                    .eq('match_logs.liga', ligaExterna)

                if (playerRatings) {
                    const playerMap = new Map<string, { total: number; count: number }>()
                    playerRatings.forEach((pr: any) => {
                        const cur = playerMap.get(pr.player_name) || { total: 0, count: 0 }
                        cur.total += Number(pr.rating) || 0
                        cur.count++
                        playerMap.set(pr.player_name, cur)
                    })
                    const sortedPlayers = Array.from(playerMap.entries())
                        .map(([name, data]) => ({
                            name,
                            rating: data.total / data.count,
                            count: data.count
                        }))
                        .sort((a, b) => b.rating - a.rating)
                        .slice(0, 5)
                    setTopPlayers(sortedPlayers)
                }

            } catch (err) {
                console.error('Error fetching comunidad data:', err)
            } finally {
                setLoading(false)
            }
        }

        fetchComunidadData()
    }, [ligaExterna])

    if (loading) {
        return (
            <div className="space-y-4 animate-pulse">
                {[1, 2, 3].map(i => (
                    <div key={i} className="h-32 bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)]" />
                ))}
            </div>
        )
    }

    return (
        <div className="space-y-6">
            {/* Summary Stats - Flat Grid */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                <div className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)] text-center rounded-2xl">
                    <p className="text-[10px] text-[var(--text-muted)] capitalize font-bold tracking-tight mb-1">Comunidad</p>
                    <p className="text-sm font-bold capitalize">Activa</p>
                </div>
                <div className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)] text-center rounded-2xl">
                    <p className="text-[10px] text-[var(--text-muted)] capitalize font-bold tracking-tight mb-1">Promedio Gral</p>
                    <p className="text-sm font-bold capitalize">4.2 / 10</p>
                </div>
            </div>

            {/* Sections Selector - Flat Bar */}
            <div className="flex border border-[var(--card-border)] bg-[var(--card-bg)] overflow-hidden rounded-2xl">
                {(['teams', 'players', 'projections'] as const).map(section => (
                    <button
                        key={section}
                        onClick={() => { hapticFeedback(5); setActiveSection(section); }}
                        className={`flex-1 py-4 text-[10px] font-bold capitalize tracking-tight transition-colors
                            ${activeSection === section
                                ? 'bg-[var(--foreground)] text-[var(--background)]'
                                : 'text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'}`}
                    >
                        {section === 'teams' ? 'Equipos' : section === 'players' ? 'Jugadores' : 'Tendencias'}
                    </button>
                ))}
            </div>

            <div className="min-h-[300px]">
                {activeSection === 'teams' && (
                    <RankingList items={topTeams} title="TOP EQUIPOS" color="var(--foreground)" />
                )}

                {activeSection === 'players' && (
                    <>
                        {topPlayers.length > 0 ? (
                            <RankingList items={topPlayers} title="TOP JUGADORES" color="var(--foreground)" isPlayer />
                        ) : (
                            <EmptyState message="Sin votos suficientes." />
                        )}
                    </>
                )}

                {activeSection === 'projections' && (
                    <div className="py-12 text-center bg-[var(--card-bg)] border border-[var(--card-border)] border-dashed rounded-3xl">
                        <TrendingUp size={30} className="mx-auto mb-4 opacity-20" />
                        <h3 className="text-xs font-bold capitalize tracking-tight mb-2">Crowd Wisdom</h3>
                        <p className="text-[10px] text-[var(--text-muted)] max-w-xs mx-auto mb-4 font-medium capitalize tracking-tight">
                            Analizando tendencias globales de la comunidad...
                        </p>
                        <div className="inline-block px-3 py-1 bg-[var(--background)] border border-[var(--card-border)] rounded-full">
                            <span className="text-[8px] font-bold capitalize tracking-tight">Procesando Data</span>
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

function RankingList({ items, title, titleColor = 'var(--foreground)', isPlayer = false }: { items: RankedItem[], title: string, color?: string, isPlayer?: boolean, titleColor?: string }) {
    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden rounded-3xl">
            <div className="px-5 py-3 border-b border-[var(--card-border)] bg-[var(--background)] flex justify-between items-center">
                <h3 className="text-[10px] font-bold capitalize tracking-tight">
                    {title}
                </h3>
                <span className="text-[8px] text-[var(--text-muted)] capitalize font-bold tracking-tight">Líderes de Opinión</span>
            </div>

            <table className="w-full text-left border-collapse">
                <tbody className="divide-y divide-[var(--card-border)]">
                    {items.map((item, idx) => (
                        <tr key={item.name} className="hover:bg-[var(--background)] transition-colors">
                            <td className="px-5 py-4 text-xs font-bold text-[var(--text-muted)] w-8 text-center">{idx + 1}</td>
                            <td className="px-2 py-4">
                                <div className="flex items-center gap-3">
                                    {!isPlayer && item.logo && (
                                        <div className="w-8 h-8 flex items-center justify-center bg-[var(--background)] border border-[var(--card-border)] rounded-lg">
                                            <img src={item.logo} alt="" className="w-6 h-6 object-contain opacity-80" />
                                        </div>
                                    )}
                                    <div className="min-w-0">
                                        <p className="text-xs font-bold capitalize tracking-tight truncate">{item.name}</p>
                                        <p className="text-[8px] text-[var(--text-muted)] font-bold capitalize tracking-tight">{item.count} Reseñas</p>
                                    </div>
                                </div>
                            </td>
                            <td className="px-5 py-4 text-right">
                                <span className="inline-block px-3 py-1 bg-[var(--accent-green)] text-black text-[10px] font-bold rounded-full">
                                    {item.rating.toFixed(1)}
                                </span>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    )
}

function EmptyState({ message }: { message: string }) {
    return (
        <div className="py-12 text-center bg-[var(--card-bg)] border border-[var(--card-border)] border-dashed" style={{ borderRadius: 'var(--radius)' }}>
            <p className="text-[10px] text-[var(--text-muted)] font-black capitalize tracking-widest">{message}</p>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { X, Lock, Users, Shield, Link as LinkIcon, Share2 } from 'lucide-react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'
import { useRouter } from 'next/navigation'
import { QRCodeSVG } from 'qrcode.react'
import { Button } from './ui/Button'

interface CreateGroupModalProps {
    isOpen: boolean
    onClose: () => void
    onSuccess?: (groupId: string) => void
}

export function CreateGroupModal({ isOpen, onClose, onSuccess }: CreateGroupModalProps) {
    const { user } = useAuth()
    const { showToast } = useToast()
    const router = useRouter()

    const [name, setName] = useState('')
    const [description, setDescription] = useState('')
    const [isPrivate, setIsPrivate] = useState(false)
    const [isSubmitting, setIsSubmitting] = useState(false)
    const [createdGroup, setCreatedGroup] = useState<{ id: string, name: string } | null>(null)

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!user) return
        if (!name.trim()) {
            showToast('El nombre del grupo es obligatorio', 'error')
            return
        }

        setIsSubmitting(true)
        try {
            // First create the group
            const { data: groupData, error: groupError } = await supabase
                .from('grupos')
                .insert({
                    name: name.trim(),
                    description: description.trim(),
                    is_private: isPrivate,
                    created_by: user.id
                })
                .select('id, name')
                .single()

            if (groupError) throw groupError

            // Then automatically add creator as admin/member to grupo_members
            const { error: memberError } = await supabase
                .from('grupo_members')
                .insert({
                    grupo_id: groupData.id,
                    user_id: user.id,
                    role: 'admin'
                })

            if (memberError) throw memberError

            setCreatedGroup(groupData)
            showToast('Grupo creado correctamente', 'success')

            if (onSuccess) onSuccess(groupData.id)

        } catch (error) {
            console.error('Error creating group:', error)
            showToast('Hubo un error al crear el grupo', 'error')
        } finally {
            setIsSubmitting(false)
        }
    }

    const shareUrl = typeof window !== 'undefined' && createdGroup
        ? `${window.location.origin}/grupos/${createdGroup.id}/join`
        : ''

    const handleShare = async () => {
        if (!shareUrl) return
        if (navigator.share) {
            try {
                await navigator.share({
                    title: `Sumate a ${createdGroup?.name} en FutLog`,
                    text: `¡Preparate para el prode! Uníte a mi grupo privado en FutLog. 🏆⚽`,
                    url: shareUrl,
                })
            } catch (err) {
                console.error(err)
            }
        } else {
            navigator.clipboard.writeText(shareUrl)
            showToast('Link de invitación copiado', 'success')
        }
    }

    if (!isOpen) return null

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={onClose}
                className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4"
            >
                <motion.div
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 20, opacity: 0 }}
                    transition={{ duration: 0.25, ease: 'easeOut' }}
                    onClick={(e) => e.stopPropagation()}
                    className="bg-[var(--card-bg)] w-full max-w-sm p-6 border border-[var(--card-border)] relative overflow-hidden"
                    style={{ borderRadius: 'var(--radius)' }}
                >
                    <button
                        onClick={onClose}
                        className="absolute top-4 right-4 p-2 bg-[var(--background)] text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors z-10 border border-[var(--card-border)]"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <X size={18} />
                    </button>

                    {!createdGroup ? (
                        <>
                            <div className="w-12 h-12 bg-[#16a34a]/10 text-[#16a34a] border border-[#16a34a]/20 flex items-center justify-center mb-4" style={{ borderRadius: 'var(--radius)' }}>
                                <Users size={24} />
                            </div>

                            <h2 className="text-xl font-black capitalize italic tracking-tighter">Crear Grupo</h2>
                            <p className="text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-6">
                                Armá tu tribuna virtual para debatir.
                            </p>

                            <form onSubmit={handleCreate} className="space-y-4">
                                <div>
                                    <label className="text-[10px] font-black text-[var(--text-muted)] capitalize tracking-widest mb-1.5 block">
                                        Nombre del Grupo
                                    </label>
                                    <input
                                        type="text"
                                        value={name}
                                        onChange={(e) => setName(e.target.value)}
                                        placeholder="EJ: FÚTBOL DE LOS JUEVES"
                                        className="w-full bg-[var(--background)] border border-[var(--card-border)] px-4 py-3 text-sm font-black capitalize tracking-tighter focus:outline-none focus:border-[#16a34a] transition-colors"
                                        style={{ borderRadius: 'var(--radius)' }}
                                        maxLength={40}
                                        required
                                    />
                                </div>

                                <div>
                                    <label className="text-[10px] font-black text-[var(--text-muted)] capitalize tracking-widest mb-1.5 block">
                                        Descripción
                                    </label>
                                    <textarea
                                        value={description}
                                        onChange={(e) => setDescription(e.target.value)}
                                        placeholder="¿DE QUÉ SE TRATA?"
                                        className="w-full bg-[var(--background)] border border-[var(--card-border)] px-4 py-3 text-sm font-black focus:outline-none focus:border-[#16a34a] transition-colors resize-none h-20"
                                        style={{ borderRadius: 'var(--radius)' }}
                                        maxLength={160}
                                    />
                                </div>

                                {/* Private Toggle */}
                                <div
                                    className={`p-4 border flex gap-3 cursor-pointer transition-colors ${isPrivate ? 'bg-[#16a34a]/5 border-[#16a34a]/30' : 'bg-[var(--background)] border-[var(--card-border)]'}`}
                                    onClick={() => setIsPrivate(!isPrivate)}
                                    style={{ borderRadius: 'var(--radius)' }}
                                >
                                    <div className={`mt-0.5 ${isPrivate ? 'text-[#16a34a]' : 'text-[var(--text-muted)]'}`}>
                                        {isPrivate ? <Lock size={20} /> : <Shield size={20} />}
                                    </div>
                                    <div className="flex-1">
                                        <div className="flex items-center justify-between mb-0.5">
                                            <span className={`text-[10px] font-black capitalize tracking-widest ${isPrivate ? 'text-[#16a34a]' : ''}`}>
                                                Grupo Privado
                                            </span>
                                            <div className={`w-10 h-6 border p-1 transition-colors ${isPrivate ? 'bg-[#16a34a] border-[#16a34a]' : 'bg-[var(--background)] border-[var(--card-border)]'}`} style={{ borderRadius: 'var(--radius)' }}>
                                                <div className={`w-4 h-4 bg-white transition-transform ${isPrivate ? 'translate-x-4' : 'translate-x-0'}`} style={{ borderRadius: '2px' }} />
                                            </div>
                                        </div>
                                        <p className="text-[9px] font-black capitalize tracking-widest text-[var(--text-muted)] leading-tight italic">
                                            {isPrivate
                                                ? 'Sólo con invitación.'
                                                : 'Público. Cualquiera puede sumarse.'}
                                        </p>
                                    </div>
                                </div>

                                <Button
                                    type="submit"
                                    loading={isSubmitting}
                                    disabled={!name.trim()}
                                    fullWidth
                                    className="mt-2"
                                >
                                    Crear grupo
                                </Button>
                            </form>
                        </>
                    ) : (
                        // SUCCESS STATE - INVITE QR
                        <div className="flex flex-col items-center text-center">
                            <div className="w-16 h-16 bg-[#16a34a]/10 text-[#16a34a] border border-[#16a34a]/20 flex items-center justify-center mb-4 text-3xl" style={{ borderRadius: 'var(--radius)' }}>
                                🎉
                            </div>
                            <h2 className="text-xl font-black capitalize italic tracking-tighter">Grupo creado</h2>
                            <p className="text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-6">
                                Invitá a tus amigos a "{createdGroup.name}".
                            </p>

                            <div className="bg-white p-3 border border-[var(--card-border)] mb-6 transition-transform hover:scale-105" style={{ borderRadius: 'var(--radius)' }}>
                                <QRCodeSVG
                                    value={shareUrl}
                                    size={160}
                                    level="H"
                                    includeMargin={false}
                                    fgColor="#000000"
                                    bgColor="#ffffff"
                                />
                            </div>

                            <div className="w-full grid grid-cols-2 gap-2">
                                <Button
                                    onClick={handleShare}
                                    icon={Share2}
                                    fullWidth
                                >
                                    Compartir
                                </Button>
                                <Button
                                    onClick={() => {
                                        onClose()
                                        router.push(`/grupos/${createdGroup.id}`)
                                    }}
                                    variant="secondary"
                                    fullWidth
                                >
                                    Ir al grupo
                                </Button>
                            </div>
                        </div>
                    )}
                </motion.div>
            </motion.div>
        </AnimatePresence>
    )
}

