            { position: 2, name: 'M. Salah', team: 'Liverpool', teamLogo: 'https://www.thesportsdb.com/images/media/team/badge/uvxuqq1448813372.png', goals: 15, assists: 10, matches: 20, nationality: '🇪🇬' },
