        icon: <Sparkles size={56} className="text-[#3b82f6] drop-shadow-md" />,
        title: '¡Ya estás listo!',
        description: 'Empezá a usar FutLog para desbloquear tu medalla de Beta Explorer.',
        bgOffset: 'bg-gradient-to-br from-[var(--card-bg)] to-[#3b82f6]/5'
    }
]

export function OnboardingCarousel() {
    const router = useRouter()
    const { user } = useAuth()
    const [currentSlide, setCurrentSlide] = useState(0)
    const [hasSeenOnboarding, setHasSeenOnboarding] = useState(true) // Default to true to prevent flash

    useEffect(() => {
        const seen = localStorage.getItem('FutLog-Onboarding-Seen')
        if (!seen) {
            setHasSeenOnboarding(false)
        }
    }, [])

    const handleNext = () => {
        if (currentSlide < SLIDES.length - 1) {
            setCurrentSlide(prev => prev + 1)
        } else {
            finishOnboarding()
        }
    }

    const finishOnboarding = async () => {
        localStorage.setItem('FutLog-Onboarding-Seen', 'true')
        setHasSeenOnboarding(true)

        if (user) {
            try {
                await checkAndAwardBadges(user.id)
            } catch (e) {
                console.error("Error awarding beta badge:", e)
            }
        }
    }

    if (hasSeenOnboarding) return null

    const slide = SLIDES[currentSlide]

    return (
        <div className={`mb-6 relative overflow-hidden rounded-[var(--radius)] border border-[var(--card-border)] p-6 shadow-sm min-h-[220px] flex flex-col justify-between ${slide.bgOffset} transition-colors duration-500`}>

            {/* Skip Button - Hidden on last slide */}
            {currentSlide < SLIDES.length - 1 && (
                <button
                    onClick={finishOnboarding}
                    className="absolute top-4 right-4 text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors p-1 z-20"
                    title="Saltar"
                >
                    <span className="text-xs font-semibold mr-1">Saltar</span>
                    <X size={14} className="inline" />
                </button>
            )}

            {/* Main Content Area */}
            <AnimatePresence mode="wait">
                <motion.div
                    key={currentSlide}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.3, ease: 'easeOut' }}
                    className="flex-1 flex flex-col items-center justify-center text-center mt-2"
                    drag="x"
                    dragConstraints={{ left: 0, right: 0 }}
                    dragElastic={0.2}
                    onDragEnd={(e, { offset, velocity }) => {
                        const swipe = offset.x
                        // Swipe right (prev slide)
                        if (swipe > 50 && currentSlide > 0) {
                            setCurrentSlide(prev => prev - 1)
                        }
                        // Swipe left (next slide)
                        else if (swipe < -50 && currentSlide < SLIDES.length - 1) {
                            setCurrentSlide(prev => prev + 1)
                        }
                    }}
                >
                    <div className="mb-4">
                        {slide.icon}
                    </div>
                    <h2 className="text-xl font-black mb-2 tracking-tight">{slide.title}</h2>
                    <p className="text-sm text-[var(--text-muted)] max-w-[280px] leading-relaxed mx-auto">
                        {slide.description}
                    </p>
                </motion.div>
            </AnimatePresence>

            {/* Bottom Controls */}
            <div className="flex items-center justify-between mt-6">

                {/* Progress Dots */}
                <div className="flex gap-1.5">
                    {SLIDES.map((_, idx) => (
                        <div
                            key={idx}
                            className={`h-1.5 rounded-[var(--radius)] transition-all duration-300 ${currentSlide === idx ? 'w-4 bg-[var(--foreground)]' : 'w-1.5 bg-[var(--card-border)]'}`}
                        />
                    ))}
                </div>

                {/* CTA Button */}
                <button
                    onClick={handleNext}
                    className={`flex items-center gap-1.5 px-5 py-2 rounded-xl text-xs font-bold transition-all shadow-md active:scale-95
                    ${currentSlide === SLIDES.length - 1
                            ? 'bg-[var(--accent-green)] text-white shadow-[var(--accent-green)]/20 hover:bg-[#009040]'
                            : 'bg-[var(--foreground)] text-[var(--background)] hover:opacity-90'}`}
                >
                    {currentSlide === SLIDES.length - 1 ? (
                        <>
                            ¡Entrá Ya! <Sparkles size={14} />
                        </>
                    ) : (
                        <>
                            Siguiente <ChevronRight size={14} />
                        </>
                    )}
                </button>
            </div>

        </div>
    )
}

// src/components/OnboardingModal.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { useRouter } from 'next/navigation'
import { ChevronRight, Film, Star, Users, Trophy, QrCode, UserPlus, Layout, Sparkles } from 'lucide-react'
import { Button } from './ui/Button'
import { checkAndAwardBadges } from '@/app/actions/badges'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'

const ONBOARDING_KEY = 'FutLog_onboarding_done'

const slides = [
    {
        emoji: '🏟️',
        title: '¡Bienvenido a FutLog!',
        description: 'Tu Letterboxd del fútbol. Rateá partidos enteros, armá tu prode y competí con la comunidad.',
        color: 'var(--accent)',
        icon: Star,
        visual: null
    },
    {
        emoji: '⭐',
        title: 'Rateá tu primer partido',
        description: 'Puntuá el juego, elegí figura, villano y criticá al árbitro. Que quede guardado para la historia.',
        color: 'var(--accent-yellow)',
        icon: Film,
        visual: (
            <div className="flex justify-center gap-1 my-4 bg-[var(--background)] py-2 px-4 rounded-full border border-[var(--card-border)] w-fit mx-auto">
                {[1, 2, 3, 4, 5].map(i => <Star key={i} size={24} fill="currentColor" className="text-[var(--accent-yellow)]" />)}
            </div>
        )
    },
    {
        emoji: '🎯',
        title: 'Prode y Competencia',
        description: 'Pronosticá resultados exactos, sumá puntos fecha a fecha y demostrá quién sabe de verdad.',
        color: 'var(--accent-green)',
        icon: Trophy,
        visual: null
    },
    {
        emoji: '🚀',
        title: '¡Ya estás listo!',
        description: 'Completá tu perfil para desbloquear tu medalla de "Beta Explorer" y empezar a sumar XP.',
        color: 'var(--accent-blue)',
        icon: Sparkles,
        visual: null
    },
]

export function OnboardingModal() {
    const { user } = useAuth()
    const { showToast } = useToast()
    const [isOpen, setIsOpen] = useState(false)
    const [currentSlide, setCurrentSlide] = useState(0)
    const router = useRouter()

    useEffect(() => {
        // Only show once
        const done = localStorage.getItem(ONBOARDING_KEY)
        if (!done) {
            // Small delay so the app loads first
            const timer = setTimeout(() => setIsOpen(true), 800)
            return () => clearTimeout(timer)
        }
    }, [])

    const handleNext = async () => {
        if (currentSlide < slides.length - 1) {
            setCurrentSlide(currentSlide + 1)
        } else {
            if (user) {
                try {
                    await checkAndAwardBadges(user.id)
                } catch (e) {
                    console.error("Error awarding beta badge:", e)
                }
            }
            handleClose()
        }
    }

    const handleClose = () => {
        localStorage.setItem(ONBOARDING_KEY, 'true')
        setIsOpen(false)
    }

    if (!isOpen) return null

    const slide = slides[currentSlide]

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-6"
            >
                <motion.div
                    key={currentSlide}
                    initial={{ scale: 0.9, opacity: 0, y: 20 }}
                    animate={{ scale: 1, opacity: 1, y: 0 }}
                    exit={{ scale: 0.9, opacity: 0, y: -20 }}
                    transition={{ type: 'spring', damping: 20 }}
                    className="bg-[var(--card-bg)] rounded-3xl p-8 w-full max-w-sm border border-[var(--card-border)] shadow-2xl text-center"
                >
                    {/* Skip button - Hidden on last slide */}
                    <div className="flex justify-end mb-2 h-4">
                        {currentSlide < slides.length - 1 && (
                            <button
                                onClick={handleClose}
                                className="text-xs text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                            >
                                Saltar
                            </button>
                        )}
                    </div>

                    {/* Icon/Emoji */}
                    <motion.div
                        key={`icon-${currentSlide}`}
                        initial={{ scale: 0.5, rotate: -10 }}
                        animate={{ scale: 1, rotate: 0 }}
                        transition={{ type: 'spring', damping: 10, delay: 0.1 }}
                        className="text-6xl mb-6"
                    >
                        {slide.emoji}
                    </motion.div>

                    {/* Title */}
                    <h2 className="text-xl font-black mb-3 text-[var(--foreground)]">{slide.title}</h2>

                    {/* Description */}
                    <p className="text-sm text-[var(--text-muted)] leading-relaxed mb-4 max-w-xs mx-auto">
                        {slide.description}
                    </p>

                    {/* Visual Extra & CTAs on last slide */}
                    {currentSlide === slides.length - 1 ? (
                        <div className="space-y-2 mb-6 text-left">
                            <Button
                                variant="glass"
                                size="sm"
                                fullWidth
                                onClick={() => { handleClose(); router.push('/perfil'); }}
                                icon={QrCode}
                                className="justify-start px-4 py-3"
                            >
                                Generar mi QR
                            </Button>
                            <Button
                                variant="glass"
                                size="sm"
                                fullWidth
                                onClick={() => { handleClose(); router.push('/grupos'); }}
                                icon={UserPlus}
                                className="justify-start px-4 py-3"
                            >
                                Crear mi primer grupo
                            </Button>
                            <Button
                                variant="glass"
                                size="sm"
                                fullWidth
                                onClick={() => { handleClose(); router.push('/build-xi'); }}
                                icon={Layout}
                                className="justify-start px-4 py-3"
                            >
                                Armar mi XI
                            </Button>
                        </div>
                    ) : (
                        slide.visual && (
                            <motion.div
                                initial={{ scale: 0.8, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                transition={{ delay: 0.2 }}
                                className="mb-4"
                            >
                                {slide.visual}
                            </motion.div>
                        )
                    )}

                    {/* Dots indicator */}
                    <div className="flex justify-center gap-2 mb-6">
                        {slides.map((_, i) => (
                            <div
                                key={i}
                                className={`h-1.5 rounded-full transition-all duration-300 ${i === currentSlide
                                    ? 'w-6 bg-[var(--accent)]'
                                    : 'w-1.5 bg-[var(--card-border)]'
                                    }`}
                            />
                        ))}
                    </div>

                    {/* Main CTA */}
                    <Button
                        onClick={handleNext}
                        variant={currentSlide === slides.length - 1 ? "primary" : "secondary"}
                        fullWidth
                        size="lg"
                        icon={ChevronRight}
                    >
                        {currentSlide === slides.length - 1 ? '¡Empezar ahora!' : 'Siguiente'}
                    </Button>
                </motion.div>
            </motion.div>
        </AnimatePresence>
    )
}

// src/components/PartidoCard.tsx
'use client'

import { useRouter } from 'next/navigation'
import { memo, useState, useEffect, useRef } from 'react'
import { motion } from 'framer-motion'
import { FavoriteButton } from './FavoriteButton'
import { TeamLogo } from './TeamLogo'
import { useTheme } from '@/contexts/ThemeContext'
import type { Partido } from '@/types'
import { formatearFecha, formatearHora } from '@/lib/utils'

interface PartidoCardProps {
  partido: Partido
}

export const PartidoCard = memo(({ partido }: PartidoCardProps) => {
    const router = useRouter()
  // Utilidad para extraer color "glow" semialeatorio según el nombre
  const getGlowColor = (teamName: string) => {
    let hash = 0
    for (let i = 0; i < teamName.length; i++) hash = teamName.charCodeAt(i) + ((hash << 5) - hash)
    return `hsl(${Math.abs(hash % 360)}, 70%, 50%)`
  }
  const prevGolesLocal = useRef(partido.goles_local)
  const prevGolesVisitante = useRef(partido.goles_visitante)

  const [flashLocal, setFlashLocal] = useState(false)
  const [flashVisitante, setFlashVisitante] = useState(false)

  useEffect(() => {
    if (partido.goles_local !== undefined && partido.goles_local !== prevGolesLocal.current) {
      if (prevGolesLocal.current !== undefined) {
        setFlashLocal(true)
        setTimeout(() => setFlashLocal(false), 3000)
      }
      prevGolesLocal.current = partido.goles_local
    }
    if (partido.goles_visitante !== undefined && partido.goles_visitante !== prevGolesVisitante.current) {
      if (prevGolesVisitante.current !== undefined) {
        setFlashVisitante(true)
        setTimeout(() => setFlashVisitante(false), 3000)
      }
      prevGolesVisitante.current = partido.goles_visitante
    }
  }, [partido.goles_local, partido.goles_visitante])

  const handleClick = () => {
    router.push(`/partido/${partido.id}`)
  }

  const isLive = partido.estado === 'EN_JUEGO'
  const isFinished = partido.estado === 'FINALIZADO'
  const showScore = isLive || isFinished

  return (
    <div
      onClick={handleClick}
      className={`bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden
                 transition-all duration-200 cursor-pointer active:scale-[0.99]
                 ${isLive ? 'border-[var(--accent)] ring-1 ring-[var(--accent)]/20' : ''}
      `}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => e.key === 'Enter' && handleClick()}
    >
      {/* Header — liga + estado + fecha */}
      <div className="px-3 py-1.5 flex items-center justify-between bg-[var(--background)]/50">
        <span className="text-[9px] font-bold text-[var(--text-muted)] capitalize tracking-wider">
          {partido.liga}
        </span>
        <div className="flex items-center gap-2 text-[10px] text-[var(--text-muted)]">
          {isLive && (
            <span className="flex items-center gap-1 text-[var(--accent)] font-black">
              <span className="w-1.5 h-1.5 bg-[var(--accent)] rounded-full animate-pulse" />
              VIVO
            </span>
          )}
          {isFinished && (
            <span className="text-[var(--text-muted)] font-medium">FIN</span>
          )}
          <span>{formatearFecha(partido.fecha_inicio)}</span>
          <span className="font-semibold">{formatearHora(partido.fecha_inicio)}</span>
        </div>
      </div>

      {/* Equipos — layout Inmersivo Centrado (Escudos Gigantes) */}
      <div className="px-4 py-6 relative">
        <div className="flex items-center justify-between relative z-10 w-full">
          {/* Local */}
          <div className="flex flex-col items-center flex-1 gap-2 cursor-pointer group">
            <TeamLogo src={partido.logo_local} teamName={partido.equipo_local} size={40} className="relative z-10" />
            <span className={`text-[12px] md:text-sm font-bold text-center leading-tight line-clamp-2 px-1 ${flashLocal ? 'text-[#ff6b6b]' : ''}`}>
              {partido.equipo_local}
            </span>
          </div>

          {/* VS / Score Divider */}
          <div className="flex flex-col items-center justify-center px-2 shrink-0 w-[80px]">
            {showScore ? (
              <div className="flex items-center gap-2 font-black text-3xl md:text-3xl tracking-tighter">
                <motion.span animate={flashLocal ? { scale: [1, 1.1, 1], color: ['var(--foreground)', 'var(--foreground)', 'var(--foreground)'] } : {}} transition={{ duration: 0.6 }}>
                  {partido.goles_local ?? '-'}
                </motion.span>
                <span className="text-[var(--text-muted)] opacity-30 text-xl mx-1">:</span>
                <motion.span animate={flashVisitante ? { scale: [1, 1.1, 1], color: ['var(--foreground)', 'var(--foreground)', 'var(--foreground)'] } : {}} transition={{ duration: 0.6 }}>
                  {partido.goles_visitante ?? '-'}
                </motion.span>
              </div>
            ) : (
              <div className="border border-[var(--card-border)] bg-[var(--background)] px-2 py-1">
                <span className="text-[9px] font-black text-[var(--text-muted)] italic">VS</span>
              </div>
            )}

            {/* Quick Favorite actions centered below score */}
            <div className="flex justify-center gap-4 mt-2" onClick={(e) => e.stopPropagation()}>
              <FavoriteButton equipo={partido.equipo_local} compact />
              <FavoriteButton equipo={partido.equipo_visitante} compact />
            </div>
          </div>

          {/* Visitante */}
          <div className="flex flex-col items-center flex-1 gap-2 cursor-pointer group">
            <TeamLogo src={partido.logo_visitante} teamName={partido.equipo_visitante} size={40} className="relative z-10" />
            <span className={`text-[12px] md:text-sm font-bold text-center leading-tight line-clamp-2 px-1 ${flashVisitante ? 'text-[#ff6b6b]' : ''}`}>
              {partido.equipo_visitante}
            </span>
          </div>
        </div>
      </div>

    </div>
  )
})

PartidoCard.displayName = 'PartidoCard'

// src/components/ProdeCard.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import Image from 'next/image'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'
import confetti from 'canvas-confetti'
import type { Partido, Pronostico } from '@/types'
import { formatearHora, formatearFecha } from '@/lib/utils'

interface ProdeCardProps {
    partido: Partido
    pronosticoExistente?: Pronostico | null
    onGuardar: (golesLocal: number, golesVisitante: number) => Promise<void>
}

function GoalStepper({
    value,
    onChange,
    disabled,
    teamName,
}: {
    value: number
    onChange: (v: number) => void
    disabled: boolean
    teamName: string
}) {
    return (
        <div className="flex items-center gap-1">
            <motion.button
                type="button"
                whileTap={{ scale: 0.85 }}
                disabled={disabled || value <= 0}
                onClick={() => onChange(Math.max(0, value - 1))}
                aria-label={`Restar gol ${teamName}`}
                className={`w-9 h-9 flex items-center justify-center text-lg font-black transition-all border
                    ${disabled
                        ? 'bg-[var(--card-bg)] border-[var(--card-border)] text-[var(--text-muted)] cursor-not-allowed opacity-40'
                        : 'bg-[var(--background)] border-[var(--card-border)] text-[var(--text-muted)] hover:bg-red-600/10 hover:text-red-600 hover:border-red-600 active:bg-red-600/20'
                    }`}
                style={{ borderRadius: 'var(--radius)' }}
            >
                −
            </motion.button>

            <div className={`w-12 h-12 flex items-center justify-center text-xl font-black tabular-nums transition-all border
                ${disabled
                    ? 'bg-[var(--card-bg)] border-[var(--card-border)] text-[var(--text-muted)]'
                    : 'bg-[var(--background)] border-[var(--foreground)] text-[var(--foreground)]'
                }`}
                style={{ borderRadius: 'var(--radius)' }}
            >
                {value}
            </div>

            <motion.button
                type="button"
                whileTap={{ scale: 0.85 }}
                disabled={disabled || value >= 20}
                onClick={() => onChange(Math.min(20, value + 1))}
                aria-label={`Sumar gol ${teamName}`}
                className={`w-9 h-9 flex items-center justify-center text-lg font-black transition-all border
                    ${disabled
                        ? 'bg-[var(--card-bg)] border-[var(--card-border)] text-[var(--text-muted)] cursor-not-allowed opacity-40'
                        : 'bg-[var(--background)] border-[var(--card-border)] text-[var(--text-muted)] hover:bg-[#16a34a]/10 hover:text-[#16a34a] hover:border-[#16a34a] active:bg-[#16a34a]/20'
                    }`}
                style={{ borderRadius: 'var(--radius)' }}
            >
                +
            </motion.button>
        </div>
    )
}

export function ProdeCard({ partido, pronosticoExistente, onGuardar }: ProdeCardProps) {
    const { user } = useAuth()
    const { showToast } = useToast()
    const [golesLocal, setGolesLocal] = useState(pronosticoExistente?.goles_local_pronostico ?? 0)
    const [golesVisitante, setGolesVisitante] = useState(pronosticoExistente?.goles_visitante_pronostico ?? 0)
    const [guardando, setGuardando] = useState(false)
    const [guardado, setGuardado] = useState(!!pronosticoExistente)
    const [hasLineup, setHasLineup] = useState(false)

    useEffect(() => {
        const checkLineup = async () => {
            if (!user) return
            const { data } = await supabase
                .from('user_lineups')
                .select('id')
                .eq('user_id', user.id)
                .maybeSingle()
            if (data) setHasLineup(true)
        }
        checkLineup()
    }, [user])

    const isPartidoBloqueado = partido.estado !== 'PREVIA' || pronosticoExistente?.bloqueado

    const handleGuardar = async () => {
        setGuardando(true)

        try {
            await onGuardar(golesLocal, golesVisitante)
            setGuardado(true)
            showToast('¡Pronóstico guardado!', 'success')

            // Subtle feedback
            if (typeof window !== 'undefined' && 'vibrate' in navigator) {
                navigator.vibrate(50)
            }
        } catch (error) {
            console.error('Error guardando pronóstico:', error)
            showToast('Error al guardar pronóstico', 'error')
        } finally {
            setGuardando(false)
        }
    }

    const handleUsarXI = () => {
        // Some rudimentary fun logic to simulate a score
        const posiblesResultados = [
            [2, 1], [1, 2], [1, 1], [0, 0], [3, 1], [1, 0], [0, 1]
        ]
        const idx = Math.floor(Math.random() * posiblesResultados.length)
        setGolesLocal(posiblesResultados[idx][0])
        setGolesVisitante(posiblesResultados[idx][1])
        setGuardado(false)
    }

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden
                 hover:border-[var(--foreground)] transition-all"
            style={{ borderRadius: 'var(--radius)' }}
        >
            {/* Header */}
            <div className="px-5 py-3 bg-[var(--background)] flex items-center justify-between border-b border-[var(--card-border)]">
                <div className="flex items-center gap-2">
                    <span className="text-[10px] font-bold text-[var(--accent-green)] capitalize tracking-tight">
                        {partido.liga}
                    </span>
                </div>
                <div className="flex items-center gap-3 text-[10px] text-[var(--text-muted)] font-medium capitalize tracking-tight">
                    <span>{formatearFecha(partido.fecha_inicio)}</span>
                    <span className="font-bold">{formatearHora(partido.fecha_inicio)}</span>
                </div>
            </div>

            {/* Equipos y pronóstico */}
            <div className="p-5">
                {/* Equipo Local */}
                <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-3 flex-1 min-w-0">
                        {partido.logo_local && (
                            <div className="relative w-8 h-8 shrink-0">
                                <Image
                                    src={partido.logo_local}
                                    alt={partido.equipo_local}
                                    fill
                                    className="object-contain"
                                    sizes="32px"
                                />
                            </div>
                        )}
                        <span className="text-sm font-medium truncate">{partido.equipo_local}</span>
                    </div>

                    <GoalStepper
                        value={golesLocal}
                        onChange={(v) => !isPartidoBloqueado && setGolesLocal(v)}
                        disabled={!!isPartidoBloqueado}
                        teamName={partido.equipo_local}
                    />
                </div>

                {/* VS Divider */}
                <div className="flex items-center justify-center my-2">
                    <div className="h-px bg-[var(--card-border)] flex-1"></div>
                    <span className="px-3 text-xs text-[var(--text-muted)] font-semibold">VS</span>
                    <div className="h-px bg-[var(--card-border)] flex-1"></div>
                </div>

                {/* Equipo Visitante */}
                <div className="flex items-center justify-between mt-3">
                    <div className="flex items-center gap-3 flex-1 min-w-0">
                        {partido.logo_visitante && (
                            <div className="relative w-8 h-8 shrink-0">
                                <Image
                                    src={partido.logo_visitante}
                                    alt={partido.equipo_visitante}
                                    fill
                                    className="object-contain"
                                    sizes="32px"
                                />
                            </div>
                        )}
                        <span className="text-sm font-medium truncate">{partido.equipo_visitante}</span>
                    </div>

                    <GoalStepper
                        value={golesVisitante}
                        onChange={(v) => !isPartidoBloqueado && setGolesVisitante(v)}
                        disabled={!!isPartidoBloqueado}
                        teamName={partido.equipo_visitante}
                    />
                </div>
            </div>

            {/* Use My XI Button */}
            {!isPartidoBloqueado && hasLineup && !guardado && (
                <div className="px-5 pb-2">
                    <button
                        onClick={handleUsarXI}
                        className="w-full py-2 text-[10px] font-black capitalize tracking-widest bg-[var(--background)] border border-blue-600/30 text-blue-600 hover:bg-blue-600/10 transition-all flex items-center justify-center gap-2"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <span>⚡</span> Usar mi XI Ideal
                    </button>
                </div>
            )}

            {/* Footer con botón */}
            <div className="px-5 py-4 bg-[var(--background)]/50 border-t border-[var(--card-border)]">
                {isPartidoBloqueado ? (
                    <div className="text-center">
                        <span className="text-xs text-[var(--text-muted)] font-medium">
                            {pronosticoExistente?.bloqueado ? '🔒 Pronóstico bloqueado' : '⚽ Partido en curso'}
                        </span>
                    </div>
                ) : (
                    <motion.button
                        onClick={handleGuardar}
                        disabled={guardando}
                        whileTap={{ scale: 0.98 }}
                        className={`w-full py-3 font-bold capitalize tracking-tight text-xs transition-all border-2
                       ${guardado
                                ? 'bg-[var(--accent-green)] text-white border-[var(--accent-green)] hover:opacity-90'
                                : 'bg-transparent text-[var(--accent-green)] border-[var(--accent-green)] hover:bg-[var(--accent-green)] hover:text-white'
                            }`}
                        style={{ borderRadius: 'var(--radius-md)' }}
                    >
                        {guardando ? 'Guardando...' : guardado ? '✓ Guardado' : 'Guardar Pronóstico'}
                    </motion.button>
                )}

                {/* Puntos posibles */}
                {!isPartidoBloqueado && (
                    <div className="mt-3 text-center text-[10px] text-[var(--text-muted)] font-medium">
                        <span>Exacto: 8 pts</span>
                        <span className="mx-2 opacity-30">•</span>
                        <span>Ganador + Dif: 5 pts</span>
                        <span className="mx-2 opacity-30">•</span>
                        <span>Ganador: 3 pts</span>
                    </div>
                )}
            </div>
        </motion.div>
    )
}

// src/components/ProdeStats.tsx
'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { motion } from 'framer-motion'

interface Stats {
    puntos_totales: number
    partidos_jugados: number
    aciertos_exactos: number
    aciertos_ganador_diferencia: number
    aciertos_ganador: number
    posicion: number
}

export function ProdeStats() {
    const { user } = useAuth()
    const [stats, setStats] = useState<Stats | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        if (user) fetchStats()
    }, [user])

    const fetchStats = async () => {
        try {
            // Obtener stats del usuario
            const { data: rankingData, error } = await supabase
                .from('ranking_prode')
                .select('*')
                .eq('user_id', user?.id)
                .single()

            if (error && error.code !== 'PGRST116') throw error // PGRST116 = no rows

            // Obtener posición
            let posicion = 0
            if (rankingData) {
                const { count } = await supabase
                    .from('ranking_prode')
                    .select('*', { count: 'exact', head: true })
                    .gt('puntos_totales', rankingData.puntos_totales)

                posicion = (count || 0) + 1
            }

            setStats(rankingData ? { ...rankingData, posicion } : null)
        } catch (err: any) {
            console.error('Error fetching stats:', err)
        } finally {
            setLoading(false)
        }
    }

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-6 animate-pulse" style={{ borderRadius: 'var(--radius)' }}>
                <div className="h-4 bg-[var(--background)] w-1/2 mb-4" style={{ borderRadius: 'var(--radius)' }}></div>
                <div className="h-8 bg-[var(--background)] w-1/3" style={{ borderRadius: 'var(--radius)' }}></div>
            </div>
        )
    }

    if (!stats) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-8 rounded-3xl shadow-sm text-center">
                <span className="text-5xl mb-4 block">🎯</span>
                <h3 className="text-xl font-bold mb-2 tracking-tight">¡EMPEZÁ A PRONOSTICAR!</h3>
                <p className="text-sm text-[var(--text-muted)] font-medium max-w-[200px] mx-auto">
                    Predecí los resultados y sumá puntos en el ranking global.
                </p>
            </div>
        )
    }

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-[var(--card-bg)] border border-[var(--card-border)] p-6 rounded-3xl shadow-sm"
        >
            <div className="flex items-center justify-between mb-6">
                <h3 className="text-xs font-bold text-[var(--text-muted)] capitalize tracking-tight flex items-center gap-2">
                    📊 Estadísticas
                </h3>
                {stats.posicion > 0 && (
                    <div className="flex items-center gap-1.5 bg-[var(--accent-green)]/10 text-[var(--accent-green)] px-3 py-1 rounded-full border border-[var(--accent-green)]/20 shadow-sm">
                        <span className="text-[10px] capitalize font-bold tracking-tight">Pos #{stats.posicion}</span>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div className="text-center">
                    <div className="text-4xl font-bold text-[var(--foreground)] tabular-nums tracking-tighter">{stats.puntos_totales}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Puntos</div>
                </div>
                <div className="text-center">
                    <div className="text-4xl font-bold tracking-tighter">{stats.partidos_jugados}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Partidos</div>
                </div>
            </div>

            <div className="mt-6 pt-6 border-t border-[var(--card-border)] grid grid-cols-3 gap-2 text-center">
                <div>
                    <div className="text-xl font-bold text-[var(--accent-green)]">{stats.aciertos_exactos}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Exactos</div>
                </div>
                <div>
                    <div className="text-xl font-bold text-blue-500">{stats.aciertos_ganador_diferencia}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Gan+Dif</div>
                </div>
                <div>
                    <div className="text-xl font-bold text-[var(--foreground)]">{stats.aciertos_ganador}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Ganador</div>
                </div>
            </div>
        </motion.div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/lib/supabase'
import { GlassCard } from './ui/GlassCard'

export function ProgresoHoyWidget() {
    const { user } = useAuth()
    const router = useRouter()
    const [stats, setStats] = useState({
        prodes: 0,
        badges: 0,
        rango: 0
    })

    useEffect(() => {
        if (!user) return

        const getStats = async () => {
            try {
                // Today's prodes
                const startOfDay = new Date()
                startOfDay.setHours(0, 0, 0, 0)

                const { count: prodesCount } = await supabase
                    .from('pronosticos')
                    .select('*', { count: 'exact', head: true })
                    .eq('user_id', user.id)
                    .gte('created_at', startOfDay.toISOString())

                // Ranking Position
                const { data: rankData } = await supabase
                    .from('ranking_prode')
                    .select('puntos_totales')
                    .eq('user_id', user.id)
                    .single()

                let posicion = 0
                if (rankData) {
                    const { count: higherRanked } = await supabase
                        .from('ranking_prode')
                        .select('*', { count: 'exact', head: true })
                        .gt('puntos_totales', rankData.puntos_totales)

                    posicion = (higherRanked || 0) + 1
                }

                // New Badges Today (Optional depending on how user_badges stores them)
                const { count: badgesCount } = await supabase
                    .from('user_badges')
                    .select('*', { count: 'exact', head: true })
                    .eq('user_id', user.id)
                    .gte('earned_at', startOfDay.toISOString())

                setStats({
                    prodes: prodesCount || 0,
                    badges: badgesCount || 0,
                    rango: posicion
                })

            } catch (err) {
                console.error(err)
            }
        }

        getStats()
    }, [user])

    if (!user) return null

    return (
        <div
            className="flex items-center justify-between cursor-pointer border border-[var(--card-border)] bg-[var(--card-bg)] p-4 transition-all"
            style={{ borderRadius: 'var(--radius)' }}
            onClick={() => router.push('/perfil')}
        >
            <div className="flex flex-col">
                <span className="text-[10px] capitalize font-black text-[var(--text-muted)] tracking-widest">Tu Progreso Hoy</span>
                <div className="flex gap-4 mt-1.5">
                    <div className="flex items-center gap-1.5">
                        <span className="text-[#16a34a] text-sm">🎯</span>
                        <span className="font-black text-sm tracking-tighter tabular-nums">{stats.prodes} <span className="text-[10px] capitalize font-bold text-[var(--text-muted)]">Prodes</span></span>
                    </div>
                    {stats.badges > 0 && (
                        <div className="flex items-center gap-1.5">
                            <span className="text-[#d97706] text-sm">🎖️</span>
                            <span className="font-black text-sm tracking-tighter tabular-nums">{stats.badges} <span className="text-[10px] capitalize font-bold text-[var(--text-muted)]">Nuevos</span></span>
                        </div>
                    )}
                    <div className="flex items-center gap-1.5">
                        <span className="text-[#2563eb] text-sm">🏆</span>
                        <span className="font-black text-sm tracking-tighter tabular-nums">#{stats.rango} <span className="text-[10px] capitalize font-bold text-[var(--text-muted)]">Global</span></span>
                    </div>
                </div>
            </div>

            <div className="w-8 h-8 bg-[var(--foreground)]/5 flex items-center justify-center text-[var(--foreground)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 18 15 12 9 6"></polyline></svg>
            </div>
        </div>
    )
}

