'use client'

import { useState } from 'react'
import { useAuth } from '@/contexts/AuthContext'
import { motion } from 'framer-motion'
import { Bell, Send, CheckCircle2, AlertCircle } from 'lucide-react'

export function PushDebug() {
    const { user } = useAuth()
    const [loading, setLoading] = useState(false)
    const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle')
    const [error, setError] = useState('')

    const sendTestNotification = async (type: 'test' | 'profile' | 'match') => {
        if (!user) return

        setLoading(true)
        setStatus('idle')
        setError('')

        const data: any = {
            userId: user.id,
            title: '⚽ FutLog Debug',
            message: `Esta es una notificación de prueba de tipo: ${type}`,
            type: type
        }

        if (type === 'profile') {
            data.url = `/perfil/${user.id}`
            data.message = '¡Alguien te empezó a seguir! (Prueba)'
        } else if (type === 'match') {
            data.url = '/partido/debug' // Placeholder
            data.message = '¡GOL en el partido que estás siguiendo! (Prueba)'
        }

        try {
            const res = await fetch('/api/push/test', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            })

            const result = await res.json()
            if (!res.ok) throw new Error(result.error || 'Error al enviar')

            setStatus('success')
        } catch (err: any) {
            console.error(err)
            setStatus('error')
            setError(err.message)
        } finally {
            setLoading(false)
        }
    }

    if (!user) return null

    return (
        <div className="bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)] p-5 mt-4">
            <h3 className="font-bold flex items-center gap-2 text-sm text-[var(--foreground)] mb-4">
                <Bell size={16} className="text-[var(--accent)]" /> Panel de Debug: Notificaciones
            </h3>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                <button
                    onClick={() => sendTestNotification('test')}
                    disabled={loading}
                    className="flex items-center justify-center gap-2 px-3 py-2 bg-[var(--background)] border border-[var(--card-border)] rounded-xl text-xs font-medium hover:border-[var(--accent)] transition-all"
                >
                    <Send size={12} /> Test Simple
                </button>
                <button
                    onClick={() => sendTestNotification('profile')}
                    disabled={loading}
                    className="flex items-center justify-center gap-2 px-3 py-2 bg-[var(--background)] border border-[var(--card-border)] rounded-xl text-xs font-medium hover:border-[var(--accent)] transition-all"
                >
                    <Send size={12} /> Test Perfil
                </button>
                <button
                    onClick={() => sendTestNotification('match')}
                    disabled={loading}
                    className="flex items-center justify-center gap-2 px-3 py-2 bg-[var(--background)] border border-[var(--card-border)] rounded-xl text-xs font-medium hover:border-[var(--accent)] transition-all"
                >
                    <Send size={12} /> Test Partido
                </button>
            </div>

            {status === 'success' && (
                <motion.p
                    initial={{ opacity: 0, y: 5 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-[10px] text-emerald-500 mt-3 flex items-center gap-1"
                >
                    <CheckCircle2 size={10} /> Notificación enviada correctamente.
                </motion.p>
            )}

            {status === 'error' && (
                <motion.p
                    initial={{ opacity: 0, y: 5 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-[10px] text-red-500 mt-3 flex items-center gap-1"
                >
                    <AlertCircle size={10} /> {error}
                </motion.p>
            )}

            <p className="text-[10px] text-[var(--text-muted)] mt-4 italic">
                Nota: Requiere `ONESIGNAL_REST_API_KEY` en variables de entorno para funcionar.
            </p>
        </div>
    )
}

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { motion, AnimatePresence } from 'framer-motion'
import { useRouter } from 'next/navigation'

interface SearchBarProps {
    value: string
    onChange: (value: string) => void
    placeholder?: string
}

export function SearchBar({ value, onChange, placeholder = 'Buscar hincha o equipo...' }: SearchBarProps) {
    const [isFocused, setIsFocused] = useState(false)
    const [suggestions, setSuggestions] = useState<any[]>([])
    const [loading, setLoading] = useState(false)
    const router = useRouter()

    useEffect(() => {
        const timer = setTimeout(() => {
            if (value.length >= 2) {
                fetchSuggestions(value)
            } else {
                setSuggestions([])
            }
        }, 200)

        return () => clearTimeout(timer)
    }, [value])

    const fetchSuggestions = async (query: string) => {
        setLoading(true)
        const { data } = await supabase
            .from('profiles')
            .select('id, username, avatar_url')
            .ilike('username', `%${query}%`)
            .limit(5)

        setSuggestions(data || [])
        setLoading(false)
    }

    return (
        <div className="relative w-full max-w-md">
            <div className={`
        relative flex items-center gap-3 px-4 py-3 rounded-xl
        bg-[var(--card-bg)] border transition-all duration-200
        ${isFocused
                    ? 'border-[var(--accent)] shadow-lg shadow-[var(--accent)]/10'
                    : 'border-[var(--card-border)] hover:border-[var(--hover-bg)]'
                }
      `}>
                {/* Search Icon */}
                <span className="text-xl">🔍</span>

                {/* Input */}
                <input
                    type="text"
                    value={value}
                    onChange={(e) => onChange(e.target.value)}
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => setIsFocused(false)}
                    placeholder={placeholder}
                    className="flex-1 bg-transparent text-[var(--foreground)] placeholder-[var(--text-muted)] 
                     outline-none text-sm font-medium"
                />

                {/* Clear Button */}
                {value && (
                    <button
                        onClick={() => onChange('')}
                        className="text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                        aria-label="Limpiar búsqueda"
                    >
                        <span className="text-lg">✕</span>
                    </button>
                )}
            </div>

            {/* Suggestions Autocomplete */}
            <AnimatePresence>
                {isFocused && (suggestions.length > 0 || loading) && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="absolute top-full mt-2 left-0 right-0 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl shadow-2xl z-50 overflow-hidden"
                    >
                        {loading ? (
                            <div className="p-4 text-center text-xs text-[var(--text-muted)] animate-pulse">
                                Buscando...
                            </div>
                        ) : (
                            <div className="py-2">
                                {suggestions.map(s => (
                                    <button
                                        key={s.id}
                                        onMouseDown={() => router.push(`/perfil/${s.id}`)}
                                        className="w-full flex items-center gap-3 px-4 py-3 hover:bg-[var(--hover-bg)] transition-colors text-left"
                                    >
                                        <div className="w-8 h-8 rounded-full bg-[var(--hover-bg)] overflow-hidden flex items-center justify-center text-xs font-bold">
                                            {s.avatar_url ? <img src={s.avatar_url} className="w-full h-full object-cover" /> : s.username[0]}
                                        </div>
                                        <span className="text-sm font-medium">{s.username}</span>
                                    </button>
                                ))}
                            </div>
                        )}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    )
}

import { motion } from 'framer-motion'

