'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import Link from 'next/link'
import { Trophy, MessageSquare, TrendingUp } from 'lucide-react'
import { motion } from 'framer-motion'

interface TrendingMatch {
  id: number
  local: string
  visitante: string
  count: number
}

export function TopMatchesToday() {
  const [trending, setTrending] = useState<TrendingMatch[]>([])
  const [loading, setLoading] = useState(true)
  const supabase = createClient()

  useEffect(() => {
    const fetchTrending = async () => {
      const today = new Date()
      today.setHours(0, 0, 0, 0)

      // Fetch logs from today to count discussions
      const { data, error } = await supabase
        .from('match_logs')
        .select('equipo_local, equipo_visitante, match_id')
        .gte('created_at', today.toISOString())
        .order('created_at', { ascending: false })
        .limit(100)

      if (data) {
        const counts: Record<number, { local: string; visitante: string; count: number }> = {}
        data.forEach(log => {
          if (!log.match_id) return
          const id = Number(log.match_id)
          if (!counts[id]) {
            counts[id] = { local: log.equipo_local, visitante: log.equipo_visitante, count: 0 }
          }
          counts[id].count++
        })

        const sorted = Object.entries(counts)
          .map(([id, val]) => ({ id: Number(id), ...val }))
          .sort((a, b) => b.count - a.count)
          .slice(0, 3)

        setTrending(sorted)
      }
      setLoading(false)
    }

    fetchTrending()
  }, [])

  if (loading) return (
    <div className="grid grid-cols-1 gap-2 mb-8">
      {[1, 2, 3].map(i => <div key={i} className="h-12 bg-[var(--card-bg)] animate-pulse rounded-xl border border-[var(--card-border)]" />)}
    </div>
  )

  if (trending.length === 0) return null

  return (
    <div className="mb-8">
      <div className="flex items-center gap-2 mb-4 px-1">
        <div className="p-1.5 bg-amber-500/10 rounded-lg">
          <TrendingUp size={16} className="text-amber-500" />
        </div>
        <h2 className="text-xs font-black uppercase tracking-widest italic">Tendencias de Hoy</h2>
      </div>

      <div className="grid grid-cols-1 gap-3">
        {trending.map((match, i) => (
          <motion.div
            key={match.id}
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: i * 0.1 }}
          >
            <Link 
              href={`/partido/${match.id}`}
              className="group flex items-center justify-between p-4 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl hover:border-[var(--accent)]/40 hover:shadow-lg transition-all"
            >
              <div className="flex items-center gap-4 flex-1">
                <div className="flex flex-col items-center justify-center w-8 h-8 rounded-full bg-[var(--background)] text-[10px] font-black text-[var(--text-muted)] group-hover:bg-[var(--accent)] group-hover:text-white transition-colors">
                  #{i + 1}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-black truncate tracking-tighter">
                    {match.local} <span className="text-[var(--text-muted)] opacity-30 mx-1">vs</span> {match.visitante}
                  </p>
                  <div className="flex items-center gap-1.5 mt-0.5">
                    <MessageSquare size={10} className="text-[#6366f1]" />
                    <span className="text-[10px] font-bold text-[var(--text-muted)]">{match.count} reseñas hoy</span>
                  </div>
                </div>
              </div>
              <ChevronRight size={16} className="text-[var(--text-muted)] group-hover:translate-x-1 transition-transform" />
            </Link>
          </motion.div>
        ))}
      </div>
    </div>
  )
}

function ChevronRight({ size, className }: { size: number; className?: string }) {
  return (
    <svg 
      width={size} 
      height={size} 
      viewBox="0 0 24 24" 
      fill="none" 
      stroke="currentColor" 
      strokeWidth="3" 
      strokeLinecap="round" 
      strokeLinejoin="round" 
      className={className}
    >
      <path d="m9 18 6-6-6-6"/>
    </svg>
  )
}

// src/components/grupos/CanchaSeleccion.tsx
'use client'

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { FORMACIONES, Formacion } from '@/lib/formaciones'
import type { JugadorPartidoAmigo } from '@/types'

interface CanchaSeleccionProps {
    tipoPartido: string
    equipo: 'azul' | 'rojo'
    jugadores: JugadorPartidoAmigo[]
    onSelectPosicion: (orden: number) => void // Al hacer click en un slot vacío o lleno
    onEliminarJugador: (jugador: JugadorPartidoAmigo) => void // Al hacer click en "borrar"
    formacionActual: Formacion
    setFormacionActual: (f: Formacion) => void
}

export function CanchaSeleccion({
    tipoPartido,
    equipo,
    jugadores,
    onSelectPosicion,
    onEliminarJugador,
    formacionActual,
    setFormacionActual
}: CanchaSeleccionProps) {
    const formacionesDisponibles = FORMACIONES[tipoPartido] || []

    // Si no hay formacion, usar la primera por defecto (esto debería manejarse arriba, pero por seguridad)
    const formacion = formacionActual || formacionesDisponibles[0]

    return (
        <div className="flex flex-col gap-4">
            {/* Header: Selector de Formación */}
            <div className="flex justify-between items-center bg-[var(--card-bg)] p-3 rounded-xl border border-[var(--card-border)]">
                <span className="text-sm font-bold text-[var(--text-muted)] capitalize">Formación</span>
                <div className="flex gap-2">
                    {formacionesDisponibles.map(f => (
                        <button
                            key={f.nombre}
                            onClick={() => setFormacionActual(f)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all
                                ${formacion.nombre === f.nombre
                                    ? 'bg-[var(--foreground)] text-[var(--background)] border-[var(--foreground)]'
                                    : 'border-[var(--card-border)] hover:bg-[var(--hover-bg)]'}`}
                        >
                            {f.nombre}
                        </button>
                    ))}
                </div>
            </div>

            {/* Cancha */}
            <div className="relative aspect-[3/4] w-full max-w-sm mx-auto bg-gradient-to-b from-[#2d5016] to-[#1e3a0f] rounded-2xl border-4 border-[#333] shadow-inner overflow-hidden">
                {/* Patrón de pasto */}
                <div className="absolute inset-0 opacity-10"
                    style={{ backgroundImage: 'repeating-linear-gradient(0deg, transparent, transparent 20px, #000 20px, #000 40px)' }}>
                </div>

                {/* Líneas */}
                <div className="absolute inset-0 opacity-40 pointer-events-none">
                    <div className="absolute top-1/2 w-full h-0.5 bg-white/50"></div>
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-20 h-20 border-2 border-white/50 rounded-full"></div>
                    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-16 border-b-2 border-x-2 border-white/50 rounded-b-lg"></div>
                    <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-32 h-16 border-t-2 border-x-2 border-white/50 rounded-t-lg"></div>
                </div>

                {/* Posiciones */}
                <div className="absolute inset-0 p-4">
                    {formacion?.posiciones.map((pos, index) => {
                        // Buscar si hay jugador en este 'orden' (index)
                        // IMPORTANTE: El backend usa indices 0-based o 1-based?
                        // Asumiremos que 'orden' en JugadorPartidoAmigo coincide con este index.
                        const jugador = jugadores.find(j => j.orden === index)

                        return (
                            <div
                                key={index}
                                className="absolute -translate-x-1/2 -translate-y-1/2 flex flex-col items-center gap-1"
                                style={{
                                    left: `${pos.x}%`,
                                    top: `${pos.y}%`,
                                    zIndex: 10
                                }}
                            >
                                <button
                                    onClick={() => onSelectPosicion(index)}
                                    className={`w-10 h-10 rounded-full flex items-center justify-center border-2 shadow-lg transition-transform hover:scale-110 active:scale-95
                                        ${jugador
                                            ? (equipo === 'azul' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-red-600 border-red-400 text-white')
                                            : 'bg-black/40 border-white/30 text-white/50 hover:bg-black/60 hover:border-white/50'
                                        }`}
                                >
                                    {jugador ? (
                                        <span className="text-xs font-black">{index === 0 ? 'ARQ' : index}</span>
                                    ) : (
                                        <span className="text-lg font-light">+</span>
                                    )}
                                </button>

                                <div className="bg-black/70 px-2 py-0.5 rounded text-[10px] font-bold text-white max-w-[80px] truncate backdrop-blur-sm">
                                    {jugador ? jugador.nombre : pos.label || 'Vacío'}
                                </div>

                                {jugador && (
                                    <button
                                        onClick={(e) => { e.stopPropagation(); onEliminarJugador(jugador) }}
                                        className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 rounded-full text-white flex items-center justify-center text-[10px] shadow-sm hover:scale-110"
                                    >✕</button>
                                )}
                            </div>
                        )
                    })}
                </div>
            </div>

            {/* Lista resumen (opcional, para ver a todos si la cancha confunde) */}
            <div className="text-xs text-center text-[var(--text-muted)]">
                {jugadores.length} / {formacion.posiciones.length} jugadores
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useGrupos } from '@/hooks/useGrupos'
import { motion } from 'framer-motion'

interface Props {
    onCancel: () => void
    onSuccess?: () => void
}

export function CrearGrupoForm({ onCancel, onSuccess }: Props) {
    const router = useRouter()
    const { crearGrupo } = useGrupos()
    const [nombre, setNombre] = useState('')
    const [procesando, setProcesando] = useState(false)

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!nombre.trim()) return

        setProcesando(true)
        try {
            const grupo = await crearGrupo(nombre)
            setNombre('')
            if (onSuccess) onSuccess()
            router.push(`/grupos/${grupo.id}`)
        } catch (error: any) {
            alert(error.message)
        } finally {
            setProcesando(false)
        }
    }

    return (
        <motion.form
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            onSubmit={handleSubmit}
            className="bg-[var(--card-bg)] p-8 rounded-3xl border border-[var(--card-border)] shadow-xl mb-12"
        >
            <div className="flex items-center gap-3 mb-6">
                <div className="w-10 h-10 bg-[#10b981]/20 rounded-xl flex items-center justify-center text-xl">👥</div>
                <div>
                    <h3 className="font-black italic text-xl capitalize tracking-tighter">Nuevo Grupo</h3>
                    <p className="text-xs text-[var(--text-muted)] font-medium">Sumá a tus amigos y empezá a votar</p>
                </div>
            </div>

            <div className="space-y-6">
                <div>
                    <label className="block text-[10px] font-black capitalize tracking-[0.2em] text-[var(--text-muted)] mb-2">Nombre del Grupo</label>
                    <input
                        type="text"
                        placeholder="Ej: Los Pibes del FutLog"
                        value={nombre}
                        onChange={(e) => setNombre(e.target.value)}
                        className="w-full bg-[var(--background)] border-2 border-[var(--card-border)] rounded-2xl px-5 py-4 outline-none focus:border-[#10b981] transition-all font-bold text-lg"
                        autoFocus
                    />
                </div>

                <div className="flex flex-col sm:flex-row gap-3 pt-2">
                    <button
                        type="submit"
                        disabled={procesando || !nombre.trim()}
                        className="flex-1 bg-[#10b981] text-white py-4 rounded-2xl font-black capitalize tracking-widest text-xs shadow-lg shadow-emerald-500/20 hover:brightness-110 disabled:opacity-50 transition-all active:scale-[0.98]"
                    >
                        {procesando ? 'Creando...' : 'Crear Grupo'}
                    </button>
                    <button
                        type="button"
                        onClick={onCancel}
                        className="px-8 py-4 bg-[var(--background)] text-[var(--text-muted)] hover:text-[var(--foreground)] border border-[var(--card-border)] rounded-2xl transition-all font-black capitalize tracking-widest text-xs"
                    >
                        Cancelar
                    </button>
                </div>
            </div>
        </motion.form>
    )
}

// src/components/grupos/CrearPartidoAmigo.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { supabase } from '@/lib/supabase'
import { useToast } from '@/contexts/ToastContext'
import { CanchaSeleccion } from './CanchaSeleccion'
import { Formacion } from '@/lib/formaciones'
import type { TipoPartidoAmigo, JugadorPartidoAmigo } from '@/types'

interface CrearPartidoAmigoProps {
    grupoId: string
    onClose: () => void
    onCreated: () => void
}

const TIPOS_PARTIDO: { value: TipoPartidoAmigo; label: string; jugadores: number }[] = [
    { value: '5', label: 'Fútbol 5', jugadores: 10 },
    { value: '7', label: 'Fútbol 7', jugadores: 14 },
    { value: '8', label: 'Fútbol 8', jugadores: 16 },
    { value: '9', label: 'Fútbol 9', jugadores: 18 },
    { value: '11', label: 'Fútbol 11', jugadores: 22 },
]

export function CrearPartidoAmigo({ grupoId, onClose, onCreated }: CrearPartidoAmigoProps) {
    const { crearPartido, agregarJugador, eliminarJugador, abrirVotacion } = usePartidosAmigos(grupoId)
    const { showToast } = useToast()

    // Step 1 state
    const [paso, setPaso] = useState(1)
    const [tipo, setTipo] = useState<TipoPartidoAmigo>('7')
    const [fecha, setFecha] = useState('')
    const [hora, setHora] = useState('18:00')
    const [cancha, setCancha] = useState('')

    // Step 2 state
    const [partidoId, setPartidoId] = useState<string | null>(null)
    const [jugadoresAzul, setJugadoresAzul] = useState<JugadorPartidoAmigo[]>([])
    const [jugadoresRojo, setJugadoresRojo] = useState<JugadorPartidoAmigo[]>([])
    const [nuevoNombre, setNuevoNombre] = useState('')
    const [selectedUserId, setSelectedUserId] = useState<string | null>(null) // Nuevo
    const [miembros, setMiembros] = useState<any[]>([]) // Nuevo
    const [equipoAgregando, setEquipoAgregando] = useState<'azul' | 'rojo' | null>(null)
    const [ordenAgregando, setOrdenAgregando] = useState<number | null>(null) // Nuevo: Slot seleccionado
    const [guardando, setGuardando] = useState(false)

    // Estado de formaciones
    const [formacionAzul, setFormacionAzul] = useState<Formacion | null>(null)
    const [formacionRojo, setFormacionRojo] = useState<Formacion | null>(null)

    // Nuevo: Fetch miembros
    useEffect(() => {
        if (grupoId) {
            supabase
                .from('miembros_grupo')
                .select('user_id, profile:profiles(username)')
                .eq('grupo_id', grupoId)
                .then(({ data }) => setMiembros(data || []))
        }
    }, [grupoId])

    const tipoInfo = TIPOS_PARTIDO.find(t => t.value === tipo)!
    const jugadoresPorEquipo = tipoInfo.jugadores / 2

    // Resetear formaciones y jugadores si cambia el tipo de partido
    useEffect(() => {
        setFormacionAzul(null)
        setFormacionRojo(null)
        setJugadoresAzul([])
        setJugadoresRojo([])
    }, [tipo])

    // ── PASO 1: Crear partido ──
    const handleSiguiente = async () => {
        if (!fecha) {
            showToast('Seleccioná una fecha', 'error')
            return
        }
        setGuardando(true)
        try {
            const partido = await crearPartido({
                tipo_partido: tipo,
                fecha,
                hora,
                cancha: cancha || undefined
            })
            setPartidoId(partido.id)
            setPaso(2)
        } catch (err: any) {
            showToast(err.message, 'error')
        } finally {
            setGuardando(false)
        }
    }

    // ── PASO 2: Agregar jugadores ──
    const handleAgregarJugador = async () => {
        if (!nuevoNombre.trim() || !partidoId || !equipoAgregando) return
        setGuardando(true)
        try {
            // Pasamos selectedUserId (si es null será invitado)
            const jugador = await agregarJugador(partidoId, nuevoNombre.trim(), equipoAgregando, selectedUserId || undefined)

            // Si tenemos orden, lo actualizamos (esto requeriría update en DB si queremos persistir posición exacta)
            // Por ahora, solo lo usamos visualmente en el cliente, pero el hook devuelve el objeto.
            // Hack: Asignamos 'orden' manualmente al objeto local para que se vea en la cancha
            if (ordenAgregando !== null) {
                jugador.orden = ordenAgregando
            }

            if (equipoAgregando === 'azul') {
                setJugadoresAzul(prev => [...prev, jugador])
            } else {
                setJugadoresRojo(prev => [...prev, jugador])
            }
            setNuevoNombre('')
            setSelectedUserId(null)
            setEquipoAgregando(null)
            setOrdenAgregando(null)
        } catch (err: any) {
            showToast(err.message, 'error')
        } finally {
            setGuardando(false)
        }
    }

    const handleEliminarJugador = async (jugador: JugadorPartidoAmigo) => {
        try {
            await eliminarJugador(jugador.id)
            if (jugador.equipo === 'azul') {
                setJugadoresAzul(prev => prev.filter(j => j.id !== jugador.id))
            } else {
                setJugadoresRojo(prev => prev.filter(j => j.id !== jugador.id))
            }
        } catch (err: any) {
            showToast(err.message, 'error')
        }
    }

    const handleCrearYAbrir = async () => {
        if (!partidoId) return
        if (jugadoresAzul.length === 0 && jugadoresRojo.length === 0) {
            showToast('Agregá al menos un jugador', 'error')
            return
        }
        setGuardando(true)
        try {
            await abrirVotacion(partidoId)
            showToast('¡Partido creado! Votación abierta 🗳️', 'success')
            onCreated()
            onClose()
        } catch (err: any) {
            showToast(err.message, 'error')
        } finally {
            setGuardando(false)
        }
    }

    const handleGuardarBorrador = () => {
        showToast('Partido guardado como borrador 📝', 'success')
        onCreated()
        onClose()
    }

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-end sm:items-center justify-center"
            onClick={onClose}
        >
            <motion.div
                initial={{ y: '100%' }}
                animate={{ y: 0 }}
                exit={{ y: '100%' }}
                transition={{ type: 'spring', damping: 25 }}
                className="bg-[var(--card-bg)] rounded-t-3xl sm:rounded-3xl w-full max-w-lg max-h-[90vh] overflow-y-auto border border-[var(--card-border)] shadow-2xl"
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <div className="sticky top-0 bg-[var(--card-bg)] z-10 p-5 border-b border-[var(--card-border)] flex items-center gap-3">
                    {paso === 2 && (
                        <button onClick={() => setPaso(1)}
                            className="w-8 h-8 rounded-full bg-[var(--background)] flex items-center justify-center">←</button>
                    )}
                    <div className="flex-1">
                        <h3 className="text-lg font-black">
                            {paso === 1 ? '⚽ Crear Partido Amateur' : `🏗️ Armar Equipos (${tipoInfo.label})`}
                        </h3>
                        <p className="text-xs text-[var(--text-muted)]">Paso {paso} de 2</p>
                    </div>
                    <button onClick={onClose}
                        className="w-8 h-8 rounded-full bg-[var(--background)] flex items-center justify-center text-[var(--text-muted)]"
                    >✕</button>
                </div>

                <AnimatePresence mode="wait">
                    {paso === 1 ? (
                        <motion.div
                            key="paso1"
                            initial={{ x: -20, opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            exit={{ x: -20, opacity: 0 }}
                            className="p-5 space-y-5"
                        >
                            {/* Tipo de partido */}
                            <div>
                                <label className="text-xs font-bold text-[var(--text-muted)] capitalize mb-2 block">
                                    ⚽ Tipo de partido
                                </label>
                                <div className="space-y-2">
                                    {TIPOS_PARTIDO.map(t => (
                                        <button
                                            key={t.value}
                                            onClick={() => setTipo(t.value)}
                                            className={`w-full p-3 rounded-[var(--radius)] border text-left flex justify-between items-center transition-all ${tipo === t.value
                                                ? 'border-[#16a34a] bg-[#16a34a]/10 text-[#16a34a]'
                                                : 'border-[var(--card-border)] hover:bg-[var(--hover-bg)]'
                                                }`}
                                        >
                                            <span className="font-bold">{tipo === t.value ? '●' : '○'} {t.label}</span>
                                            <span className="text-xs text-[var(--text-muted)]">({t.jugadores} jugadores)</span>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Fecha y hora */}
                            <div className="grid grid-cols-2 gap-3">
                                <div>
                                    <label className="text-xs font-bold text-[var(--text-muted)] capitalize mb-1 block">📅 Fecha</label>
                                    <input
                                        type="date"
                                        value={fecha}
                                        onChange={e => setFecha(e.target.value)}
                                        className="w-full bg-[var(--input-bg)] border border-[var(--card-border)] rounded-[var(--radius)] p-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#16a34a]/50"
                                    />
                                </div>
                                <div>
                                    <label className="text-xs font-bold text-[var(--text-muted)] capitalize mb-1 block">🕐 Hora</label>
                                    <input
                                        type="time"
                                        value={hora}
                                        onChange={e => setHora(e.target.value)}
                                        className="w-full bg-[var(--input-bg)] border border-[var(--card-border)] rounded-[var(--radius)] p-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#16a34a]/50"
                                    />
                                </div>
                            </div>

                            {/* Cancha */}
                            <div>
                                <label className="text-xs font-bold text-[var(--text-muted)] capitalize mb-1 block">📍 Cancha</label>
                                <input
                                    type="text"
                                    value={cancha}
                                    onChange={e => setCancha(e.target.value)}
                                    placeholder="Ej: Cancha Don Pepe"
                                    className="w-full bg-[var(--input-bg)] border border-[var(--card-border)] rounded-[var(--radius)] p-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#16a34a]/50"
                                />
                            </div>

                            {/* Siguiente */}
                            <button
                                onClick={handleSiguiente}
                                disabled={!fecha || guardando}
                                className="w-full py-4 rounded-[var(--radius)] font-black text-white bg-[#16a34a] disabled:opacity-40 hover:bg-[#059669] transition-all"
                            >
                                {guardando ? '⏳ Creando...' : 'Siguiente: Armar Equipos →'}
                            </button>
                        </motion.div>
                    ) : (
                        <motion.div
                            key="paso2"
                            initial={{ x: 20, opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            exit={{ x: 20, opacity: 0 }}
                            className="p-5 space-y-4"
                        >
                            <div className="flex flex-col sm:flex-row gap-8">
                                {/* Equipo Azul */}
                                <div className="flex-1">
                                    <h4 className="font-black text-blue-500 mb-2 text-center">🔵 EQUIPO AZUL</h4>
                                    <CanchaSeleccion
                                        tipoPartido={tipo}
                                        equipo="azul"
                                        jugadores={jugadoresAzul}
                                        onSelectPosicion={(orden) => {
                                            setEquipoAgregando('azul')
                                            setOrdenAgregando(orden)
                                        }}
                                        onEliminarJugador={handleEliminarJugador}
                                        formacionActual={formacionAzul!}
                                        setFormacionActual={setFormacionAzul}
                                    />
                                </div>

                                {/* Equipo Rojo */}
                                <div className="flex-1">
                                    <h4 className="font-black text-red-500 mb-2 text-center">🔴 EQUIPO ROJO</h4>
                                    <CanchaSeleccion
                                        tipoPartido={tipo}
                                        equipo="rojo"
                                        jugadores={jugadoresRojo}
                                        onSelectPosicion={(orden) => {
                                            setEquipoAgregando('rojo')
                                            setOrdenAgregando(orden)
                                        }}
                                        onEliminarJugador={handleEliminarJugador}
                                        formacionActual={formacionRojo!}
                                        setFormacionActual={setFormacionRojo}
                                    />
                                </div>
                            </div>

                            {/* Actions */}
                            <div className="space-y-2 pt-2">
                                <button
                                    onClick={handleCrearYAbrir}
                                    disabled={guardando || (jugadoresAzul.length === 0 && jugadoresRojo.length === 0)}
                                    className="w-full py-4 rounded-[var(--radius)] font-black text-white bg-[#16a34a] disabled:opacity-40 hover:bg-[#059669] transition-all"
                                >
                                    {guardando ? '⏳' : '🗳️ Crear y Abrir Votación'}
                                </button>
                                <button
                                    onClick={handleGuardarBorrador}
                                    className="w-full py-3 rounded-[var(--radius)] font-bold text-[var(--text-muted)] border border-[var(--card-border)] hover:bg-[var(--hover-bg)]"
                                >
                                    📝 Guardar como Borrador
                                </button>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Modal agregar jugador */}
                <AnimatePresence>
                    {equipoAgregando && (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className="fixed inset-0 bg-black/40 z-[60] flex items-center justify-center p-4"
                            onClick={() => setEquipoAgregando(null)}
                        >
                            <motion.div
                                initial={{ scale: 0.9 }}
                                animate={{ scale: 1 }}
                                exit={{ scale: 0.9 }}
                                className="bg-[var(--card-bg)] rounded-2xl p-5 w-full max-w-xs border border-[var(--card-border)] shadow-2xl"
                                onClick={e => e.stopPropagation()}
                            >
                                <h4 className="font-black mb-3">➕ Agregar Jugador</h4>
                                <p className="text-xs text-[var(--text-muted)] mb-3">
                                    Equipo {equipoAgregando === 'azul' ? '🔵 Azul' : '🔴 Rojo'}
                                </p>
                                <div className="mb-3 space-y-2">
                                    {/* Lista de miembros para seleccionar */}
                                    <div className="max-h-32 overflow-y-auto border border-[var(--card-border)] rounded-[var(--radius)] mb-2">
                                        {miembros.map(m => (
                                            <button
                                                key={m.user_id}
                                                onClick={() => {
                                                    setNuevoNombre(m.profile?.username || 'Usuario');
                                                    setSelectedUserId(m.user_id);
                                                }}
                                                className={`w-full text-left p-2 text-xs flex items-center gap-2 hover:bg-[var(--hover-bg)] ${selectedUserId === m.user_id ? 'bg-[#16a34a]/10 text-[#16a34a] font-bold' : ''
                                                    }`}
                                            >
                                                <span>{m.profile?.username}</span>
                                            </button>
                                        ))}
                                    </div>

                                    <div className="flex gap-2">
                                        <input
                                            type="text"
                                            value={nuevoNombre}
                                            onChange={e => {
                                                setNuevoNombre(e.target.value);
                                                setSelectedUserId(null); // Si escribe manualmente, es invitado
                                            }}
                                            onKeyDown={e => e.key === 'Enter' && handleAgregarJugador()}
                                            placeholder="O escribí nombre invitado..."
                                            autoFocus
                                            className="flex-1 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-[var(--radius)] p-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#16a34a]/50"
                                        />
                                    </div>
                                </div>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => { setEquipoAgregando(null); setNuevoNombre(''); setSelectedUserId(null); setOrdenAgregando(null) }}
                                        className="flex-1 py-2 rounded-[var(--radius)] text-[var(--text-muted)] font-bold"
                                    >Cancelar</button>
                                    <button
                                        onClick={handleAgregarJugador}
                                        disabled={!nuevoNombre.trim() || guardando}
                                        className="flex-1 py-2 rounded-[var(--radius)] font-black text-white bg-[#16a34a] disabled:opacity-40"
                                    >{guardando ? '⏳' : 'Agregar'}</button>
                                </div>
                            </motion.div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </motion.div>
        </motion.div>
    )
}

function TeamSection({ equipo, color, emoji, maxJugadores, jugadores, onAgregar, onEliminar }: {
    equipo: 'azul' | 'rojo'
    color: string
    emoji: string
    maxJugadores: number
    jugadores: JugadorPartidoAmigo[]
    onAgregar: () => void
    onEliminar: (j: JugadorPartidoAmigo) => void
}) {
    return (
        <div>
            <h4 className="font-black text-sm mb-2" style={{ color }}>
                {emoji} EQUIPO {equipo.toUpperCase()} ({jugadores.length}/{maxJugadores})
            </h4>

            <button
                onClick={onAgregar}
                className="w-full p-3 rounded-[var(--radius)] border-2 border-dashed border-[var(--card-border)] text-sm text-[var(--text-muted)] hover:border-[#16a34a] hover:text-[#16a34a] transition-all mb-2"
            >
                + Agregar jugador
            </button>

            <div className="space-y-1">
                {jugadores.map(j => (
                    <motion.div
                        key={j.id}
                        initial={{ x: -10, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        className="flex items-center justify-between p-3 bg-[var(--background)] rounded-[var(--radius)]"
                    >
                        <span className="text-sm font-bold">👤 {j.nombre}</span>
                        <button
                            onClick={() => onEliminar(j)}
                            className="text-[#ef4444] hover:bg-[#ef4444]/10 w-7 h-7 rounded-full flex items-center justify-center text-xs"
                        >❌</button>
                    </motion.div>
                ))}
            </div>
        </div>
    )
}

// src/components/grupos/DetalleJugadorAmigo.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import type { JugadorPartidoAmigo, VotoPartidoAmigo } from '@/types'

interface DetalleJugadorProps {
    jugador: JugadorPartidoAmigo
    grupoId: string
    onClose: () => void
}

export function DetalleJugadorAmigo({ jugador, grupoId, onClose }: DetalleJugadorProps) {
    const { fetchDetalleJugador } = usePartidosAmigos(grupoId)
    const [detalle, setDetalle] = useState<{
        votos: (VotoPartidoAmigo & { profile?: any })[]
        distribucion: Record<number, number>
        promedio: number
        totalVotos: number
    } | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        loadDetalle()
    }, [jugador.id])

    const loadDetalle = async () => {
        try {
            const data = await fetchDetalleJugador(jugador.id)
            setDetalle(data)
        } catch (e) {
            console.error(e)
        } finally {
            setLoading(false)
        }
    }

    const maxDistribucion = detalle
        ? Math.max(...Object.values(detalle.distribucion), 1)
        : 1

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-end sm:items-center justify-center"
            onClick={onClose}
        >
            <motion.div
                initial={{ y: 100, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                className="bg-[var(--card-bg)] rounded-t-3xl sm:rounded-3xl w-full max-w-md max-h-[85vh] overflow-y-auto border border-[var(--card-border)] shadow-2xl pb-[env(safe-area-inset-bottom)]"
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <div className="p-5 border-b border-[var(--card-border)] flex items-center justify-between">
                    <div>
                        <h3 className="text-xl font-black">👤 {jugador.nombre}</h3>
                        <p className="text-xs text-[var(--text-muted)]">
                            Equipo {jugador.equipo === 'azul' ? '🔵 Azul' : '🔴 Rojo'}
                        </p>
                    </div>
                    <button onClick={onClose}
                        className="w-8 h-8 rounded-full bg-[var(--background)] flex items-center justify-center text-[var(--text-muted)]"
                    >✕</button>
                </div>

                {loading ? (
                    <div className="p-10 text-center text-[var(--text-muted)]">⏳ Cargando...</div>
                ) : detalle && (
                    <div className="p-5 space-y-5">
                        {/* Nota final */}
                        <div className="text-center">
                            <div className="text-5xl font-black text-[#fbbf24]">⭐ {detalle.promedio}</div>
                            <p className="text-sm text-[var(--text-muted)] mt-1">
                                Basada en {detalle.totalVotos} voto{detalle.totalVotos !== 1 ? 's' : ''}
                            </p>
                        </div>

                        {/* Distribución de votos */}
                        <div className="bg-[var(--background)] rounded-2xl p-4">
                            <h4 className="font-bold text-sm mb-3">Distribución de votos</h4>
                            <div className="space-y-1.5">
                                {Array.from({ length: 10 }, (_, i) => 10 - i).map(n => {
                                    const count = detalle.distribucion[n] || 0
                                    const width = (count / maxDistribucion) * 100
                                    return (
                                        <div key={n} className="flex items-center gap-2 text-xs">
                                            <span className="w-8 text-right font-bold text-[#fbbf24]">{n} ⭐</span>
                                            <div className="flex-1 h-5 bg-[var(--card-bg)] rounded-full overflow-hidden">
                                                <motion.div
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${width}%` }}
                                                    transition={{ delay: 0.1 * (10 - n), duration: 0.5 }}
                                                    className={`h-full rounded-full ${n >= 8 ? 'bg-[#22c55e]' : n >= 5 ? 'bg-[#fbbf24]' : 'bg-[#ef4444]'}`}
                                                />
                                            </div>
                                            <span className="w-6 text-[var(--text-muted)]">({count})</span>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>

                        {/* Comentarios */}
                        {detalle.votos.filter(v => v.comentario).length > 0 && (
                            <div>
                                <h4 className="font-bold text-sm mb-3">
                                    💬 Comentarios ({detalle.votos.filter(v => v.comentario).length})
                                </h4>
                                <div className="space-y-3">
                                    {detalle.votos
                                        .filter(v => v.comentario)
                                        .map(v => (
                                            <div key={v.id} className="bg-[var(--background)] rounded-xl p-3">
                                                <div className="flex items-center justify-between mb-1">
                                                    <span className="text-xs font-bold">
                                                        {v.profile?.username || 'Anónimo'}
                                                    </span>
                                                    <span className="text-xs text-[#fbbf24] font-bold">{v.nota}/10 ⭐</span>
                                                </div>
                                                <p className="text-sm text-[var(--text-muted)]">&ldquo;{v.comentario}&rdquo;</p>
                                            </div>
                                        ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </motion.div>
        </motion.div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useToast } from '@/contexts/ToastContext'
import { LoadingSpinner } from '@/components/LoadingSpinner'
import { Info, BarChart2, Inbox, Trophy, X, UserPlus, Flashlight as Flash } from 'lucide-react'
import type { PartidoAmigo, JugadorPartidoAmigo, FacetType, FacetVote } from '@/types'
import { FacetVotingCards } from './FacetVotingCards'
import { MatchStatisticsPanel } from './MatchStatisticsPanel'
import { CanchaSeleccion } from './CanchaSeleccion'
import { VotarModal } from './VotarModal'
import { VotacionRapida } from './VotacionRapida'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/lib/supabase'
import { FORMACIONES, Formacion } from '@/lib/formaciones'

interface MatchDetailTabsProps {
    partido: PartidoAmigo
    grupoId: string
    onClose: () => void
    onUpdate: () => void
    initialTab?: 'info' | 'stats' | 'votos' | 'resultados'
}

export function MatchDetailTabs({ partido, grupoId, onClose, onUpdate, initialTab = 'info' }: MatchDetailTabsProps) {
    const { user } = useAuth()
    const { showToast } = useToast()
    const [activeTab, setActiveTab] = useState<'info' | 'stats' | 'votos' | 'resultados'>(initialTab)
    const [jugadores, setJugadores] = useState<JugadorPartidoAmigo[]>([])
    const [facetVotes, setFacetVotes] = useState<FacetVote[]>([])
    const [loading, setLoading] = useState(true)

    // States for Lineup/Creation
    const [miembros, setMiembros] = useState<any[]>([])
    const [equipoAgregando, setEquipoAgregando] = useState<'azul' | 'rojo' | null>(null)
    const [ordenAgregando, setOrdenAgregando] = useState<number | null>(null)
    const [nuevoNombre, setNuevoNombre] = useState('')
    const [selectedUserId, setSelectedUserId] = useState<string | null>(null)
    const [formacionAzul, setFormacionAzul] = useState<Formacion | null>(null)
    const [formacionRojo, setFormacionRojo] = useState<Formacion | null>(null)
    const [guardando, setGuardando] = useState(false)

    // States for Voting
    const [votandoA, setVotandoA] = useState<JugadorPartidoAmigo | null>(null)
    const [showRapida, setShowRapida] = useState(false)

    const { 
        fetchJugadoresConVotos, 
        votarJugador, 
        eliminarVotoJugador,
        votarFaceta, 
        eliminarVotoFaceta,
        fetchFacetVotes, 
        agregarJugador,
        eliminarJugador
    } = usePartidosAmigos(grupoId)

    useEffect(() => {
        loadData()
        fetchMiembros()
    }, [partido.id])

    const fetchMiembros = async () => {
        const { data } = await supabase
            .from('miembros_grupo')
            .select('user_id, profile:profiles(username)')
            .eq('grupo_id', grupoId)
        setMiembros(data || [])
    }

    const loadData = async () => {
        try {
            setLoading(true)
            const [jugs, fVotes] = await Promise.all([
                fetchJugadoresConVotos(partido.id),
                fetchFacetVotes(partido.id)
            ])
            setJugadores(jugs)
            setFacetVotes(fVotes)
        } catch {
            showToast('Error cargando datos del partido', 'error')
        } finally {
            setLoading(false)
        }
    }

    const handleVotar = async (nota: number, comentario?: string) => {
        if (!votandoA) return
        try {
            await votarJugador(partido.id, votandoA.id, nota, comentario)
            showToast(`Voto guardado para ${votandoA.nombre} ⭐`, 'success')
            loadData()
        } catch {
            showToast('Error al guardar voto', 'error')
        }
    }

    const handleEliminarVoto = async (jugadorId: string) => {
        try {
            await eliminarVotoJugador(partido.id, jugadorId)
            showToast('Voto eliminado 🗑️', 'success')
            loadData()
        } catch {
            showToast('Error al eliminar voto', 'error')
        }
    }

    const handleVotarTodos = async (votos: { jugadorId: string; nota: number }[]) => {
        try {
            for (const v of votos) {
                await votarJugador(partido.id, v.jugadorId, v.nota)
            }
            showToast(`${votos.length} votos guardados ⚡`, 'success')
            await loadData()
        } catch {
            showToast('Error al guardar votos', 'error')
        }
    }

    const handleAgregarJugador = async () => {
        if (!nuevoNombre.trim() || !equipoAgregando) return
        setGuardando(true)
        try {
            const jugador = await agregarJugador(partido.id, nuevoNombre.trim(), equipoAgregando, selectedUserId || undefined)

            // Si tenemos orden, lo asignamos visualmente (esto asume que el backend no lo guarda pero el frontend lo usa para la cancha)
            if (ordenAgregando !== null) {
                // Actualizamos el orden en la DB si es necesario, pero CrearPartidoAmigo.tsx lo hacía localmente
                // Por ahora replicamos el comportamiento:
                jugador.orden = ordenAgregando
            }

            showToast('Jugador agregado', 'success')
            setNuevoNombre('')
            setSelectedUserId(null)
            setEquipoAgregando(null)
            setOrdenAgregando(null)
            await loadData()
        } catch (err: any) {
            showToast(err.message, 'error')
        } finally {
            setGuardando(false)
        }
    }

    const handleEliminarJugador = async (j: JugadorPartidoAmigo) => {
        try {
            await eliminarJugador(j.id)
            showToast('Jugador eliminado', 'success')
            await loadData()
        } catch (err: any) {
            showToast(err.message, 'error')
        }
    }

    const esAutor = user?.id === partido.creado_por
    const votados = jugadores.filter(j => j.mi_voto).length
    const totalJugadores = jugadores.length
    const progreso = totalJugadores > 0 ? Math.round((votados / totalJugadores) * 100) : 0

    const tabs = [
        { id: 'info', label: 'Info', icon: Info },
        { id: 'stats', label: 'Estadísticas', icon: BarChart2 },
        { id: 'votos', label: 'Votos', icon: Inbox },
        { id: 'resultados', label: 'Resultados', icon: Trophy },
    ] as const

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 20 }}
            className="fixed inset-0 bg-[var(--background)] z-[60] flex flex-col"
        >
            {/* Header Sticky */}
            <div className="bg-[#16a34a] text-white pt-10 pb-4 px-6 relative shrink-0">
                <button 
                    onClick={onClose}
                    className="absolute top-10 right-6 p-2 bg-black/20 rounded-full hover:bg-black/30 transition-all"
                >
                    <X size={20} />
                </button>
                <div className="max-w-4xl mx-auto">
                    <h2 className="text-2xl font-black italic tracking-tighter">
                        ⚽ Detalle del Partido
                    </h2>
                    <p className="text-white/80 text-[10px] font-bold uppercase tracking-widest mt-1">
                        {new Date(partido.fecha + 'T00:00:00').toLocaleDateString('es-AR', { weekday: 'long', day: 'numeric', month: 'long' })}
                    </p>
                </div>
            </div>

            {/* Selector de Tabs */}
            <div className="bg-[var(--card-bg)] border-b border-[var(--card-border)] px-4 py-2 shrink-0">
                <div className="max-w-4xl mx-auto flex gap-1">
                    {tabs.map((tab) => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex-1 flex flex-col items-center gap-1 py-2 rounded-xl transition-all ${
                                activeTab === tab.id 
                                ? 'bg-[#16a34a]/10 text-[#16a34a]' 
                                : 'text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'
                            }`}
                        >
                            <tab.icon size={18} />
                            <span className="text-[10px] font-black uppercase tracking-tighter">
                                {tab.label}
                            </span>
                        </button>
                    ))}
                </div>
            </div>

            {/* Scrollable Content */}
            <div className="flex-1 overflow-y-auto pb-24">
                <div className="max-w-4xl mx-auto p-6">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-20 opacity-50">
                            <LoadingSpinner />
                            <p className="text-[10px] font-black uppercase tracking-widest mt-4">Cargando...</p>
                        </div>
                    ) : (
                        <AnimatePresence mode="wait">
                            <motion.div
                                key={activeTab}
                                initial={{ opacity: 0, x: 10 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -10 }}
                                transition={{ duration: 0.2 }}
                            >
                                {activeTab === 'info' && (
                                    <div className="space-y-6">
                                        <div className="bg-[var(--card-bg)] p-6 rounded-3xl border border-[var(--card-border)] text-center">
                                            <p className="text-4xl mb-2">🏟️</p>
                                            <h3 className="font-black text-xl italic">{partido.cancha || 'Cancha por definir'}</h3>
                                            <p className="text-[var(--text-muted)] font-bold text-sm mt-1">
                                                {partido.hora.slice(0, 5)} HS • Fútbol {partido.tipo_partido}
                                            </p>
                                        </div>

                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="bg-blue-500/10 p-4 rounded-2xl border border-blue-500/20 text-center">
                                                <p className="text-2xl mb-1">🔵</p>
                                                <p className="text-blue-500 font-black text-xs uppercase">Equipo Azul</p>
                                                <p className="text-2xl font-black mt-1">
                                                    {jugadores.filter(j => j.equipo === 'azul').length}
                                                </p>
                                            </div>
                                            <div className="bg-red-500/10 p-4 rounded-2xl border border-red-500/20 text-center">
                                                <p className="text-2xl mb-1">🔴</p>
                                                <p className="text-red-500 font-black text-xs uppercase">Equipo Rojo</p>
                                                <p className="text-2xl font-black mt-1">
                                                    {jugadores.filter(j => j.equipo === 'rojo').length}
                                                </p>
                                            </div>
                                        </div>

                                        {(partido.estado === 'borrador' && (esAutor || user?.id === partido.creado_por)) ? (
                                            <div className="space-y-8 pt-4">
                                                <div className="flex flex-col gap-8">
                                                    <div className="flex-1">
                                                        <h4 className="font-black text-blue-500 mb-2 text-center text-xs uppercase tracking-widest">🔵 Lineup Azul</h4>
                                                        <CanchaSeleccion
                                                            tipoPartido={partido.tipo_partido}
                                                            equipo="azul"
                                                            jugadores={jugadores.filter(j => j.equipo === 'azul')}
                                                            onSelectPosicion={(orden) => {
                                                                setEquipoAgregando('azul')
                                                                setOrdenAgregando(orden)
                                                            }}
                                                            onEliminarJugador={handleEliminarJugador}
                                                            formacionActual={formacionAzul || FORMACIONES[partido.tipo_partido][0]}
                                                            setFormacionActual={setFormacionAzul}
                                                        />
                                                    </div>
                                                    <div className="flex-1">
                                                        <h4 className="font-black text-red-500 mb-2 text-center text-xs uppercase tracking-widest">🔴 Lineup Rojo</h4>
                                                        <CanchaSeleccion
                                                            tipoPartido={partido.tipo_partido}
                                                            equipo="rojo"
                                                            jugadores={jugadores.filter(j => j.equipo === 'rojo')}
                                                            onSelectPosicion={(orden) => {
                                                                setEquipoAgregando('rojo')
                                                                setOrdenAgregando(orden)
                                                            }}
                                                            onEliminarJugador={handleEliminarJugador}
                                                            formacionActual={formacionRojo || FORMACIONES[partido.tipo_partido][0]}
                                                            setFormacionActual={setFormacionRojo}
                                                        />
                                                    </div>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="bg-[var(--card-bg)] p-6 rounded-3xl border border-[var(--card-border)]">
                                                <h4 className="font-black text-xs uppercase tracking-widest mb-4 opacity-50">Equipos Confirmados</h4>
                                                <div className="grid grid-cols-2 gap-8">
                                                    <div className="space-y-2">
                                                        {jugadores.filter(j => j.equipo === 'azul').map(j => (
                                                            <p key={j.id} className="text-sm font-bold">👤 {j.nombre}</p>
                                                        ))}
                                                    </div>
                                                    <div className="space-y-2">
                                                        {jugadores.filter(j => j.equipo === 'rojo').map(j => (
                                                            <p key={j.id} className="text-sm font-bold">👤 {j.nombre}</p>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )}

                                {activeTab === 'stats' && (
                                    <MatchStatisticsPanel 
                                        partido={partido}
                                        jugadores={jugadores}
                                        grupoId={grupoId}
                                        onUpdate={() => { onUpdate(); loadData(); }}
                                    />
                                )}

                                {activeTab === 'votos' && (
                                    <div className="space-y-8">
                                        {/* Progreso de Votación */}
                                        <div className="bg-[var(--card-bg)] p-5 rounded-3xl border border-[var(--card-border)] shadow-sm">
                                            <div className="flex justify-between items-end mb-3">
                                                <div>
                                                    <p className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">Tu Progreso</p>
                                                    <p className="text-lg font-black italic">{votados} / {totalJugadores}</p>
                                                </div>
                                                <div className="text-right">
                                                    <p className="text-2xl font-black text-[#16a34a] leading-none">{progreso}%</p>
                                                </div>
                                            </div>
                                            <div className="h-2 bg-[var(--background)] rounded-full overflow-hidden border border-[var(--card-border)]">
                                                <motion.div 
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${progreso}%` }}
                                                    className="h-full bg-[#16a34a]"
                                                />
                                            </div>
                                        </div>

                                        {/* Lista de Jugadores para Votar */}
                                        <div className="space-y-6">
                                            <div className="flex items-center justify-between">
                                                <h3 className="font-black italic uppercase tracking-tighter text-sm">⭐ Puntuar Rendimiento (1-10)</h3>
                                                {votados < totalJugadores && (
                                                    <button 
                                                        onClick={() => setShowRapida(true)}
                                                        className="flex items-center gap-1.5 bg-[#d97706] text-white px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest hover:brightness-110 transition-all shadow-lg"
                                                    >
                                                        <Flash size={12} /> Votar Todos
                                                    </button>
                                                )}
                                            </div>

                                            <div className="grid grid-cols-1 gap-6">
                                                {/* Votos Equipo Azul */}
                                                <div className="space-y-3">
                                                    <h4 className="font-black text-blue-500 text-[10px] uppercase tracking-[0.2em] mb-3 border-b border-blue-500/10 pb-2 flex items-center gap-2">
                                                        <div className="w-1.5 h-1.5 rounded-full bg-blue-500" /> EQUIPO AZUL
                                                    </h4>
                                                    <div className="grid grid-cols-1 gap-2">
                                                        {jugadores.filter(j => j.equipo === 'azul').map((j) => (
                                                            <div 
                                                                key={j.id} 
                                                                className="bg-blue-500/5 p-4 rounded-2xl border border-blue-500/10 flex items-center justify-between gap-4 group hover:bg-blue-500/10 transition-all"
                                                            >
                                                                <div className="flex items-center gap-3 min-w-0">
                                                                    <div className="min-w-0">
                                                                        <p className="font-bold text-sm truncate">{j.nombre}</p>
                                                                        {j.mi_voto ? (
                                                                            <div className="flex items-center gap-2">
                                                                                <div className="flex gap-0.5">
                                                                                    {Array.from({ length: 5 }).map((_, i) => (
                                                                                        <span key={i} className={`text-[8px] ${i < Math.round(j.mi_voto!.nota / 2) ? 'grayscale-0' : 'grayscale opacity-20'}`}>⭐</span>
                                                                                    ))}
                                                                                </div>
                                                                                <span className="text-[10px] font-bold text-blue-500">{j.mi_voto.nota}/10</span>
                                                                            </div>
                                                                        ) : (
                                                                            <p className="text-[10px] text-[var(--text-muted)] font-medium">Sin votar aún</p>
                                                                        )}
                                                                    </div>
                                                                </div>
                                                                <div className="flex gap-2">
                                                                    {j.mi_voto && (
                                                                        <button
                                                                            onClick={() => handleEliminarVoto(j.id)}
                                                                            className="shrink-0 p-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all bg-red-500/20 text-red-400 border border-red-500/20 hover:bg-red-500/30"
                                                                        >
                                                                            🗑️
                                                                        </button>
                                                                    )}
                                                                    <button 
                                                                        onClick={() => setVotandoA(j)}
                                                                        className={`shrink-0 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                                                            j.mi_voto 
                                                                            ? 'bg-blue-500/20 text-blue-400 border border-blue-500/20' 
                                                                            : 'bg-blue-600 text-white shadow-md hover:shadow-lg hover:-translate-y-0.5'
                                                                        }`}
                                                                    >
                                                                        {j.mi_voto ? 'Editar' : 'Votar'}
                                                                    </button>
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>

                                                {/* Votos Equipo Rojo */}
                                                <div className="space-y-3">
                                                    <h4 className="font-black text-red-500 text-[10px] uppercase tracking-[0.2em] mb-3 border-b border-red-500/10 pb-2 flex items-center gap-2">
                                                        <div className="w-1.5 h-1.5 rounded-full bg-red-500" /> EQUIPO ROJO
                                                    </h4>
                                                    <div className="grid grid-cols-1 gap-2">
                                                        {jugadores.filter(j => j.equipo === 'rojo').map((j) => (
                                                            <div 
                                                                key={j.id} 
                                                                className="bg-red-500/5 p-4 rounded-2xl border border-red-500/10 flex items-center justify-between gap-4 group hover:bg-red-500/10 transition-all"
                                                            >
                                                                <div className="flex items-center gap-3 min-w-0">
                                                                    <div className="min-w-0">
                                                                        <p className="font-bold text-sm truncate">{j.nombre}</p>
                                                                        {j.mi_voto ? (
                                                                            <div className="flex items-center gap-2">
                                                                                <div className="flex gap-0.5">
                                                                                    {Array.from({ length: 5 }).map((_, i) => (
                                                                                        <span key={i} className={`text-[8px] ${i < Math.round(j.mi_voto!.nota / 2) ? 'grayscale-0' : 'grayscale opacity-20'}`}>⭐</span>
                                                                                    ))}
                                                                                </div>
                                                                                <span className="text-[10px] font-bold text-red-500">{j.mi_voto.nota}/10</span>
                                                                            </div>
                                                                        ) : (
                                                                            <p className="text-[10px] text-[var(--text-muted)] font-medium">Sin votar aún</p>
                                                                        )}
                                                                    </div>
                                                                </div>
                                                                <div className="flex gap-2">
                                                                    {j.mi_voto && (
                                                                        <button
                                                                            onClick={() => handleEliminarVoto(j.id)}
                                                                            className="shrink-0 p-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all bg-red-500/20 text-red-400 border border-red-500/20 hover:bg-red-500/30"
                                                                        >
                                                                            🗑️
                                                                        </button>
                                                                    )}
                                                                    <button 
                                                                        onClick={() => setVotandoA(j)}
                                                                        className={`shrink-0 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                                                            j.mi_voto 
                                                                            ? 'bg-red-500/20 text-red-400 border border-red-500/20' 
                                                                            : 'bg-red-600 text-white shadow-md hover:shadow-lg hover:-translate-y-0.5'
                                                                        }`}
                                                                    >
                                                                        {j.mi_voto ? 'Editar' : 'Votar'}
                                                                    </button>
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        </div>

                                        <div className="border-t border-[var(--card-border)] pt-8">
                                            <h3 className="font-black italic uppercase tracking-tighter text-sm mb-2">🏆 Premios Especiales</h3>
                                            <p className="text-[10px] text-[var(--text-muted)] font-medium mb-6">
                                                Elegí a los destacados del partido en cada categoría.
                                            </p>
                                            <FacetVotingCards 
                                                partidoId={partido.id} 
                                                jugadores={jugadores}
                                                votosExistentes={facetVotes}
                                                onVote={async (pid: string, facet: FacetType) => {
                                                    try {
                                                        await votarFaceta(partido.id, pid, facet)
                                                        showToast('Voto guardado 🏆', 'success')
                                                        loadData()
                                                    } catch {
                                                        showToast('Error al votar', 'error')
                                                    }
                                                }}
                                                onDeleteVote={async (facet: FacetType) => {
                                                    try {
                                                        await eliminarVotoFaceta(partido.id, facet)
                                                        showToast('Voto de faceta eliminado 🗑️', 'success')
                                                        loadData()
                                                    } catch {
                                                        showToast('Error al eliminar voto de faceta', 'error')
                                                    }
                                                }}
                                            />
                                        </div>
                                    </div>
                                )}

                                {activeTab === 'resultados' && (
                                    <div className="space-y-6">
                                         <div className="bg-gradient-to-br from-[#16a34a] to-emerald-600 p-8 rounded-3xl text-white text-center shadow-xl">
                                            <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-4 opacity-80">Marcador Final</p>
                                             {/* Marcador Final Autocalculado con Casting Forzado */}
                                             <div className="flex items-center justify-center gap-8">
                                                 <div className="text-center">
                                                     <p className="text-4xl font-black tabular-nums">
                                                         {jugadores.filter(j => j.equipo === 'azul').reduce((acc, j) => acc + Number(j.goles || 0), 0)}
                                                     </p>
                                                     <p className="text-[9px] font-bold uppercase opacity-70 mt-1">AZUL</p>
                                                 </div>
                                                 <div className="text-2xl font-light opacity-50">-</div>
                                                 <div className="text-center">
                                                     <p className="text-4xl font-black tabular-nums">
                                                         {jugadores.filter(j => j.equipo === 'rojo').reduce((acc, j) => acc + Number(j.goles || 0), 0)}
                                                     </p>
                                                     <p className="text-[9px] font-bold uppercase opacity-70 mt-1">ROJO</p>
                                                 </div>
                                             </div>
                                         </div>
                                          {/* Estadísticas Reales (Auto-calculadas) */}
                                          <h3 className="font-black italic uppercase tracking-tighter text-sm pt-4">📈 Estadísticas del Partido</h3>
                                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                              {[
                                                  { 
                                                      label: 'Máximo Goleador', 
                                                      emoji: '🔥', 
                                                      players: jugadores.filter(j => (j.goles || 0) > 0).sort((a, b) => (b.goles || 0) - (a.goles || 0)).slice(0, 1),
                                                      statName: 'goles',
                                                      statEmoji: '⚽'
                                                  },
                                                  { 
                                                      label: 'Máximo Asistidor', 
                                                      emoji: '🎯', 
                                                      players: jugadores.filter(j => (j.asistencias || 0) > 0).sort((a, b) => (b.asistencias || 0) - (a.asistencias || 0)).slice(0, 1),
                                                      statName: 'asistencias',
                                                      statEmoji: '👟'
                                                  }
                                              ].map((stat, i) => (
                                                  stat.players.length > 0 ? (
                                                      <div key={i} className="bg-gradient-to-br from-[var(--card-bg)] to-[var(--hover-bg)] p-5 rounded-3xl border border-[var(--card-border)] flex items-center gap-4 relative overflow-hidden group">
                                                          <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                                                              <span className="text-6xl">{stat.emoji}</span>
                                                          </div>
                                                          <span className="text-3xl relative z-10">{stat.emoji}</span>
                                                          <div className="min-w-0 relative z-10">
                                                              <p className="text-[9px] font-black text-blue-500 uppercase tracking-widest">{stat.label}</p>
                                                              <p className="font-bold text-sm truncate">{stat.players[0].nombre}</p>
                                                              <p className="text-[10px] text-[var(--text-muted)] font-black uppercase tracking-tighter">
                                                                  {stat.statName === 'goles' ? stat.players[0].goles : stat.players[0].asistencias} {stat.statEmoji}
                                                              </p>
                                                          </div>
                                                      </div>
                                                  ) : null
                                              ))}
                                              {jugadores.every(j => !j.goles && !j.asistencias) && (
                                                  <div className="col-span-full py-8 text-center text-[10px] text-[var(--text-muted)] font-bold italic opacity-50 bg-[var(--card-bg)] rounded-3xl border border-dashed border-[var(--card-border)]">
                                                      No se cargaron goles ni asistencias aún
                                                  </div>
                                              )}
                                          </div>

                                          <h3 className="font-black italic uppercase tracking-tighter text-sm pt-4">🏅 Premios (Votación)</h3>
                                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                             {[
                                                 { id: 'goleador', label: 'El Goleador', emoji: '⚽' },
                                                 { id: 'comilon', label: 'El Comilón', emoji: '🍔' },
                                                 { id: 'patadas', label: 'Pegapatadas', emoji: '🦵' },
                                                 { id: 'arquero', label: 'Buen Arquero', emoji: '🧤' },
                                             ].map(facet => {
                                                 // Count votes for this facet
                                                 const counts = facetVotes
                                                     .filter(v => v.facet === facet.id)
                                                     .reduce((acc, v) => {
                                                         acc[v.player_id] = (acc[v.player_id] || 0) + 1
                                                         return acc
                                                     }, {} as Record<string, number>)

                                                 const entries = Object.entries(counts)
                                                 if (entries.length === 0) return null

                                                 const [winnerId, votes] = entries.sort((a,b) => b[1] - a[1])[0]
                                                 const winner = jugadores.find(j => j.id === winnerId)
                                                 const totalVotes = facetVotes.filter(v => v.facet === facet.id).length

                                                 return (
                                                     <div key={facet.id} className="bg-[var(--card-bg)] p-5 rounded-3xl border border-[var(--card-border)] flex items-center gap-4 hover:border-[#16a34a]/30 transition-all">
                                                         <span className="text-3xl">{facet.emoji}</span>
                                                         <div className="min-w-0">
                                                             <p className="text-[9px] font-black text-[#16a34a] uppercase tracking-widest">{facet.label}</p>
                                                             <p className="font-bold text-sm truncate">{winner?.nombre || 'Desconocido'}</p>
                                                             <p className="text-[10px] text-[var(--text-muted)] font-medium">
                                                                 {votes} votos ({Math.round((votes/totalVotes)*100)}%)
                                                             </p>
                                                         </div>
                                                     </div>
                                                 )
                                             })}
                                             {facetVotes.length === 0 && (
                                                 <div className="col-span-full py-10 text-center bg-[var(--card-bg)] rounded-3xl border border-dashed border-[var(--card-border)] opacity-50">
                                                     <p className="text-xs font-bold italic">Aún no hay votos para los premios</p>
                                                 </div>
                                             )}
                                          </div>
                                    </div>
                                )}
                            </motion.div>
                        </AnimatePresence>
                    )}
                </div>
            </div>

            {/* Individual 1-10 Vote Modal */}
            <AnimatePresence>
                {votandoA && (
                    <VotarModal
                        jugador={votandoA}
                        onVotar={handleVotar}
                        onClose={() => setVotandoA(null)}
                    />
                )}
            </AnimatePresence>

            {/* Quick 1-10 Vote Modal */}
            <AnimatePresence>
                {showRapida && (
                    <VotacionRapida
                        jugadores={jugadores}
                        onVotarTodos={handleVotarTodos}
                        onClose={() => setShowRapida(false)}
                    />
                )}
            </AnimatePresence>

            {/* Modal agregar jugador (Lineup) */}
            <AnimatePresence>
                {equipoAgregando && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4"
                        onClick={() => setEquipoAgregando(null)}
                    >
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            className="bg-[var(--card-bg)] rounded-3xl p-6 w-full max-w-sm border border-[var(--card-border)] shadow-2xl"
                            onClick={e => e.stopPropagation()}
                        >
                            <h4 className="text-xl font-black mb-1 italic">➕ Agregar Jugador</h4>
                            <p className="text-xs text-[var(--text-muted)] mb-6 uppercase tracking-widest font-bold">
                                Equipo {equipoAgregando === 'azul' ? '🔵 Azul' : '🔴 Rojo'}
                            </p>

                            <div className="space-y-4">
                                <div>
                                    <label className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] mb-2 block">Seleccionar Miembro</label>
                                    <div className="max-h-40 overflow-y-auto border border-[var(--card-border)] rounded-2xl bg-[var(--background)] p-2 space-y-1">
                                        {miembros.map(m => (
                                            <button
                                                key={m.user_id}
                                                onClick={() => {
                                                    setNuevoNombre(m.profile?.username || 'Usuario');
                                                    setSelectedUserId(m.user_id);
                                                }}
                                                className={`w-full text-left p-3 rounded-xl text-xs flex items-center gap-3 transition-all ${
                                                    selectedUserId === m.user_id 
                                                    ? 'bg-[#16a34a] text-white font-bold' 
                                                    : 'hover:bg-[var(--hover-bg)]'
                                                }`}
                                            >
                                                <div className="w-6 h-6 rounded-full bg-white/20 flex items-center justify-center text-[10px]">
                                                    {m.profile?.username?.[0].toUpperCase()}
                                                </div>
                                                {m.profile?.username}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <UserPlus size={16} className="text-[var(--text-muted)]" />
                                    </div>
                                    <input
                                        type="text"
                                        value={nuevoNombre}
                                        onChange={e => {
                                            setNuevoNombre(e.target.value);
                                            setSelectedUserId(null);
                                        }}
                                        onKeyDown={e => e.key === 'Enter' && handleAgregarJugador()}
                                        placeholder="O nombre de invitado..."
                                        className="w-full bg-[var(--input-bg)] border border-[var(--card-border)] rounded-2xl p-4 pl-10 text-sm focus:outline-none focus:ring-2 focus:ring-[#16a34a]/50 transition-all"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3 mt-8">
                                <button
                                    onClick={() => { setEquipoAgregando(null); setNuevoNombre(''); setSelectedUserId(null); setOrdenAgregando(null) }}
                                    className="flex-1 py-4 rounded-2xl text-[var(--text-muted)] font-black uppercase tracking-widest text-xs hover:bg-[var(--hover-bg)] transition-all"
                                >Cancelar</button>
                                <button
                                    onClick={handleAgregarJugador}
                                    disabled={!nuevoNombre.trim() || guardando}
                                    className="flex-1 py-4 rounded-2xl font-black text-white bg-[#16a34a] disabled:opacity-40 uppercase tracking-widest text-xs shadow-lg shadow-[#16a34a]/20 transition-all"
                                >{guardando ? '⏳' : 'Agregar'}</button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.div>
    )
}

'use client'

import { useState } from 'react'
import { motion } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useToast } from '@/contexts/ToastContext'
import type { JugadorPartidoAmigo, PartidoAmigo } from '@/types'

interface MatchStatisticsPanelProps {
    partido: PartidoAmigo
    jugadores: JugadorPartidoAmigo[]
    grupoId: string
    onUpdate: () => void
}

export function MatchStatisticsPanel({ partido, jugadores, grupoId, onUpdate }: MatchStatisticsPanelProps) {
    const { cerrarPartidoMundial, reabrirEstadisticas } = usePartidosAmigos(grupoId)
    const { showToast } = useToast()

    // Internal state for unsaved stats
    const [goles, setGoles] = useState<Record<string, number>>(
        Object.fromEntries(jugadores.map(j => [j.id, j.goles || 0]))
    )
    const [asistencias, setAsistencias] = useState<Record<string, number>>(
        Object.fromEntries(jugadores.map(j => [j.id, j.asistencias || 0]))
    )
    const [procesando, setProcesando] = useState(false)

    const handleUpdateStat = (id: string, type: 'goles' | 'asistencias', delta: number) => {
        if (partido.stats_completed) return

        if (type === 'goles') {
            setGoles(prev => ({ ...prev, [id]: Math.max(0, (prev[id] || 0) + delta) }))
        } else {
            setAsistencias(prev => ({ ...prev, [id]: Math.max(0, (prev[id] || 0) + delta) }))
        }
    }

    const handleSaveStats = async () => {
        if (procesando) return
        setProcesando(true)
        try {
            // Recalculate everything based on CURRENT state to be 100% sure
            const azulGoles = jugadores
                .filter(j => j.equipo === 'azul')
                .reduce((acc, j) => acc + (goles[j.id] || 0), 0)

            const rojoGoles = jugadores
                .filter(j => j.equipo === 'rojo')
                .reduce((acc, j) => acc + (goles[j.id] || 0), 0)

            const statsPayload = jugadores.map(j => ({
                id: j.id,
                goles: goles[j.id] || 0,
                asistencias: asistencias[j.id] || 0
            }))

            console.log('Guardando estadísticas finales:', { azulGoles, rojoGoles, statsPayload })
            await cerrarPartidoMundial(partido.id, azulGoles, rojoGoles, statsPayload)

            showToast('Estadísticas guardadas 🏆', 'success')
            // Don't close immediately to let the user see the success
            setTimeout(() => {
                onUpdate()
            }, 500)
        } catch (err: any) {
            console.error('Error al guardar stats:', err)
            showToast('Error al guardar: ' + (err.message || 'Cerrá y reintentá'), 'error')
        } finally {
            setProcesando(false)
        }
    }

    const Counter = ({ value, onDelta, emoji, color }: { value: number, onDelta: (d: number) => void, emoji: string, color: string }) => (
        <div className="flex flex-col items-center gap-1">
            <span className="text-[10px] opacity-50">{emoji}</span>
            <div className="flex items-center gap-2 bg-[var(--background)] px-1 py-1 rounded-xl border border-[var(--card-border)]">
                <button 
                    onClick={() => onDelta(-1)}
                    disabled={partido.stats_completed || value === 0}
                    className="w-7 h-7 flex items-center justify-center text-[var(--text-muted)] hover:bg-[var(--hover-bg)] rounded-lg disabled:opacity-20"
                >-</button>
                <span className="w-4 text-center font-black text-sm tabular-nums" style={{ color: value > 0 ? color : 'inherit' }}>
                    {value}
                </span>
                <button 
                    onClick={() => onDelta(1)}
                    disabled={partido.stats_completed}
                    className="w-7 h-7 flex items-center justify-center text-[#16a34a] hover:bg-[#16a34a]/10 rounded-lg disabled:opacity-20"
                >+</button>
            </div>
            {value > 0 && !partido.stats_completed && (
                <button 
                    onClick={() => onDelta(-value)}
                    className="mt-1 text-[8px] font-black text-red-500/50 hover:text-red-500 uppercase tracking-widest transition-colors"
                >
                    Reset
                </button>
            )}
        </div>
    )

    return (
        <div className="space-y-8 pb-32">
            <div className="grid grid-cols-1 gap-8">
                {/* Equipo Azul */}
                <div className="bg-blue-500/5 rounded-[2.5rem] p-1 border border-blue-500/10 backdrop-blur-sm">
                    <div className="bg-blue-600/10 px-6 py-4 rounded-t-[2.2rem] flex items-center justify-between border-b border-blue-500/10">
                        <div className="flex items-center gap-3">
                            <div className="w-3 h-3 rounded-full bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]" />
                            <h4 className="font-black text-blue-500 text-xs uppercase tracking-[0.2em]">EQUIPO AZUL</h4>
                        </div>
                        <span className="text-xl font-black text-blue-500 italic">
                            {jugadores.filter(j => j.equipo === 'azul').reduce((acc, j) => acc + (goles[j.id] || 0), 0)}
                        </span>
                    </div>
                    <div className="p-2 space-y-1">
                        {jugadores.filter(j => j.equipo === 'azul').map(j => (
                            <div key={j.id} className="flex items-center justify-between hover:bg-blue-500/5 p-4 rounded-2xl transition-all group">
                                <span className="font-bold text-sm truncate max-w-[120px] group-hover:translate-x-1 transition-transform">{j.nombre}</span>
                                <div className="flex gap-4">
                                    <Counter value={goles[j.id] || 0} onDelta={(d) => handleUpdateStat(j.id, 'goles', d)} emoji="⚽" color="#3b82f6" />
                                    <Counter value={asistencias[j.id] || 0} onDelta={(d) => handleUpdateStat(j.id, 'asistencias', d)} emoji="👟" color="#6de0f5" />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Equipo Rojo */}
                <div className="bg-red-500/5 rounded-[2.5rem] p-1 border border-red-500/10 backdrop-blur-sm">
                    <div className="bg-red-600/10 px-6 py-4 rounded-t-[2.2rem] flex items-center justify-between border-b border-red-500/10">
                        <div className="flex items-center gap-3">
                            <div className="w-3 h-3 rounded-full bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]" />
                            <h4 className="font-black text-red-500 text-xs uppercase tracking-[0.2em]">EQUIPO ROJO</h4>
                        </div>
                        <span className="text-xl font-black text-red-500 italic">
                            {jugadores.filter(j => j.equipo === 'rojo').reduce((acc, j) => acc + (goles[j.id] || 0), 0)}
                        </span>
                    </div>
                    <div className="p-2 space-y-1">
                        {jugadores.filter(j => j.equipo === 'rojo').map(j => (
                            <div key={j.id} className="flex items-center justify-between hover:bg-red-500/5 p-4 rounded-2xl transition-all group">
                                <span className="font-bold text-sm truncate max-w-[120px] group-hover:translate-x-1 transition-transform">{j.nombre}</span>
                                <div className="flex gap-4">
                                    <Counter value={goles[j.id] || 0} onDelta={(d) => handleUpdateStat(j.id, 'goles', d)} emoji="⚽" color="#ef4444" />
                                    <Counter value={asistencias[j.id] || 0} onDelta={(d) => handleUpdateStat(j.id, 'asistencias', d)} emoji="👟" color="#ff8a8a" />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            <div className="flex gap-4">
                {!partido.stats_completed && (
                    <button
                        onClick={() => {
                            setGoles(Object.fromEntries(jugadores.map(j => [j.id, 0])))
                            setAsistencias(Object.fromEntries(jugadores.map(j => [j.id, 0])))
                            showToast('Estadísticas reseteadas 🧹', 'success')
                        }}
                        className="flex-1 py-4 bg-gray-500/10 text-gray-500 rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-gray-500/20 transition-all border border-gray-500/10"
                    >
                        Limpiar Todo 🧹
                    </button>
                )}

                {partido.stats_completed && (
                    <button
                        onClick={async () => {
                            if (procesando) return
                            setProcesando(true)
                            try {
                                await reabrirEstadisticas(partido.id)
                                showToast('Estadísticas reabiertas 🔓', 'success')
                                onUpdate()
                            } catch (err) {
                                showToast('Error al reabrir', 'error')
                            } finally {
                                setProcesando(false)
                            }
                        }}
                        className="flex-1 py-4 bg-orange-500/10 text-orange-500 rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-orange-500/20 transition-all border border-orange-500/10"
                    >
                        Reabrir para Editar 🔓
                    </button>
                )}
            </div>

            {!partido.stats_completed && (
                <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black via-black/95 to-transparent z-50">
                    <div className="max-w-md mx-auto">
                        <motion.div 
                            initial={{ y: 20, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-[2rem] p-5 shadow-2xl backdrop-blur-xl"
                        >
                            <div className="flex items-center justify-between mb-4 px-2">
                                <div className="text-center">
                                    <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-1">Azul</p>
                                    <p className="text-2xl font-black">{jugadores.filter(j => j.equipo === 'azul').reduce((acc, j) => acc + (goles[j.id] || 0), 0)}</p>
                                </div>
                                <div className="h-8 w-px bg-[var(--card-border)]" />
                                <div className="text-center flex flex-col items-center">
                                    <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-30">VS</span>
                                    <div className="w-1.5 h-1.5 rounded-full bg-[#16a34a] mt-1 shadow-[0_0_8px_#16a34a]" />
                                </div>
                                <div className="h-8 w-px bg-[var(--card-border)]" />
                                <div className="text-center">
                                    <p className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-1">Rojo</p>
                                    <p className="text-2xl font-black">{jugadores.filter(j => j.equipo === 'rojo').reduce((acc, j) => acc + (goles[j.id] || 0), 0)}</p>
                                </div>
                            </div>

                            <button
                                onClick={handleSaveStats}
                                disabled={procesando}
                                className="w-full relative group overflow-hidden bg-[#16a34a] text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs transition-all hover:shadow-[0_0_30px_rgba(22,163,74,0.4)] disabled:opacity-50"
                            >
                                <span className="relative z-10 flex items-center justify-center gap-2">
                                    {procesando ? '⏳ Procesando...' : '🔥 Confirmar y Cerrar'}
                                </span>
                                <motion.div 
                                    className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full"
                                    animate={{ translateX: ['100%', '-100%'] }}
                                    transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
                                />
                            </button>
                            <p className="text-center text-[8px] text-[var(--text-muted)] mt-3 font-black uppercase tracking-[0.2em]">
                                Finalizará el partido y guardará estadísticas
                            </p>
                        </motion.div>
                    </div>
                </div>
            )}
        </div>
    )
}

// src/components/grupos/PartidosAmigosTab.tsx
'use client'

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'
import { CrearPartidoAmigo } from './CrearPartidoAmigo'
import { VotarJugadores } from './VotarJugadores'
import { MatchDetailTabs } from './MatchDetailTabs'
import type { PartidoAmigo, GrupoProde } from '@/types'

interface PartidosAmigosTabProps {
    grupo: GrupoProde
}

export function PartidosAmigosTab({ grupo }: PartidosAmigosTabProps) {
    const { partidos, loading, abrirVotacion, cerrarVotacion, cerrarPartidoMundial, eliminarPartido, refetch, fetchJugadoresConVotos } = usePartidosAmigos(grupo.id)
    const { user } = useAuth()
    const { showToast } = useToast()

    const [creando, setCreando] = useState(false)
    const [detalleVisible, setDetalleVisible] = useState<PartidoAmigo | null>(null)
    const [tabInicial, setTabInicial] = useState<'info' | 'stats' | 'votos' | 'resultados'>('info')
    const [procesandoCierre, setProcesandoCierre] = useState(false)

    const esAdmin = user?.id === grupo.admin_id

    const votacionAbierta = partidos.filter(p => p.estado === 'votacion_abierta')
    const borradores = partidos.filter(p => p.estado === 'borrador')
    const finalizados = partidos.filter(p => p.estado === 'finalizado')

    const formatFecha = (fecha: string, hora: string) => {
        const d = new Date(fecha + 'T00:00:00')
        return d.toLocaleDateString('es-AR', {
            weekday: 'short', day: 'numeric', month: 'short'
        }) + ` - ${hora.slice(0, 5)}`
    }

    const getTipoLabel = (tipo: string) => {
        const map: Record<string, string> = { '5': 'Fútbol 5', '7': 'Fútbol 7', '8': 'Fútbol 8', '9': 'Fútbol 9', '11': 'Fútbol 11' }
        return map[tipo] || tipo
    }


    const handleAbrirVotacion = async (partidoId: string) => {
        try {
            await abrirVotacion(partidoId)
            showToast('Votación abierta 🗳️', 'success')
        } catch {
            showToast('Error al abrir votación', 'error')
        }
    }

    const [confirmandoEliminar, setConfirmandoEliminar] = useState<string | null>(null)

    const handleEliminarPartido = async (partidoId: string) => {
        if (confirmandoEliminar !== partidoId) {
            setConfirmandoEliminar(partidoId)
            return
        }
        try {
            await eliminarPartido(partidoId)
            showToast('Partido eliminado', 'success')
        } catch {
            showToast('Error al eliminar', 'error')
        } finally {
            setConfirmandoEliminar(null)
        }
    }

    if (loading) {
        return <div className="text-center py-10 text-[var(--text-muted)]">⏳ Cargando partidos...</div>
    }

    return (
        <>
            <div className="space-y-6">
                {/* Header */}
                <div className="flex justify-between items-center">
                    <h2 className="text-xl font-black capitalize italic tracking-tighter">⚽ Partidos Amigos</h2>
                    {user && (
                        <button
                            onClick={() => setCreando(true)}
                            className="bg-[#16a34a] text-white px-4 py-2 font-black capitalize tracking-widest text-[10px] hover:brightness-110 transition-all italic"
                            style={{ borderRadius: 'var(--radius)' }}
                        >
                            + Crear Partido
                        </button>
                    )}
                </div>

                {/* Empty State */}
                {partidos.length === 0 && (
                    <div className="text-center py-16 bg-[var(--card-bg)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                        <div className="text-5xl mb-4">⚽</div>
                        <p className="font-black capitalize tracking-widest mb-1">No hay partidos</p>
                        <p className="text-[10px] text-[var(--text-muted)] font-black capitalize">
                            {'Cualquier miembro del grupo puede crear partidos'}
                        </p>
                    </div>
                )}

                {/* Votación Abierta */}
                {votacionAbierta.length > 0 && (
                    <Section title="🗳️ VOTACIÓN ABIERTA">
                        {votacionAbierta.map(p => (
                            <PartidoCard key={p.id} partido={p} variant="votacion">
                                <div className="flex items-center justify-between gap-2 text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-3">
                                    <span>👥 {p.votos_usuarios || 0} votaron</span>
                                    <span>{p.jugadores_count} jugadores</span>
                                </div>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => { setDetalleVisible(p); setTabInicial('votos'); }}
                                        className="flex-1 bg-[#16a34a] text-white py-3 font-black capitalize tracking-widest italic text-sm hover:brightness-110 transition-all"
                                        style={{ borderRadius: 'var(--radius)' }}
                                    >
                                        🗳️ Votar y Stats
                                    </button>
                                    {(esAdmin || user?.id === p.creado_por) && (
                                        <button
                                            onClick={() => { setDetalleVisible(p); setTabInicial('stats'); }}
                                            className="px-3 py-3 text-[10px] font-black capitalize tracking-widest border border-[var(--card-border)] text-[var(--text-muted)] hover:bg-[var(--hover-bg)]"
                                            style={{ borderRadius: 'var(--radius)' }}
                                        >
                                            🔒 Cerrar
                                        </button>
                                    )}
                                </div>
                            </PartidoCard>
                        ))}
                    </Section>
                )}

                {/* Borradores (admin o creador) */}
                {borradores.length > 0 && (
                    <Section title="📝 BORRADORES">
                        {borradores.map(p => {
                            const puedeEditar = esAdmin || user?.id === p.creado_por
                            if (!puedeEditar) return null

                            return (
                                <PartidoCard key={p.id} partido={p} variant="borrador">
                                    <div className="text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-3 italic">
                                        📝 En armado... — {p.jugadores_count || 0} jugadores
                                    </div>
                                    <div className="flex gap-2">
                                        <button
                                            onClick={() => handleAbrirVotacion(p.id)}
                                            className="flex-1 bg-[#16a34a] text-white py-2.5 font-black capitalize tracking-widest text-xs"
                                            style={{ borderRadius: 'var(--radius)' }}
                                        >
                                            🗳️ Abrir Votación
                                        </button>
                                        <button
                                            onClick={() => handleEliminarPartido(p.id)}
                                            className={`px-3 py-2.5 font-black text-xs capitalize tracking-widest border transition-all ${confirmandoEliminar === p.id
                                                ? 'bg-[#991b1b] text-white border-[#991b1b]'
                                                : 'text-[#991b1b] border-[#991b1b]/30 hover:bg-[#991b1b]/10'
                                                }`}
                                            style={{ borderRadius: 'var(--radius)' }}
                                        >
                                            {confirmandoEliminar === p.id ? '¿Seguro?' : '🗑️'}
                                        </button>
                                    </div>
                                </PartidoCard>
                            )
                        })}
                    </Section>
                )}

                {/* Finalizados */}
                {finalizados.length > 0 && (
                    <Section title="✅ FINALIZADOS">
                        {finalizados.map(p => (
                            <PartidoCard key={p.id} partido={p} variant="finalizado">
                                {p.resultado_azul !== null && p.resultado_rojo !== null && (
                                    <p className="text-sm font-black capitalize tracking-tighter mb-2 italic">
                                        🔵 Azul {p.resultado_azul} - {p.resultado_rojo} Rojo 🔴
                                    </p>
                                )}
                                <button
                                    onClick={() => { setDetalleVisible(p); setTabInicial('resultados'); }}
                                    className="w-full bg-[#2563eb] text-white py-2.5 font-black capitalize tracking-widest text-xs"
                                    style={{ borderRadius: 'var(--radius)' }}
                                >
                                    📊 Ver Resultados y Stats
                                </button>
                            </PartidoCard>
                        ))}
                    </Section>
                )}
            </div>

            {/* Modal de Detalle con Tabs */}
            <AnimatePresence>
                {detalleVisible && (
                    <MatchDetailTabs
                        partido={detalleVisible}
                        grupoId={grupo.id}
                        initialTab={tabInicial}
                        onClose={() => { setDetalleVisible(null); refetch() }}
                        onUpdate={refetch}
                    />
                )}
            </AnimatePresence>

            <AnimatePresence>
                {creando && (
                    <CrearPartidoAmigo
                        grupoId={grupo.id}
                        onClose={() => setCreando(false)}
                        onCreated={refetch}
                    />
                )}
            </AnimatePresence>
        </>
    )
}

// ── Section Header ──
function Section({ title, children }: { title: string; children: React.ReactNode }) {
    return (
        <div>
            <h3 className="text-xs font-black text-[var(--text-muted)] capitalize tracking-wider mb-3">{title}</h3>
            <div className="space-y-3">{children}</div>
        </div>
    )
}

// ── Match Card ──
function PartidoCard({ partido, variant, children }: {
    partido: PartidoAmigo
    variant: 'votacion' | 'borrador' | 'finalizado'
    children: React.ReactNode
}) {
    const borderColor = variant === 'votacion' ? '#16a34a' : variant === 'finalizado' ? '#2563eb' : 'var(--card-border)'

    const formatFecha = (fecha: string, hora: string) => {
        const d = new Date(fecha + 'T00:00:00')
        return d.toLocaleDateString('es-AR', {
            weekday: 'short', day: 'numeric', month: 'short'
        }) + ` - ${hora.slice(0, 5)}`
    }

    const getTipoLabel = (tipo: string) => {
        const map: Record<string, string> = { '5': 'Fútbol 5', '7': 'Fútbol 7', '8': 'Fútbol 8', '9': 'Fútbol 9', '11': 'Fútbol 11' }
        return map[tipo] || tipo
    }

    return (
        <motion.div
            initial={{ y: 10, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)]"
            style={{ borderLeftColor: borderColor, borderLeftWidth: 4, borderRadius: 'var(--radius)' }}
        >
            <div className="mb-3">
                <p className="text-[10px] font-black capitalize tracking-widest text-[var(--foreground)]">{formatFecha(partido.fecha, partido.hora)}</p>
                <p className="text-[9px] font-black capitalize tracking-widest text-[var(--text-muted)]">
                    ⚽ {getTipoLabel(partido.tipo_partido)}{partido.cancha ? ` - ${partido.cancha}` : ''}
                </p>
            </div>
            {children}
        </motion.div>
    )
}

// src/components/grupos/ResultadosPartidoAmigo.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useToast } from '@/contexts/ToastContext'
import { DetalleJugadorAmigo } from './DetalleJugadorAmigo'
import type { PartidoAmigo, JugadorPartidoAmigo } from '@/types'

interface ResultadosProps {
    partido: PartidoAmigo
    grupoId: string
    onClose: () => void
}

export function ResultadosPartidoAmigo({ partido, grupoId, onClose }: ResultadosProps) {
    const { fetchJugadoresConVotos } = usePartidosAmigos(grupoId)
    const { showToast } = useToast()
    const [jugadores, setJugadores] = useState<JugadorPartidoAmigo[]>([])
    const [loading, setLoading] = useState(true)
    const [jugadorDetalle, setJugadorDetalle] = useState<JugadorPartidoAmigo | null>(null)

    useEffect(() => {
        loadResultados()
    }, [partido.id])

    const loadResultados = async () => {
        try {
            const data = await fetchJugadoresConVotos(partido.id)
            setJugadores(data)
        } catch {
            showToast('Error cargando resultados', 'error')
        } finally {
            setLoading(false)
        }
    }

    const sorted = [...jugadores].sort((a, b) => (b.promedio || 0) - (a.promedio || 0))
    const mvp = sorted[0]
    const top3 = sorted.slice(0, 3)
    const azules = jugadores.filter(j => j.equipo === 'azul').sort((a, b) => (b.promedio || 0) - (a.promedio || 0))
    const rojos = jugadores.filter(j => j.equipo === 'rojo').sort((a, b) => (b.promedio || 0) - (a.promedio || 0))

    const promedioEquipo = (equipo: JugadorPartidoAmigo[]) => {
        const conVotos = equipo.filter(j => (j.promedio || 0) > 0)
        if (conVotos.length === 0) return 0
        return Math.round(conVotos.reduce((sum, j) => sum + (j.promedio || 0), 0) / conVotos.length * 10) / 10
    }

    const fechaDisplay = new Date(partido.fecha + 'T00:00:00').toLocaleDateString('es-AR', {
        weekday: 'short', day: 'numeric', month: 'short'
    })

    const resultado = partido.resultado_azul !== undefined && partido.resultado_rojo !== undefined
        ? `Azul ${partido.resultado_azul}-${partido.resultado_rojo} Rojo`
        : null

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="fixed inset-0 bg-[var(--background)] z-[60] overflow-y-auto"
        >
            {/* Header */}
            <div className="bg-gradient-to-b from-[#3b82f6] to-[#2563eb] text-white pt-10 pb-12 px-6 rounded-b-[3rem] shadow-2xl">
                <div className="max-w-lg mx-auto">
                    <button onClick={onClose} className="bg-white/20 p-2 rounded-full mb-6 backdrop-blur-md hover:bg-white/30 transition-all">← Volver</button>
                    <h1 className="text-3xl font-black italic tracking-tighter capitalize mb-2">📊 Estadísticas</h1>
                    <p className="text-white/80 text-sm font-bold capitalize tracking-widest bg-black/20 inline-block px-3 py-1 rounded-full backdrop-blur-sm">
                        {fechaDisplay} • {partido.cancha || 'Partido Amigo'}
                    </p>
                    {resultado && (
                        <div className="mt-8 flex items-center justify-center gap-6 text-4xl font-black italic">
                            <div className="flex flex-col items-center">
                                <span className="text-xs capitalize tracking-[0.3em] font-black text-white/60 mb-2">AZUL</span>
                                <span>{partido.resultado_azul}</span>
                            </div>
                            <div className="text-white/30 text-2xl">VS</div>
                            <div className="flex flex-col items-center">
                                <span className="text-xs capitalize tracking-[0.3em] font-black text-white/60 mb-2">ROJO</span>
                                <span>{partido.resultado_rojo}</span>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {loading ? (
                <div className="text-center py-20 font-black italic capitalize tracking-widest text-[var(--text-muted)] animate-pulse">Cargando resultados...</div>
            ) : (
                <div className="max-w-lg mx-auto px-4 -mt-6 pb-20 space-y-6">
                    {/* MVP */}
                    {mvp && mvp.promedio! > 0 && (
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            transition={{ delay: 0.2, type: 'spring' }}
                            className="bg-gradient-to-br from-amber-400 to-amber-600 rounded-[2.5rem] p-8 text-center shadow-2xl relative overflow-hidden group shadow-amber-500/30"
                        >
                            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-16 translate-x-16" />
                            <p className="text-[10px] text-white/80 capitalize font-black tracking-[0.4em] mb-4">MEMBER OF THE MATCH</p>
                            <div className="relative inline-block mb-4">
                                <div className="absolute inset-0 bg-white/20 blur-xl rounded-full" />
                                <div className="text-5xl relative">👑</div>
                            </div>
                            <h2 className="text-3xl font-black text-white italic tracking-tighter capitalize">{mvp.nombre}</h2>
                            <p className="text-4xl font-black text-white mt-2 drop-shadow-lg">⭐ {mvp.promedio}</p>
                            <p className="text-[10px] text-white/80 font-bold capitalize mt-4">{mvp.total_votos} VOTOS EN TOTAL</p>
                        </motion.div>
                    )}

                    {/* Team Results */}
                    <TeamResults
                        equipo="azul"
                        color="#3b82f6"
                        emoji="🔵"
                        jugadores={azules}
                        promedio={promedioEquipo(azules)}
                        onClickJugador={setJugadorDetalle}
                    />

                    <TeamResults
                        equipo="rojo"
                        color="#ef4444"
                        emoji="🔴"
                        jugadores={rojos}
                        promedio={promedioEquipo(rojos)}
                        onClickJugador={setJugadorDetalle}
                    />
                </div>
            )}

            {jugadorDetalle && (
                <DetalleJugadorAmigo
                    jugador={jugadorDetalle}
                    grupoId={grupoId}
                    onClose={() => setJugadorDetalle(null)}
                />
            )}
        </motion.div>
    )
}

function TeamResults({ equipo, color, emoji, jugadores, promedio, onClickJugador }: {
    equipo: string
    color: string
    emoji: string
    jugadores: JugadorPartidoAmigo[]
    promedio: number
    onClickJugador: (j: JugadorPartidoAmigo) => void
}) {
    return (
        <div className="bg-[var(--card-bg)] rounded-[2rem] border border-[var(--card-border)] overflow-hidden shadow-xl">
            <div className="p-5 border-b border-[var(--card-border)] bg-[var(--background)]/50" style={{ borderLeftColor: color, borderLeftWidth: 6 }}>
                <div className="flex justify-between items-end">
                    <div>
                        <h3 className="text-xs font-black capitalize tracking-[0.2em] mb-1" style={{ color }}>
                            {emoji} EQUIPO {equipo.toUpperCase()}
                        </h3>
                        <p className="text-2xl font-black italic tracking-tighter">ESTADÍSTICAS</p>
                    </div>
                    <div className="text-right">
                        <span className="text-[10px] text-[var(--text-muted)] font-black capitalize tracking-widest">PROM EQUIPO</span>
                        <p className="text-xl font-black" style={{ color }}>{promedio}</p>
                    </div>
                </div>
            </div>
            <div>
                {jugadores.map((j, i) => (
                    <button
                        key={j.id}
                        onClick={() => onClickJugador(j)}
                        className={`w-full flex items-center gap-4 p-5 border-b border-[var(--card-border)] last:border-0 hover:bg-[var(--hover-bg)] transition-all text-left ${i === 0 ? 'bg-amber-400/5' : ''}`}
                    >
                        <span className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-black ${i === 0 ? 'bg-amber-400 text-amber-900 shadow-md' : 'bg-[var(--background)] text-[var(--text-muted)]'}`}>
                            {i + 1}
                        </span>
                        <div className="flex-1 min-w-0">
                            <span className="font-bold text-sm block">
                                {i === 0 && '👑 '}{j.nombre}
                            </span>
                            <div className="w-full h-1.5 bg-[var(--background)] rounded-full mt-2 overflow-hidden shadow-inner">
                                <motion.div
                                    initial={{ width: 0 }}
                                    animate={{ width: `${((j.promedio || 0) / 10) * 100}%` }}
                                    transition={{ duration: 0.8 }}
                                    className="h-full rounded-full"
                                    style={{ backgroundColor: color }}
                                />
                            </div>
                        </div>
                        <div className="text-right">
                            <span className="text-sm font-black italic" style={{ color }}>{j.promedio || '-'}</span>
                            <p className="text-[8px] text-[var(--text-muted)] font-bold capitalize">{j.total_votos} V</p>
                        </div>
                    </button>
                ))}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'

interface TablaEstadisticasProps {
    grupoId: string
    miembros: any[]
}

interface EstadisticaJugador {
    userId: string
    nombre: string
    foto?: string
    pj: number
    goles: number
    asistencias: number
    promedio: number
    mvps: number
}

export function TablaEstadisticas({ grupoId, miembros }: TablaEstadisticasProps) {
    const [stats, setStats] = useState<EstadisticaJugador[]>([])
    const [loading, setLoading] = useState(true)
    const [orden, setOrden] = useState<'goles' | 'asistencias' | 'promedio' | 'pj'>('goles')

    useEffect(() => {
        fetchStats()
    }, [grupoId])

    const fetchStats = async () => {
        setLoading(true)
        try {
            const { data: partidos } = await supabase
                .from('partidos_amigos')
                .select('id')
                .eq('grupo_id', grupoId)
                .eq('estado', 'finalizado')

            if (!partidos || partidos.length === 0) {
                setStats([])
                setLoading(false)
                return
            }

            const partidoIds = partidos.map(p => p.id)

            const { data: jugadoresHistorial } = await supabase
                .from('jugadores_partido_amigo')
                .select('user_id, goles, asistencias, nombre')
                .in('partido_amigo_id', partidoIds)
                .not('user_id', 'is', null)

            const { data: votos } = await supabase
                .from('votos_partido_amigo')
                .select('jugador_id, nota, jugadores_partido_amigo!inner(user_id)')
                .in('partido_amigo_id', partidoIds)

            const statsMap: Record<string, EstadisticaJugador> = {}

            miembros.forEach(m => {
                if (m.user_id) {
                    statsMap[m.user_id] = {
                        userId: m.user_id,
                        nombre: m.profile?.username || 'Usuario',
                        foto: m.profile?.avatar_url,
                        pj: 0,
                        goles: 0,
                        asistencias: 0,
                        promedio: 0,
                        mvps: 0
                    }
                }
            })

            jugadoresHistorial?.forEach((j: any) => {
                const uid = j.user_id
                if (!statsMap[uid]) return
                statsMap[uid].pj += 1
                statsMap[uid].goles += (j.goles || 0)
                statsMap[uid].asistencias += (j.asistencias || 0)
            })

            const notasSum: Record<string, number> = {}
            const notasCount: Record<string, number> = {}

            votos?.forEach((v: any) => {
                const uid = v.jugadores_partido_amigo?.user_id
                if (!uid || !statsMap[uid]) return
                notasSum[uid] = (notasSum[uid] || 0) + v.nota
                notasCount[uid] = (notasCount[uid] || 0) + 1
            })

            Object.values(statsMap).forEach(s => {
                if (notasCount[s.userId]) {
                    s.promedio = Number((notasSum[s.userId] / notasCount[s.userId]).toFixed(1))
                }
            })

            setStats(Object.values(statsMap))
        } catch (error) {
            console.error('Error stats', error)
        } finally {
            setLoading(false)
        }
    }

    const sortedStats = [...stats].sort((a, b) => b[orden] - a[orden])

    if (loading) return <div className="text-center py-20 animate-pulse text-[var(--text-muted)] font-bold italic capitalize tracking-widest">Calculando estadísticas...</div>

    if (stats.length === 0) return (
        <div className="text-center py-20 text-[var(--text-muted)] bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)]">
            <p className="text-4xl mb-4">📉</p>
            <p className="font-bold italic">Aún no hay estadísticas. ¡Jueguen partidos para generar datos!</p>
        </div>
    )

    return (
        <div className="space-y-6">
            <div className="flex gap-2 justify-center pb-2 overflow-x-auto no-scrollbar px-2">
                <FilterButton active={orden === 'goles'} onClick={() => setOrden('goles')} label="⚽ Goles" />
                <FilterButton active={orden === 'asistencias'} onClick={() => setOrden('asistencias')} label="👟 Asistencias" />
                <FilterButton active={orden === 'promedio'} onClick={() => setOrden('promedio')} label="⭐ Promedio" />
                <FilterButton active={orden === 'pj'} onClick={() => setOrden('pj')} label="📅 PJ" />
            </div>

            <div className="bg-[var(--card-bg)] rounded-3xl border border-[var(--card-border)] overflow-hidden shadow-xl">
                <table className="w-full text-sm">
                    <thead className="bg-[#10b981]/10 text-[#10b981]">
                        <tr>
                            <th className="p-4 text-left font-black capitalize italic text-xs">Jugador</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">PJ</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">⚽</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">👟</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">⭐</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-[var(--card-border)]">
                        {sortedStats.map((s, i) => (
                            <tr key={s.userId} className="hover:bg-[var(--hover-bg)] transition-colors">
                                <td className="p-4 flex items-center gap-3">
                                    <span className="text-[10px] font-black w-4 text-[var(--text-muted)]">#{i + 1}</span>
                                    <div className="w-10 h-10 rounded-full bg-[var(--background)] overflow-hidden border-2 border-[var(--card-border)] flex items-center justify-center shrink-0 shadow-sm">
                                        {s.foto ? <img src={s.foto} alt={s.nombre} className="w-full h-full object-cover" /> : '👤'}
                                    </div>
                                    <span className="font-bold truncate max-w-[120px]">{s.nombre}</span>
                                </td>
                                <td className={`p-4 text-center text-xs ${orden === 'pj' ? 'font-black text-[var(--foreground)]' : 'font-medium text-[var(--text-muted)]'}`}>{s.pj}</td>
                                <td className={`p-4 text-center text-xs ${orden === 'goles' ? 'font-black text-[#10b981]' : 'font-medium text-[var(--text-muted)]'}`}>{s.goles}</td>
                                <td className={`p-4 text-center text-xs ${orden === 'asistencias' ? 'font-black text-blue-400' : 'font-medium text-[var(--text-muted)]'}`}>{s.asistencias}</td>
                                <td className={`p-4 text-center text-xs ${orden === 'promedio' ? 'font-black text-yellow-400' : 'font-medium text-[var(--text-muted)]'}`}>{s.promedio || '-'}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    )
}

function FilterButton({ active, onClick, label }: { active: boolean, onClick: () => void, label: string }) {
    return (
        <button
            onClick={onClick}
            className={`px-4 py-2 rounded-full text-xs font-black capitalize tracking-wider transition-all shadow-sm shrink-0
                ${active ? 'bg-[#10b981] text-white shadow-emerald-500/20' : 'bg-[var(--card-bg)] border border-[var(--card-border)] text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'}`}
        >
            {label}
        </button>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { useGrupos } from '@/hooks/useGrupos'

interface Props {
    onCancel: () => void
    onSuccess?: () => void
}

export function UnirseGrupoForm({ onCancel, onSuccess }: Props) {
    const router = useRouter()
    const { unirseAGrupo } = useGrupos()
    const [codigo, setCodigo] = useState('')
    const [procesando, setProcesando] = useState(false)

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!codigo.trim() || codigo.length < 6) return

        setProcesando(true)
        try {
            const grupo = await unirseAGrupo(codigo)
            setCodigo('')
            if (onSuccess) onSuccess()
            // Navegar directamente al grupo
            router.push(`/grupos/${grupo.id}`)
        } catch (error: any) {
            alert(error.message)
        } finally {
            setProcesando(false)
        }
    }

    return (
        <form onSubmit={handleSubmit} className="bg-[var(--card-bg)] p-6 rounded-2xl border border-[#ffd700] mb-8">
            <h3 className="font-bold mb-4 text-lg">Unirse a Grupo</h3>
            <div className="space-y-4">
                <div>
                    <label className="block text-sm text-[var(--text-muted)] mb-1">Código de Invitación</label>
                    <input
                        type="text"
                        placeholder="Ej: FULBO-123"
                        value={codigo}
                        onChange={(e) => setCodigo(e.target.value.toUpperCase())}
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-xl px-4 py-3 outline-none focus:border-[#ffd700] text-center font-mono text-xl tracking-widest capitalize transition-colors"
                        maxLength={8}
                        autoFocus
                    />
                    <p className="text-xs text-[var(--text-muted)] mt-2 text-center">
                        Pedile el código al administrador del grupo
                    </p>
                </div>

                <div className="flex gap-3 pt-2">
                    <button
                        type="submit"
                        disabled={procesando || codigo.length < 6}
                        className="flex-1 bg-[#ffd700] text-black py-3 rounded-xl font-bold hover:bg-[#e6c200] disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                    >
                        {procesando ? 'Verificando...' : 'Unirme'}
                    </button>
                    <button
                        type="button"
                        onClick={onCancel}
                        className="px-6 py-3 text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors font-medium"
                    >
                        Cancelar
                    </button>
                </div>
            </div>
        </form>
    )
}

// src/components/grupos/VotarJugadores.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useToast } from '@/contexts/ToastContext'
import { VotarModal } from './VotarModal'
import { VotacionRapida } from './VotacionRapida'
import type { PartidoAmigo, JugadorPartidoAmigo } from '@/types'

interface VotarJugadoresProps {
    partido: PartidoAmigo
    grupoId: string
    onClose: () => void
}

export function VotarJugadores({ partido, grupoId, onClose }: VotarJugadoresProps) {
    const { fetchJugadoresConVotos, votarJugador } = usePartidosAmigos(grupoId)
    const { showToast } = useToast()
    const [jugadores, setJugadores] = useState<JugadorPartidoAmigo[]>([])
    const [loading, setLoading] = useState(true)
    const [votandoA, setVotandoA] = useState<JugadorPartidoAmigo | null>(null)
    const [showRapida, setShowRapida] = useState(false)

    useEffect(() => {
        loadJugadores()
    }, [partido.id])

    const loadJugadores = async () => {
        try {
            const data = await fetchJugadoresConVotos(partido.id)
            setJugadores(data)
        } catch {
            showToast('Error cargando jugadores', 'error')
        } finally {
            setLoading(false)
        }
    }

    const handleVotar = async (nota: number, comentario?: string) => {
        if (!votandoA) return
        try {
            await votarJugador(partido.id, votandoA.id, nota, comentario)
            showToast(`Voto guardado para ${votandoA.nombre} ⭐`, 'success')
            await loadJugadores()
        } catch {
            showToast('Error al votar', 'error')
        }
    }

    const handleVotarTodos = async (votos: { jugadorId: string; nota: number }[]) => {
        try {
            for (const v of votos) {
                await votarJugador(partido.id, v.jugadorId, v.nota)
            }
            showToast(`${votos.length} votos guardados ⚡`, 'success')
            await loadJugadores()
        } catch {
            showToast('Error al guardar votos', 'error')
        }
    }

    const azules = jugadores.filter(j => j.equipo === 'azul')
    const rojos = jugadores.filter(j => j.equipo === 'rojo')
    const votados = jugadores.filter(j => j.mi_voto).length
    const total = jugadores.length
    const progreso = total > 0 ? Math.round((votados / total) * 100) : 0

    const fechaDisplay = new Date(partido.fecha + 'T00:00:00').toLocaleDateString('es-AR', {
        weekday: 'short', day: 'numeric', month: 'short'
    })

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-[var(--background)] z-[60] overflow-y-auto"
        >
            {/* Header */}
            <div className="bg-[#16a34a] text-white pt-10 pb-6 px-6 border-b border-black/10">
                <div className="max-w-lg mx-auto">
                    <button onClick={onClose} className="bg-black/20 p-2 mb-3 font-black capitalize tracking-widest text-[10px] hover:bg-black/30 transition-all" style={{ borderRadius: 'var(--radius)' }}>← Volver</button>
                    <h1 className="text-2xl font-black capitalize italic tracking-tighter">🗳️ Votar Jugadores</h1>
                    <p className="text-white/80 text-[10px] font-bold capitalize tracking-widest leading-none mt-1">{fechaDisplay} - {partido.cancha || 'Sin cancha'}</p>
                </div>
            </div>

            <div className="max-w-lg mx-auto px-4 -mt-3 pb-28 space-y-4">
                {/* Progress */}
                <div className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                    <div className="flex justify-between text-[10px] font-black capitalize tracking-widest mb-2">
                        <span>📊 Tu Progreso</span>
                        <span className="text-[#16a34a]">{votados}/{total} votados</span>
                    </div>
                    <div className="w-full h-3 bg-[var(--background)] border border-[var(--card-border)] overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                        <motion.div
                            initial={{ width: 0 }}
                            animate={{ width: `${progreso}%` }}
                            className="h-full bg-[#16a34a]"
                        />
                    </div>
                    <p className="text-right text-[10px] font-black tabular-nums text-[var(--text-muted)] mt-1">{progreso}%</p>
                </div>

                {loading ? (
                    <div className="text-center py-10 text-[var(--text-muted)]">⏳ Cargando jugadores...</div>
                ) : (
                    <>
                        {/* Equipo Azul */}
                        <TeamVoteSection
                            equipo="azul"
                            color="#3b82f6"
                            emoji="🔵"
                            jugadores={azules}
                            onVotar={setVotandoA}
                        />

                        {/* Equipo Rojo */}
                        <TeamVoteSection
                            equipo="rojo"
                            color="#ef4444"
                            emoji="🔴"
                            jugadores={rojos}
                            onVotar={setVotandoA}
                        />

                        {/* Quick vote CTA */}
                        {votados < total && (
                            <div className="bg-[var(--card-bg)] border border-[#d97706]/30 p-4 text-center" style={{ borderRadius: 'var(--radius)' }}>
                                <p className="text-[10px] font-black capitalize tracking-widest mb-3">⚠️ Te faltan <span className="text-[#d97706]">{total - votados}</span> jugadores</p>
                                <button
                                    onClick={() => setShowRapida(true)}
                                    className="w-full bg-[#d97706] text-white px-6 py-3 font-black capitalize tracking-widest italic text-sm hover:brightness-110 transition-all"
                                    style={{ borderRadius: 'var(--radius)' }}
                                >
                                    ⚡ Votar Todos
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>

            {/* Individual vote modal */}
            {votandoA && (
                <VotarModal
                    jugador={votandoA}
                    onVotar={handleVotar}
                    onClose={() => setVotandoA(null)}
                />
            )}

            {/* Quick vote modal */}
            {showRapida && (
                <VotacionRapida
                    jugadores={jugadores}
                    onVotarTodos={handleVotarTodos}
                    onClose={() => setShowRapida(false)}
                />
            )}
        </motion.div>
    )
}

function TeamVoteSection({ equipo, color, emoji, jugadores, onVotar }: {
    equipo: 'azul' | 'rojo'
    color: string
    emoji: string
    jugadores: JugadorPartidoAmigo[]
    onVotar: (j: JugadorPartidoAmigo) => void
}) {
    return (
        <div>
            <h3 className="font-black text-sm mb-2" style={{ color }}>
                {emoji} EQUIPO {equipo.toUpperCase()}
            </h3>
            <div className="space-y-2">
                {jugadores.map((j, i) => (
                    <motion.div
                        key={j.id}
                        initial={{ x: -20, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        transition={{ delay: i * 0.05 }}
                        className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)]"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="font-bold">👤 {j.nombre}</p>
                                {j.mi_voto ? (
                                    <div className="mt-1">
                                        <span className="text-xs">
                                            {Array.from({ length: 10 }, (_, i) => (
                                                <span key={i} className={i < j.mi_voto!.nota ? 'opacity-100' : 'opacity-20'}>⭐</span>
                                            ))}
                                            {' '}{j.mi_voto.nota}/10
                                        </span>
                                        {j.mi_voto.comentario && (
                                            <p className="text-xs text-[var(--text-muted)] mt-0.5">💬 &ldquo;{j.mi_voto.comentario}&rdquo;</p>
                                        )}
                                        <p className="text-[10px] text-[#16a34a] font-black capitalize tracking-widest mt-0.5">✅ Ya votaste</p>
                                    </div>
                                ) : (
                                    <p className="text-[10px] text-[var(--text-muted)] font-black capitalize tracking-widest mt-1">
                                        {'○'.repeat(10)} Sin votar
                                    </p>
                                )}
                            </div>
                            <button
                                onClick={() => onVotar(j)}
                                className={`px-4 py-2 text-xs font-black capitalize tracking-widest transition-all ${j.mi_voto
                                    ? 'bg-[var(--hover-bg)] text-[var(--text-muted)] border border-[var(--card-border)]'
                                    : 'bg-[#16a34a] text-white'
                                    }`}
                                style={{ borderRadius: 'var(--radius)' }}
                            >
                                {j.mi_voto ? 'Editar' : 'Votar →'}
                            </button>
                        </div>
                    </motion.div>
                ))}
            </div>
        </div>
    )
}

