'use client'

import { motion } from 'framer-motion'
import { LucideIcon } from 'lucide-react'

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    variant?: 'primary' | 'secondary' | 'destructive' | 'outline' | 'glass'
    size?: 'sm' | 'md' | 'lg'
    icon?: LucideIcon
    loading?: boolean
    fullWidth?: boolean
}

export function Button({
    children,
    variant = 'primary',
    size = 'md',
    icon: Icon,
    loading = false,
    fullWidth = false,
    className = '',
    disabled,
    ...props
}: ButtonProps) {

    const variants = {
        primary: 'bg-[var(--accent-green)] text-white hover:brightness-110 shadow-sm',
        secondary: 'bg-[var(--hover-bg)] text-[var(--foreground)] border border-[var(--card-border)] hover:brightness-110',
        destructive: 'bg-[var(--accent)] text-white hover:brightness-110 shadow-sm',
        outline: 'bg-transparent border border-[var(--card-border)] text-[var(--foreground)] hover:bg-[var(--hover-bg)]',
        glass: 'glass text-[var(--foreground)] hover:brightness-110'
    }

    const sizes = {
        sm: 'px-3 py-1.5 text-xs rounded-[var(--radius-sm)]',
        md: 'px-4 py-2.5 text-sm rounded-[var(--radius-md)]',
        lg: 'px-6 py-3.5 text-base rounded-[var(--radius-lg)]'
    }

    return (
        <motion.button
            whileTap={{ scale: 0.97 }}
            disabled={disabled || loading}
            className={`
        relative inline-flex items-center justify-center gap-2 font-bold transition-all
        disabled:opacity-50 disabled:cursor-not-allowed
        ${variants[variant]}
        ${sizes[size]}
        ${fullWidth ? 'w-full' : ''}
        ${className}
      `}
            {...props as any}
        >
            {loading ? (
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : Icon && (
                <Icon size={size === 'sm' ? 14 : 18} />
            )}
            <span>{children}</span>
        </motion.button>
    )
}

'use client'

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react'

import es from '../locales/es.json'
import en from '../locales/en.json'
import pt from '../locales/pt.json'

export type Language = 'es' | 'en' | 'pt'
type Dictionary = typeof es

const dictionaries: Record<Language, Dictionary> = { es, en, pt }

interface LanguageContextType {
    language: Language
    setLanguage: (lang: Language) => void
    t: (keyPath: string) => string
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined)

export function LanguageProvider({ children }: { children: ReactNode }) {
    const [language, setLanguageState] = useState<Language>('es') // Default
    const [isMounted, setIsMounted] = useState(false)

    useEffect(() => {
        setIsMounted(true)
        // 1. Try to get from local storage
        const storedLang = localStorage.getItem('futlog_lang') as Language
        if (storedLang && ['es', 'en', 'pt'].includes(storedLang)) {
            setLanguageState(storedLang)
        } else {
            // 2. Fallback to navigator language if possible
            const navLang = navigator.language.split('-')[0]
            if (['es', 'en', 'pt'].includes(navLang)) {
                setLanguageState(navLang as Language)
                localStorage.setItem('futlog_lang', navLang)
            }
        }
    }, [])

    const setLanguage = (lang: Language) => {
        setLanguageState(lang)
        localStorage.setItem('futlog_lang', lang)
    }

    const t = (keyPath: string): string => {
        const keys = keyPath.split('.')
        let current: any = dictionaries[language]

        for (const key of keys) {
            if (current === undefined || current === null) return keyPath
            current = current[key as keyof typeof current]
        }

        return typeof current === 'string' ? current : keyPath
    }

    // Prevents SSR mismatch by avoiding render of text before mounting
    if (!isMounted) {
        return <LanguageContext.Provider value={{ language: 'es', setLanguage, t }}>{children}</LanguageContext.Provider>
    }

    return (
        <LanguageContext.Provider value={{ language, setLanguage, t }}>
            {children}
        </LanguageContext.Provider>
    )
}

export function useLanguage() {
    const context = useContext(LanguageContext)
    if (context === undefined) {
        throw new Error('useLanguage must be used within a LanguageProvider')
    }
    return context
}

// src/contexts/ThemeContext.tsx
'use client'

import { createContext, useContext, useEffect, useState } from 'react'

type Theme = 'dark' | 'light'

interface ThemeContextType {
    theme: Theme
    toggleTheme: () => void
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined)

export function ThemeProvider({ children }: { children: React.ReactNode }) {
    const [theme, setTheme] = useState<Theme>('light')
    const [mounted, setMounted] = useState(false)

    // Cargar tema desde localStorage al montar
    useEffect(() => {
        const savedTheme = localStorage.getItem('FutLog-theme') as Theme | null
        let initialTheme: Theme = 'light'

        if (savedTheme === 'light' || savedTheme === 'dark') {
            initialTheme = savedTheme
        } else {
            // Check system preference
            const prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches
            initialTheme = prefersDark ? 'dark' : 'light' // Respect system, default light for classic feel
        }

        setTheme(initialTheme)
        document.documentElement.setAttribute('data-theme', initialTheme)

        setMounted(true)

        // Setup listener for system theme changes if user hasn't forced a theme
        const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
        const handleChange = (e: MediaQueryListEvent) => {
            if (!localStorage.getItem('FutLog-theme-forced')) {
                const newTheme = e.matches ? 'dark' : 'light'
                setTheme(newTheme)
                document.documentElement.setAttribute('data-theme', newTheme)
                localStorage.setItem('FutLog-theme', newTheme)
            }
        }

        mediaQuery.addEventListener('change', handleChange)
        return () => mediaQuery.removeEventListener('change', handleChange)
    }, [])

    // Aplicar tema al documento
    useEffect(() => {
        if (mounted) {
            document.documentElement.setAttribute('data-theme', theme)
            localStorage.setItem('FutLog-theme', theme)
        }
    }, [theme, mounted])

    const toggleTheme = () => {
        setTheme(prev => {
            const newTheme = prev === 'dark' ? 'light' : 'dark';
            localStorage.setItem('FutLog-theme-forced', 'true');
            return newTheme;
        })
    }

    // Evitar flash dando un render inicial seguro
    if (!mounted) {
        // En SSR o primer render, asume dark
        return (
            <ThemeContext.Provider value={{ theme: 'light', toggleTheme }}>
                {children}
            </ThemeContext.Provider>
        )
    }

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    )
}

export function useTheme() {
    const context = useContext(ThemeContext)
    if (context === undefined) {
        throw new Error('useTheme must be used within a ThemeProvider')
    }
    return context
}

// src/hooks/useGrupos.ts
'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import type { GrupoProde, MiembroGrupo } from '@/types'

export function useGrupos() {
    const [grupos, setGrupos] = useState<GrupoProde[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const { user } = useAuth()

    useEffect(() => {
        if (user) {
            fetchMisGrupos()
        } else {
            setLoading(false)
        }
    }, [user])

    const fetchMisGrupos = async () => {
        if (!user) return
        setLoading(true)

        try {
            // Obtener los grupos donde soy miembro
            const { data: miembros, error: errorMiembros } = await supabase
                .from('miembros_grupo')
                .select(`
          grupo_id,
          puntos_grupo,
          posicion,
          last_read_at,
          grupo:grupos_prode (*)
        `)
                .eq('user_id', user.id)

            if (errorMiembros) throw errorMiembros

            // Obtener count de miembros para cada grupo
            const gruposConCount = await Promise.all(
                (miembros || []).map(async (m) => {
                    const { count } = await supabase
                        .from('miembros_grupo')
                        .select('*', { count: 'exact', head: true })
                        .eq('grupo_id', m.grupo_id)

                    // Count unread messages in chat
                    const { count: unreadCount } = await supabase
                        .from('comentarios')
                        .select('*', { count: 'exact', head: true })
                        .eq('partido_id', `grupo-${m.grupo_id}`)
                        .gt('created_at', m.last_read_at || new Date(0).toISOString())

                    // Get last message preview
                    const { data: lastMsg } = await supabase
                        .from('comentarios')
                        .select('mensaje, profiles(username)')
                        .eq('partido_id', `grupo-${m.grupo_id}`)
                        .order('created_at', { ascending: false })
                        .limit(1)
                        .single()

                    return {
                        ...m.grupo,
                        mi_puntos: m.puntos_grupo,
                        mi_posicion: m.posicion,
                        miembros_count: count || 0,
                        unread_count: unreadCount || 0,
                        last_message: lastMsg?.mensaje,
                        last_message_user: (lastMsg?.profiles as any)?.username
                    }
                })
            )

            setGrupos(gruposConCount as any)
        } catch (err: any) {
            setError(err instanceof Error ? err.message : 'Error al cargar grupos')
        } finally {
            setLoading(false)
        }
    }

    const crearGrupo = async (nombre: string, descripcion?: string) => {
        if (!user) throw new Error('Usuario no autenticado')

        // Generar código aleatorio de 6 caracteres
        const codigo = Math.random().toString(36).substring(2, 8).toUpperCase()

        // 1. Crear el grupo
        const { data: grupo, error: errorGrupo } = await supabase
            .from('grupos_prode')
            .insert({
                nombre,
                descripcion,
                admin_id: user.id,
                codigo_invitacion: codigo,
                es_privado: true
            })
            .select()
            .single()

        if (errorGrupo) throw errorGrupo

        // 2. Auto-unirse como primer miembro
        const { error: errorMiembro } = await supabase
            .from('miembros_grupo')
            .insert({
                grupo_id: grupo.id,
                user_id: user.id,
                puntos_grupo: 0
            })

        if (errorMiembro) throw errorMiembro

        await fetchMisGrupos()
        return grupo
    }

    const unirseAGrupo = async (codigo: string) => {
        if (!user) throw new Error('Usuario no autenticado')

        // 1. Buscar grupo por código
        const { data: grupo, error: errorBusqueda } = await supabase
            .from('grupos_prode')
            .select('id, nombre')
            .eq('codigo_invitacion', codigo.toUpperCase())
            .single()

        if (errorBusqueda || !grupo) throw new Error('Código de invitación inválido')

        // 2. Unirse
        const { error: errorUnion } = await supabase
            .from('miembros_grupo')
            .insert({
                grupo_id: grupo.id,
                user_id: user.id,
                puntos_grupo: 0
            })

        if (errorUnion) {
            if (errorUnion.code === '23505') throw new Error('Ya pertenecés a este grupo')
            throw errorUnion
        }

        await fetchMisGrupos()
        return grupo
    }

    const salirDeGrupo = async (grupoId: string) => {
        if (!user) throw new Error('Usuario no autenticado')

        // Verificar que no sea el admin
        const grupo = grupos.find(g => g.id === grupoId)
        if (grupo?.admin_id === user.id) {
            throw new Error('No podés salir de un grupo que administrás. Eliminá el grupo o transferí la administración.')
        }

        const { error } = await supabase
            .from('miembros_grupo')
            .delete()
            .eq('grupo_id', grupoId)
            .eq('user_id', user.id)

        if (error) throw error

        await fetchMisGrupos()
    }

    return {
        grupos,
        loading,
        error,
        crearGrupo,
        unirseAGrupo,
        salirDeGrupo,
        refetch: fetchMisGrupos
    }
}

// src/hooks/useMatchLogs.ts
'use client'

import { useState, useEffect, useCallback } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'
import type { MatchLog, MatchLogPlayerRating, PuntuacionProde } from '@/types'

export interface MatchLogFilters {
    liga?: string
    equipo?: string
    matchType?: string
    userId?: string
    feedType?: 'recent' | 'popular' | 'following'
    limit?: number
    offset?: number
}

export interface CreateMatchLogData {
    partido_id?: string | number
    match_type: string
    equipo_local: string
    equipo_visitante: string
    logo_local?: string
    logo_visitante?: string
    liga?: string
    fecha_partido: string
    goles_local?: number
    goles_visitante?: number
    rating_partido: number
    rating_arbitro?: number
    rating_atmosfera?: number
    rating_garra?: number
    review_title?: string
    review_text?: string
    is_spoiler?: boolean
    is_private?: boolean
    watched_at?: string
    player_ratings?: Omit<MatchLogPlayerRating, 'id' | 'match_log_id'>[]
    tags?: string[]
    is_neutral?: boolean
    rating_dt?: number
    jugador_estrella?: string
    jugador_villano?: string
    foto_url?: string
    mood?: string
}

export type FeedItem = 
    | { type: 'log'; id: string; created_at: string; data: MatchLog }
    | { type: 'achievement'; id: string; created_at: string; data: PuntuacionProde & { profile: any; partido: any } }

export function useMatchLogs(filters?: MatchLogFilters) {
    const { user } = useAuth()
    const { showToast } = useToast()
    const [items, setItems] = useState<FeedItem[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const [hasMore, setHasMore] = useState(true)

    const fetchLogs = useCallback(async (reset = false) => {
        try {
            setLoading(true)
            setError(null)

            const limit = filters?.limit || 20
            const offset = reset ? 0 : (filters?.offset || 0)

            // 1. Fetch Match Logs
            let logQuery = supabase
                .from('match_logs')
                .select(`
                  *,
                  profile:profiles!match_logs_user_id_fkey(id, username, avatar_url),
                  player_ratings:match_log_player_ratings(*),
                  tags:match_log_tags(tag),
                  likes_count:match_log_likes(count)
                `)

            // 2. Fetch Prode Achievements (Exact Hits)
            let prodeQuery = supabase
                .from('puntuaciones_prode')
                .select(`
                    *,
                    profile:profiles(id, username, avatar_url),
                    partido:partidos(id, equipo_local, equipo_visitante, logo_local, logo_visitante, goles_local, goles_visitante)
                `)
                .eq('tipo_acierto', 'exacto')

            // Apply shared filters
            if (filters?.userId) {
                logQuery = logQuery.eq('user_id', filters.userId)
                prodeQuery = prodeQuery.eq('user_id', filters.userId)
            }

            if (filters?.feedType === 'following' && user) {
                const { data: followed } = await supabase
                    .from('user_follows')
                    .select('following_id')
                    .eq('follower_id', user.id)

                const followedIds = (followed || []).map(f => f.following_id)
                if (followedIds.length > 0) {
                    logQuery = logQuery.in('user_id', followedIds)
                    prodeQuery = prodeQuery.in('user_id', followedIds)
                } else if (filters.userId) { 
                    // userId takes precedence if provided (e.g. profile page)
                } else {
                    setItems([])
                    setHasMore(false)
                    setLoading(false)
                    return
                }
            }

            // Execute both queries
            const [logsRes, prodeRes] = await Promise.all([
                logQuery.order('created_at', { ascending: false }).range(offset, offset + Math.floor(limit * 0.8)),
                prodeQuery.order('calculated_at', { ascending: false }).range(offset, offset + Math.floor(limit * 0.2))
            ])

            if (logsRes.error) throw logsRes.error

            // Prepare reactions
            const myReactions: Record<string, string> = {}
            if (user && logsRes.data && logsRes.data.length > 0) {
                const { data: likes } = await supabase
                    .from('match_log_likes')
                    .select('match_log_id, reaction_type')
                    .in('match_log_id', logsRes.data.map(d => d.id))
                    .eq('user_id', user.id)

                if (likes) {
                    likes.forEach(l => {
                        myReactions[l.match_log_id] = l.reaction_type || 'like'
                    })
                }
            }

            // Interleave and sort
            const logItems: FeedItem[] = (logsRes.data || []).map((log: any) => ({
                type: 'log',
                id: log.id,
                created_at: log.created_at,
                data: {
                    ...log,
                    tags: (log.tags || []).map((t: any) => t.tag),
                    likes_count: log.likes_count[0]?.count || 0,
                    is_liked: !!myReactions[log.id],
                    my_reaction: myReactions[log.id]
                }
            }))

            const progItems: FeedItem[] = (prodeRes.data || []).map((p: any) => ({
                type: 'achievement',
                id: p.id,
                created_at: p.calculated_at,
                data: p
            }))

            const combined = [...logItems, ...progItems].sort((a, b) => 
                new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
            )

            if (reset) {
                setItems(combined)
            } else {
                setItems(prev => [...prev, ...combined])
            }
            setHasMore(combined.length > 0)
        } catch (err: any) {
            console.error('Error fetching feed:', err)
            setError('Error al cargar el feed')
        } finally {
            setLoading(false)
        }
    }, [filters?.liga, filters?.equipo, filters?.matchType, filters?.userId, filters?.limit, filters?.offset, filters?.feedType, user])

    useEffect(() => {
        fetchLogs(true)
    }, [fetchLogs])

    // Offline Syncing
    const syncOfflineLogs = useCallback(async () => {
        if (!user || typeof window === 'undefined' || !navigator.onLine) return

        try {
            const queueStr = localStorage.getItem('futlog_offline_queue')
            if (!queueStr) return

            const queue: (CreateMatchLogData & { _queuedAt: string })[] = JSON.parse(queueStr)
            if (queue.length === 0) return

            const successfulIndices: number[] = []

            for (let i = 0; i < queue.length; i++) {
                const item = queue[i]
                const { _queuedAt, ...data } = item
                try {
                    const { player_ratings, tags, ...logData } = data
                    const { data: newLog, error: insertError } = await supabase
                        .from('match_logs')
                        .insert({
                            ...logData,
                            user_id: user.id,
                            watched_at: logData.watched_at || new Date().toISOString(),
                        })
                        .select()
                        .single()

                    if (insertError) throw insertError

                    if (player_ratings && player_ratings.length > 0) {
                        const { error: prError } = await supabase
                            .from('match_log_player_ratings')
                            .insert(player_ratings.map(pr => ({ ...pr, match_log_id: newLog.id })))
                        if (prError) console.error('Error syncing player ratings:', prError)
                    }

                    if (tags && tags.length > 0) {
                        const { error: tagError } = await supabase
                            .from('match_log_tags')
                            .insert(tags.map(tag => ({ match_log_id: newLog.id, tag })))
                        if (tagError) console.error('Error syncing tags:', tagError)
                    }
                    successfulIndices.push(i)
                } catch (e) {
                    console.error('Error syncing individual offline log:', e)
                }
            }

            // Remove only successful items from queue
            if (successfulIndices.length > 0) {
                const newQueue = queue.filter((_, idx) => !successfulIndices.includes(idx))
                if (newQueue.length > 0) {
                    localStorage.setItem('futlog_offline_queue', JSON.stringify(newQueue))
                } else {
                    localStorage.removeItem('futlog_offline_queue')
                }

                showToast(`Se sincronizaron ${successfulIndices.length} reseña(s) guardada(s).`, 'success')
                fetchLogs(true)
            }
        } catch (e) {
            console.error('Error in syncOfflineLogs:', e)
        }
    }, [user, fetchLogs])

    useEffect(() => {
        if (typeof window !== 'undefined') {
            window.addEventListener('online', syncOfflineLogs)
            // Trigger sync on mount in case they are online and there's queue
            if (navigator.onLine) {
                syncOfflineLogs()
            }
            return () => window.removeEventListener('online', syncOfflineLogs)
        }
    }, [syncOfflineLogs])

    const createMatchLog = async (data: CreateMatchLogData): Promise<MatchLog | null> => {
        if (!user) return null

        if (typeof window !== 'undefined' && !navigator.onLine) {
            const queue = JSON.parse(localStorage.getItem('futlog_offline_queue') || '[]')
            const trimmedQueue = queue.slice(-49) // mantener solo los últimos 49
            trimmedQueue.push({ ...data, _queuedAt: new Date().toISOString() })
            localStorage.setItem('futlog_offline_queue', JSON.stringify(trimmedQueue))
            showToast('Estás sin conexión. La reseña se guardó y se subirá al conectar.', 'info')
            return { id: `offline-${Date.now()}`, ...data } as unknown as MatchLog
        }

        try {
            const { player_ratings, tags, ...logData } = data

            // Insert the main log
            const { data: newLog, error: insertError } = await supabase
                .from('match_logs')
                .insert({
                    ...logData,
                    user_id: user.id,
                    watched_at: logData.watched_at || new Date().toISOString(),
                })
                .select()
                .single()

            if (insertError) throw insertError

            // Insert player ratings if any
            if (player_ratings && player_ratings.length > 0) {
                const { error: ratingsError } = await supabase
                    .from('match_log_player_ratings')
                    .insert(
                        player_ratings.map(pr => ({
                            ...pr,
                            match_log_id: newLog.id,
                        }))
                    )
                if (ratingsError) console.error('Error inserting player ratings:', ratingsError)
            }

            // Insert tags if any
            if (tags && tags.length > 0) {
                const { error: tagsError } = await supabase
                    .from('match_log_tags')
                    .insert(
                        tags.map(tag => ({
                            match_log_id: newLog.id,
                            tag,
                        }))
                    )
                if (tagsError) console.error('Error inserting tags:', tagsError)
            }

            // Refresh the list
            fetchLogs(true)
            return newLog as MatchLog
        } catch (err: any) {
            console.error('Error creating match log:', err)
            throw err
        }
    }

    const toggleLike = async (id: string, reactionType: string = 'like') => {
        if (!user) return

        const item = items.find(i => i.id === id && i.type === 'log')
        if (!item || item.type !== 'log') return
        
        const log = item.data
        const wasLiked = log.is_liked
        const previousReaction = log.my_reaction

        // Optimistic update
        setItems(prev => prev.map(i => {
            if (i.id !== id || i.type !== 'log') return i
            
            const l = i.data
            let newLikesCount = l.likes_count || 0
            if (wasLiked) {
                if (previousReaction === reactionType) {
                    newLikesCount--
                    return { ...i, data: { ...l, is_liked: false, my_reaction: undefined, likes_count: newLikesCount } }
                } else {
                    return { ...i, data: { ...l, is_liked: true, my_reaction: reactionType } }
                }
            } else {
                newLikesCount++
                return { ...i, data: { ...l, is_liked: true, my_reaction: reactionType, likes_count: newLikesCount } }
            }
        }))

        try {
            if (wasLiked && previousReaction === reactionType) {
                await supabase
                    .from('match_log_likes')
                    .delete()
                    .eq('match_log_id', id)
                    .eq('user_id', user.id)
            } else {
                await supabase
                    .from('match_log_likes')
                    .upsert({ 
                        match_log_id: id, 
                        user_id: user.id, 
                        reaction_type: reactionType 
                    }, { onConflict: 'match_log_id,user_id' })
            }
        } catch (err) {
            console.error('Error toggling reaction:', err)
            // Revert on error
            setItems(prev => prev.map(i =>
                i.id === id && i.type === 'log'
                    ? { ...i, data: { ...i.data, is_liked: wasLiked, my_reaction: previousReaction, likes_count: log.likes_count } }
                    : i
            ))
        }
    }

    const getMatchLog = async (id: string): Promise<MatchLog | null> => {
        try {
            const { data, error: fetchError } = await supabase
                .from('match_logs')
                .select(`
          *,
          profile:profiles!match_logs_user_id_fkey(id, username, avatar_url),
          player_ratings:match_log_player_ratings(*),
          tags:match_log_tags(tag),
          likes_count:match_log_likes(count)
        `)
                .eq('id', id)
                .single()

            if (fetchError) throw fetchError

            const log = data as Record<string, unknown>
            const processed: MatchLog = {
                ...log,
                tags: ((log.tags as { tag: string }[]) || []).map((t: { tag: string }) => t.tag),
                likes_count: ((log.likes_count as { count: number }[]) || [{ count: 0 }])[0]?.count || 0,
                profile: log.profile as MatchLog['profile'],
                player_ratings: log.player_ratings as MatchLogPlayerRating[],
            } as MatchLog

            // Check if liked
            if (user) {
                const { data: likeData } = await supabase
                    .from('match_log_likes')
                    .select('id')
                    .eq('match_log_id', id)
                    .eq('user_id', user.id)
                    .maybeSingle()

                processed.is_liked = !!likeData
            }

            return processed
        } catch (err: any) {
            console.error('Error fetching match log:', err)
            return null
        }
    }

    return {
        items,
        logs: items.filter(i => i.type === 'log').map(i => i.data),
        loading,
        error,
        hasMore,
        fetchLogs,
        createMatchLog,
        toggleLike,
        getMatchLog,
        refetch: () => fetchLogs(true),
        syncOfflineLogs,
    }
}

// Hook for follow system
export function useFollows() {
    const { user } = useAuth()
    const [following, setFollowing] = useState<string[]>([])
    const [followers, setFollowers] = useState<string[]>([])

    useEffect(() => {
        if (!user) return

        const fetchFollows = async () => {
            const [{ data: followingData }, { data: followersData }] = await Promise.all([
                supabase.from('user_follows').select('following_id').eq('follower_id', user.id),
                supabase.from('user_follows').select('follower_id').eq('following_id', user.id),
            ])

            setFollowing((followingData || []).map((f: { following_id: string }) => f.following_id))
            setFollowers((followersData || []).map((f: { follower_id: string }) => f.follower_id))
        }

        fetchFollows()
    }, [user])

    const toggleFollow = async (targetUserId: string) => {
        if (!user) return

        const isFollowing = following.includes(targetUserId)

        // Optimistic update
        setFollowing(prev =>
            isFollowing ? prev.filter(id => id !== targetUserId) : [...prev, targetUserId]
        )

        try {
            if (isFollowing) {
                await supabase
                    .from('user_follows')
                    .delete()
                    .eq('follower_id', user.id)
                    .eq('following_id', targetUserId)
            } else {
                await supabase
                    .from('user_follows')
                    .insert({ follower_id: user.id, following_id: targetUserId })
            }
        } catch {
            // Revert
            setFollowing(prev =>
                isFollowing ? [...prev, targetUserId] : prev.filter(id => id !== targetUserId)
            )
        }
    }

    return {
        following,
        followers,
        followingCount: following.length,
        followersCount: followers.length,
        isFollowing: (userId: string) => following.includes(userId),
        toggleFollow,
    }
}

import { useState, useEffect, useCallback } from 'react'
import { supabase } from '@/lib/supabase'
import type { Partido, Liga, AsyncState } from '@/types'
import { fetchFixturesAction } from '@/app/actions/football'
import { syncPartidosToSupabase } from '@/app/actions/syncPartidos'
import { LIGAS_MAP } from '@/lib/constants'

const POLL_INTERVAL = 180000 // 3 minutos

export function usePartidos(filtroLiga: Liga = 'Todos') {
  const [state, setState] = useState<AsyncState<Partido[]>>({
    data: null,
    loading: true,
    error: null
  })

  const fetchPartidos = useCallback(async () => {
    try {
      setState(prev => ({ ...prev, loading: prev.data ? false : true, error: null }))

      let data: Partido[] = []

      // 1. Fetch from Scraper/API
      try {
        if (filtroLiga === 'Todos') {
          data = await fetchFixturesAction('Liga Profesional')
        } else {
          data = await fetchFixturesAction(filtroLiga)
        }

        // SYNC to Supabase to get UUIDs for navigation
        if (data.length > 0) {
          try {
            const synced = await syncPartidosToSupabase(data)
            if (synced && synced.length > 0) {
              data = synced
            }
          } catch (syncErr) {
            console.error('[usePartidos] Sync failed:', syncErr)
          }
        }
      } catch (e) {
        console.error('Error fetching API fixtures:', e)
      }

      // 2. Fetch from Supabase (for simulation and user-managed matches)
      try {
        const { data: dbPartidos, error: dbError } = await supabase
          .from('partidos')
          .select('*')
          .neq('id', 'demo-match-999') // Ignorar el mock del widget si existe en DB
          .order('fecha_inicio', { ascending: true })

        if (!dbError && dbPartidos) {
          console.log(`[usePartidos] Found ${dbPartidos.length} matches in Supabase`);
          // Borramos los milisegundos y Z para que sea consistente con el startsWith de page.tsx
          const todayLocal = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD local format

          // Merge: Overwrite or add
          dbPartidos.forEach((dbMatch: Partido) => {
            // Force simulation matches to be "Today" (local)
            if (dbMatch.id?.toString().startsWith('00000000-0000-0000-0000')) {
              const timePart = dbMatch.fecha_inicio.split('T')[1] || '20:00:00';
              dbMatch.fecha_inicio = `${todayLocal}T${timePart}`;
              console.log(`[usePartidos] Forced simulation match ${dbMatch.equipo_local} to ${dbMatch.fecha_inicio}`);
            }

            const index = data.findIndex(p => p.id === dbMatch.id || p.fixture_id === dbMatch.fixture_id)
            if (index !== -1) {
              data[index] = { ...data[index], ...dbMatch }
            } else {
              data.push(dbMatch)
            }
          })
        }
      } catch (e) {
        console.error('Error fetching Supabase matches:', e)
      }

      // 3. Fallback Mocks (si después de todo sigue vacío)
      if (data.length === 0) {
        // ... (existing fallback logic)
        const now = new Date()
        const ayer = new Date(now); ayer.setDate(ayer.getDate() - 1)
        const hoyEnJuego = new Date(now); hoyEnJuego.setHours(hoyEnJuego.getHours() - 1)
        const manana = new Date(now); manana.setDate(manana.getDate() + 1)

        const todayStr = now.toISOString().split('T')[0]

        data = [
          {
            id: 'mock-river-boca',
            fixture_id: 1001,
            equipo_local: 'River Plate',
            equipo_visitante: 'Boca Juniors',
            logo_local: 'https://media.api-sports.io/football/teams/435.png',
            logo_visitante: 'https://media.api-sports.io/football/teams/451.png',
            goles_local: 0,
            goles_visitante: 0,
            fecha_inicio: `${todayStr}T20:00:00`,
            estado: 'PREVIA',
            liga: 'Liga Profesional'
          },
          {
            id: 'mock-real-barca',
            fixture_id: 1002,
            equipo_local: 'Real Madrid',
            equipo_visitante: 'FC Barcelona',
            logo_local: 'https://media.api-sports.io/football/teams/541.png',
            logo_visitante: 'https://media.api-sports.io/football/teams/529.png',
            goles_local: 2,
            goles_visitante: 2,
            fecha_inicio: `${todayStr}T16:00:00`,
            estado: 'EN_JUEGO',
            liga: 'La Liga'
          },
          {
            id: 'mock-city-liverpool',
            fixture_id: 1003,
            equipo_local: 'Man City',
            equipo_visitante: 'Liverpool',
            logo_local: 'https://media.api-sports.io/football/teams/50.png',
            logo_visitante: 'https://media.api-sports.io/football/teams/40.png',
            goles_local: 1,
            goles_visitante: 0,
            fecha_inicio: `${todayStr}T11:00:00`,
            estado: 'FINALIZADO',
            liga: 'Premier League'
          },
          {
            id: 'mock-racing-independiente',
            fixture_id: 1004,
            equipo_local: 'Racing Club',
            equipo_visitante: 'Independiente',
            logo_local: 'https://media.api-sports.io/football/teams/436.png',
            logo_visitante: 'https://media.api-sports.io/football/teams/438.png',
            goles_local: 0,
            goles_visitante: 0,
            fecha_inicio: `${todayStr}T18:30:00`,
            estado: 'PREVIA',
            liga: 'Liga Profesional'
          }
        ] as any[]
      }

      // Final sort
      data.sort((a, b) => new Date(a.fecha_inicio).getTime() - new Date(b.fecha_inicio).getTime())

      setState({
        data,
        loading: false,
        error: null
      })
    } catch (err: any) {
      console.error('Error en usePartidos:', err)
      setState({
        data: null,
        loading: false,
        error: err instanceof Error ? err.message : 'Error desconocido'
      })
    }
  }, [filtroLiga])

  useEffect(() => {
    fetchPartidos()

    // Polling fijo: el efecto se re-ejecuta al cambiar filtroLiga
    const intervalId = setInterval(fetchPartidos, POLL_INTERVAL)

    // Refetch on window focus (to catch updates when returning to the app)
    const handleFocus = () => {
      console.log('[usePartidos] Window focused, refetching...')
      fetchPartidos()
    }
    window.addEventListener('focus', handleFocus)

    return () => {
      clearInterval(intervalId)
      window.removeEventListener('focus', handleFocus)
    }
  }, [fetchPartidos])

  return {
    partidos: state.data || [],
    loading: state.loading,
    error: state.error,
    refetch: fetchPartidos
  }
}

// src/hooks/usePartidosAmigos.ts
'use client'

import { useState, useEffect, useCallback } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import type {
    PartidoAmigo,
    JugadorPartidoAmigo,
    TipoPartidoAmigo,
    FacetType,
    FacetVote
} from '@/types'

export function usePartidosAmigos(grupoId?: string) {
    const [partidos, setPartidos] = useState<PartidoAmigo[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const { user } = useAuth()

    const fetchPartidos = useCallback(async () => {
        if (!grupoId || !user) return
        setLoading(true)
        try {
            const { data: partidosData, error: err } = await supabase
                .from('partidos_amigos')
                .select('*')
                .eq('grupo_id', grupoId)
                .order('fecha', { ascending: false })

            if (err) throw err

            const enriched = await Promise.all(
                (partidosData || []).map(async (p: PartidoAmigo) => {
                    const { count: jugCount } = await supabase
                        .from('jugadores_partido_amigo')
                        .select('*', { count: 'exact', head: true })
                        .eq('partido_amigo_id', p.id)

                    const { data: votosData } = await supabase
                        .from('votos_partido_amigo')
                        .select('user_id')
                        .eq('partido_amigo_id', p.id)

                    const uniqueVoters = new Set((votosData || []).map((v: any) => v.user_id)).size

                    const { count: miembrosCount } = await supabase
                        .from('miembros_grupo')
                        .select('*', { count: 'exact', head: true })
                        .eq('grupo_id', grupoId)

                    return {
                        ...p,
                        jugadores_count: jugCount || 0,
                        votos_usuarios: uniqueVoters,
                        total_miembros: miembrosCount || 0
                    }
                })
            )

            setPartidos(enriched)
        } catch (err: any) {
            setError(err instanceof Error ? err.message : 'Error al cargar partidos')
        } finally {
            setLoading(false)
        }
    }, [grupoId, user])

    useEffect(() => {
        fetchPartidos()
    }, [fetchPartidos])

    const crearPartido = async (data: {
        tipo_partido: TipoPartidoAmigo
        fecha: string
        hora: string
        cancha?: string
    }) => {
        if (!user || !grupoId) throw new Error('No autenticado')
        const { data: partido, error } = await supabase
            .from('partidos_amigos')
            .insert({
                grupo_id: grupoId,
                creado_por: user.id,
                tipo_partido: data.tipo_partido,
                fecha: data.fecha,
                hora: data.hora,
                cancha: data.cancha || null,
                estado: 'borrador'
            })
            .select()
            .single()
        if (error) throw error
        return partido as PartidoAmigo
    }

    const agregarJugador = async (partidoId: string, nombre: string, equipo: 'azul' | 'rojo', userId?: string) => {
        const { data, error } = await supabase
            .from('jugadores_partido_amigo')
            .insert({
                partido_amigo_id: partidoId,
                nombre,
                equipo,
                user_id: userId || null
            })
            .select()
            .single()
        if (error) throw error
        return data as JugadorPartidoAmigo
    }

    const eliminarJugador = async (jugadorId: string) => {
        const { error } = await supabase.from('jugadores_partido_amigo').delete().eq('id', jugadorId)
        if (error) throw error
    }

    const abrirVotacion = async (partidoId: string) => {
        const { error } = await supabase
            .from('partidos_amigos')
            .update({ estado: 'votacion_abierta', updated_at: new Date().toISOString() })
            .eq('id', partidoId)
        if (error) throw error
        await fetchPartidos()
    }

    const cerrarVotacion = async (partidoId: string, resultadoAzul?: number, resultadoRojo?: number) => {
        const update: any = { estado: 'finalizado', updated_at: new Date().toISOString() }
        if (resultadoAzul !== undefined) update.resultado_azul = resultadoAzul
        if (resultadoRojo !== undefined) update.resultado_rojo = resultadoRojo
        const { error } = await supabase.from('partidos_amigos').update(update).eq('id', partidoId)
        if (error) throw error
        await fetchPartidos()
    }

    const cerrarPartidoMundial = async (
        partidoId: string,
        resultadoAzul: number,
        resultadoRojo: number,
        jugadoresStats: { id: string, goles: number, asistencias: number }[]
    ) => {
        try {
            for (const j of jugadoresStats) {
                const { error: errorJ } = await supabase
                    .from('jugadores_partido_amigo')
                    .update({ goles: j.goles, asistencias: j.asistencias })
                    .eq('id', j.id)
                if (errorJ) throw errorJ
            }
            const { error: errorRPC } = await supabase.rpc('cerrar_partido_mundial', {
                p_partido_id: partidoId,
                p_resultado_azul: resultadoAzul,
                p_resultado_rojo: resultadoRojo
            })
            if (errorRPC) throw errorRPC
            const { error: errorS } = await supabase
                .from('partidos_amigos')
                .update({ stats_completed: true, updated_at: new Date().toISOString() })
                .eq('id', partidoId)
            if (errorS) throw errorS
            await fetchPartidos()
        } catch (err) { throw err }
    }

    const votarJugador = async (partidoId: string, jugadorId: string, nota: number, comentario?: string) => {
        if (!user) throw new Error('No autenticado')
        const { error } = await supabase.from('votos_partido_amigo').upsert({
            partido_amigo_id: partidoId,
            jugador_id: jugadorId,
            user_id: user.id,
            nota,
            comentario: comentario || null
        }, { onConflict: 'partido_amigo_id,jugador_id,user_id' })
        if (error) throw error
    }

    const fetchJugadoresConVotos = async (partidoId: string): Promise<JugadorPartidoAmigo[]> => {
        if (!user) return []
        const { data: jugadores, error: errJ } = await supabase
            .from('jugadores_partido_amigo')
            .select('*')
            .eq('partido_amigo_id', partidoId)
            .order('equipo').order('orden')
        if (errJ) throw errJ
        const { data: votos, error: errV } = await supabase.from('votos_partido_amigo').select('*').eq('partido_amigo_id', partidoId)
        if (errV) throw errV
        return (jugadores || []).map((j: any) => {
            const votosJugador = (votos || []).filter((v: any) => v.jugador_id === j.id)
            const miVoto = votosJugador.find((v: any) => v.user_id === user.id) || null
            const promedio = votosJugador.length > 0 ? votosJugador.reduce((sum: number, v: any) => sum + v.nota, 0) / votosJugador.length : 0
            return {
                ...j,
                promedio: Math.round(promedio * 10) / 10,
                total_votos: votosJugador.length,
                mi_voto: miVoto
            }
        })
    }

    const fetchDetalleJugador = async (jugadorId: string) => {
        const { data: votos, error } = await supabase.from('votos_partido_amigo').select('*').eq('jugador_id', jugadorId).order('created_at', { ascending: false })
        if (error) throw error
        const userIds = (votos || []).map((v: any) => v.user_id)
        const { data: profiles } = await supabase.from('profiles').select('*').in('id', userIds)
        const votosConProfile = (votos || []).map((v: any) => ({ ...v, profile: profiles?.find((p: any) => p.id === v.user_id) }))
        const distribucion: Record<number, number> = {}
        for (let i = 1; i <= 10; i++) distribucion[i] = 0
        votosConProfile.forEach((v: any) => { distribucion[v.nota] = (distribucion[v.nota] || 0) + 1 })
        const promedio = votosConProfile.length > 0 ? votosConProfile.reduce((sum: number, v: any) => sum + v.nota, 0) / votosConProfile.length : 0
        return { votos: votosConProfile, distribucion, promedio: Math.round(promedio * 10) / 10, totalVotos: votosConProfile.length }
    }

    const eliminarPartido = async (partidoId: string) => {
        const { error } = await supabase.from('partidos_amigos').delete().eq('id', partidoId)
        if (error) throw error
        await fetchPartidos()
    }

    const votarFaceta = async (partidoId: string, player_id: string, facet: FacetType) => {
        if (!user) throw new Error('No autenticado')
        const { error } = await supabase.from('facet_votes').upsert({
            partido_amigo_id: partidoId,
            voter_id: user.id,
            player_id: player_id,
            facet: facet
        }, { onConflict: 'partido_amigo_id,voter_id,facet' })
        if (error) throw error
    }

    const fetchFacetVotes = async (partidoId: string): Promise<FacetVote[]> => {
        const { data, error } = await supabase.from('facet_votes').select('*').eq('partido_amigo_id', partidoId)
        if (error) throw error
        return (data || []) as FacetVote[]
    }

    const eliminarVotoJugador = async (partidoId: string, jugadorId: string) => {
        if (!user) throw new Error('No autenticado')
        const { error } = await supabase.from('votos_partido_amigo').delete().eq('partido_amigo_id', partidoId).eq('jugador_id', jugadorId).eq('user_id', user.id)
        if (error) throw error
    }

    const eliminarVotoFaceta = async (partidoId: string, facet: FacetType) => {
        if (!user) throw new Error('No autenticado')
        const { error } = await supabase.from('facet_votes').delete().eq('partido_amigo_id', partidoId).eq('voter_id', user.id).eq('facet', facet)
        if (error) throw error
    }

    const reabrirEstadisticas = async (partidoId: string) => {
        const { error } = await supabase.from('partidos_amigos').update({ stats_completed: false }).eq('id', partidoId)
        if (error) throw error
        await fetchPartidos()
    }

    return {
        partidos,
        loading,
        error,
        crearPartido,
        agregarJugador,
        eliminarJugador,
        abrirVotacion,
        cerrarVotacion,
        cerrarPartidoMundial,
        votarJugador,
        votarFaceta,
        eliminarVotoJugador,
        eliminarVotoFaceta,
        fetchFacetVotes,
        reabrirEstadisticas,
        fetchJugadoresConVotos,
        fetchDetalleJugador,
        eliminarPartido,
        refetch: fetchPartidos
    }
}

// src/hooks/usePronosticos.ts
'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import type { Pronostico, Partido } from '@/types'

export function usePronosticos(partidoId?: string) {
    const [pronosticos, setPronosticos] = useState<Pronostico[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const { user } = useAuth()

    useEffect(() => {
        if (!user) {
            setLoading(false)
            return
        }

        fetchPronosticos()

        // Suscripción en tiempo real
        const channel = supabase
            .channel('pronosticos-changes')
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'pronosticos',
                    filter: `user_id=eq.${user.id}`
                },
                () => {
                    fetchPronosticos()
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [user, partidoId])

    const fetchPronosticos = async () => {
        if (!user) return

        try {
            let query = supabase
                .from('pronosticos')
                .select('*, partido:partidos(*)')
                .eq('user_id', user.id)

            if (partidoId) {
                query = query.eq('partido_id', partidoId)
            }

            const { data, error } = await query

            if (error) throw error

            setPronosticos(data || [])
        } catch (err: any) {
            setError(err instanceof Error ? err.message : 'Error al cargar pronósticos')
        } finally {
            setLoading(false)
        }
    }

    const guardarPronostico = async (partidoId: string, golesLocal: number, golesVisitante: number) => {
        if (!user) throw new Error('Usuario no autenticado')

        // Validación
        if (golesLocal < 0 || golesLocal > 20 || golesVisitante < 0 || golesVisitante > 20) {
            throw new Error('Los goles deben estar entre 0 y 20')
        }

        const { data, error } = await supabase
            .from('pronosticos')
            .upsert({
                user_id: user.id,
                partido_id: partidoId,
                goles_local_pronostico: golesLocal,
                goles_visitante_pronostico: golesVisitante,
                updated_at: new Date().toISOString()
            }, {
                onConflict: 'user_id,partido_id',
                ignoreDuplicates: false
            })
            .select()
            .single()

        if (error) throw error

        // Actualizar estado local
        await fetchPronosticos()

        return data
    }

    const eliminarPronostico = async (pronosticoId: string) => {
        const { error } = await supabase
            .from('pronosticos')
            .delete()
            .eq('id', pronosticoId)
            .eq('user_id', user?.id)

        if (error) throw error

        // Actualizar estado local
        setPronosticos(prev => prev.filter(p => p.id !== pronosticoId))
    }

    return {
        pronosticos,
        loading,
        error,
        guardarPronostico,
        eliminarPronostico,
        refetch: fetchPronosticos
    }
}

// Hook para obtener pronóstico de un partido específico
export function usePronosticoPartido(partidoId: string) {
    const { pronosticos, loading, error, guardarPronostico } = usePronosticos(partidoId)

    return {
        pronostico: pronosticos[0] || null,
        loading,
        error,
        guardarPronostico
    }
}

'use client'

import { useState, useEffect } from 'react'
import OneSignal from 'react-onesignal'
import { useRouter } from 'next/navigation'
import { useAuth } from '@/contexts/AuthContext'
import { supabase } from '@/lib/supabase'

export function usePushNotifications() {
    const { user } = useAuth()
    const router = useRouter()
    const [isSupported, setIsSupported] = useState(true)
    const [loading, setLoading] = useState(false)
    const [isInitialized, setIsInitialized] = useState(false)
    const [isOptedIn, setIsOptedIn] = useState(false)

    useEffect(() => {
        const initOneSignal = async () => {
            try {
                if (!isInitialized) {
                    await OneSignal.init({
                        appId: process.env.NEXT_PUBLIC_ONESIGNAL_APP_ID || '',
                        allowLocalhostAsSecureOrigin: true,
                    })
                    setIsInitialized(true)

                    // Listeners are already handled safely internally or via the global OneSignal object
                    if (OneSignal.Notifications) {
                        OneSignal.Notifications.addEventListener('click', (event: any) => {
                            const data = event?.notification?.additionalData as any
                            if (data && data.url) {
                                router.push(data.url)
                            } else if (data && data.type) {
                                if (data.type === 'profile' && data.userId) {
                                    router.push(`/perfil/${data.userId}`)
                                } else if (data.type === 'match' && data.matchId) {
                                    router.push(`/partido/${data.matchId}`)
                                }
                            }
                        })
                    }

                    // Check opt-in status
                    const optedIn = OneSignal.User.PushSubscription.optedIn
                    setIsOptedIn(!!optedIn)

                    OneSignal.User.PushSubscription.addEventListener('change', (event) => {
                        setIsOptedIn(!!event.current.optedIn)
                    })
                }
            } catch (error) {
                console.error('Error inicializando OneSignal:', error)
            }
        }

        if (typeof window !== 'undefined') {
            initOneSignal()
        }
    }, [isInitialized, router])

    // Update OneSignal external user ID when user logs in
    useEffect(() => {
        if (isInitialized && user) {
            OneSignal.login(user.id).catch(console.error)
        } else if (isInitialized && !user) {
            OneSignal.logout().catch(console.error)
        }
    }, [user, isInitialized])

    const subscribeToPush = async () => {
        if (!user) {
            alert('Debes iniciar sesión para activar las notificaciones')
            return
        }

        if (!process.env.NEXT_PUBLIC_ONESIGNAL_APP_ID) {
            console.error('Falta NEXT_PUBLIC_ONESIGNAL_APP_ID en variables de entorno')
            alert('Configuración de notificaciones incompleta en el servidor.')
            return
        }

        setLoading(true)
        try {
            await OneSignal.Slidedown.promptPush()

            if (OneSignal.User.PushSubscription.optedIn) {
                setIsOptedIn(true)
                const deviceToken = OneSignal.User.PushSubscription.id

                if (deviceToken) {
                    const { error } = await supabase
                        .from('user_notifications')
                        .upsert({
                            user_id: user.id,
                            device_token: deviceToken,
                            enabled: true
                        }, { onConflict: 'user_id, device_token' })

                    if (error) console.error('Error guardando token en DB:', error)
                }

                alert('✅ Notificaciones activadas. ¡No te vas a perder de nada!')
            } else {
                alert('Las notificaciones fueron bloqueadas o denegadas. Podés cambiarlo desde los ajustes de tu navegador.')
            }

        } catch (error) {
            console.error('Error al suscribir:', error)
            alert('Ocurrió un error al intentar activar las notificaciones.')
        } finally {
            setLoading(false)
        }
    }

    return {
        isSupported,
        isOptedIn,
        subscribeToPush,
        loading
    }
}

// src/hooks/useUserLists.ts
'use client'

import { useState, useCallback } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'

export interface UserList {
    id: string
    user_id: string
    title: string
    description?: string
    is_public: boolean
    created_at: string
    updated_at: string
    items?: UserListItem[]
    _count?: number
}

export interface UserListItem {
    id: string
    list_id: string
    partido_id: string
    equipo_local: string
    equipo_visitante: string
    logo_local?: string
    logo_visitante?: string
    order_index: number
    comment?: string
    created_at: string
}

export function useUserLists(targetUserId?: string) {
    const { user } = useAuth()
    const [lists, setLists] = useState<UserList[]>([])
    const [loading, setLoading] = useState(true)

    const fetchLists = useCallback(async () => {
        const queryUserId = targetUserId || user?.id
        if (!queryUserId) {
            setLoading(false)
            return
        }

        try {
            setLoading(true)
            const { data, error } = await supabase
                .from('user_lists')
                .select(`
                    *,
                    items:user_list_items(*)
                `)
                .eq('user_id', queryUserId)
                .order('created_at', { ascending: false })

            if (error) throw error

            const processedLists = (data || []).map(list => ({
                ...list,
                _count: list.items?.length || 0
            }))

            setLists(processedLists as UserList[])
        } catch (error) {
            console.error('Error fetching lists:', error)
        } finally {
            setLoading(false)
        }
    }, [targetUserId, user])

    const fetchListDetails = async (listId: string): Promise<UserList | null> => {
        try {
            const { data, error } = await supabase
                .from('user_lists')
                .select(`
                    *,
                    items:user_list_items(*)
                `)
                .eq('id', listId)
                .single()

            if (error) throw error
            // Order items by order_index ascending
            if (data.items) {
                data.items.sort((a: any, b: any) => a.order_index - b.order_index)
            }
            return data as UserList
        } catch (error) {
            console.error('Error fetching list details:', error)
            return null
        }
    }

    const createList = async (title: string, description?: string, isPublic = true) => {
        if (!user) return null
        try {
            const { data, error } = await supabase
                .from('user_lists')
                .insert({ user_id: user.id, title, description, is_public: isPublic })
                .select()
                .single()

            if (error) throw error
            setLists(prev => [{ ...data, items: [], _count: 0 } as UserList, ...prev])
            return data as UserList
        } catch (error) {
            console.error('Error creating list:', error)
            return null
        }
    }

    const addToList = async (listId: string, matchData: {
        partido_id: string,
        equipo_local: string,
        equipo_visitante: string,
        logo_local?: string,
        logo_visitante?: string,
        comment?: string
    }) => {
        if (!user) return false
        try {
            // Get current max list index
            const list = lists.find(l => l.id === listId)
            const newIndex = list ? (list._count || 0) : 0

            const { error } = await supabase
                .from('user_list_items')
                .insert({
                    list_id: listId,
                    ...matchData,
                    order_index: newIndex
                })

            if (error) throw error
            // Optimistic update for local state
            setLists(prev => prev.map(l =>
                l.id === listId ? { ...l, _count: (l._count || 0) + 1 } : l
            ))
            return true
        } catch (error) {
            console.error('Error adding to list:', error)
            return false
        }
    }

    const removeFromList = async (itemId: string, listId: string) => {
        if (!user) return false
        try {
            const { error } = await supabase
                .from('user_list_items')
                .delete()
                .eq('id', itemId)

            if (error) throw error
            // Optimistic count decrease
            setLists(prev => prev.map(l =>
                l.id === listId ? { ...l, _count: Math.max(0, (l._count || 1) - 1) } : l
            ))
            return true
        } catch (error) {
            console.error('Error removing from list:', error)
            return false
        }
    }

    const deleteList = async (listId: string) => {
        if (!user) return false
        try {
            const { error } = await supabase
                .from('user_lists')
                .delete()
                .eq('id', listId)

            if (error) throw error
            setLists(prev => prev.filter(l => l.id !== listId))
            return true
        } catch (error) {
            console.error('Error deleting list:', error)
            return false
        }
    }

    return {
        lists,
        loading,
        fetchLists,
        fetchListDetails,
        createList,
        addToList,
        removeFromList,
        deleteList
    }
}

// src/lib/api.ts
import 'server-only'
import { API_BASE_URL, REVALIDATE_CONFIG } from './constants'
import type { ApiStanding, ApiFixture, ApiScorer } from '@/types/api'

const API_KEY = process.env.API_FOOTBALL_KEY

const fetchApi = async <T>(endpoint: string, revalidateTime: number = 3600): Promise<T | null> => {
    if (!API_KEY) return null

    try {
        const res = await fetch(`${API_BASE_URL}${endpoint}`, {
            headers: {
                'x-apisports-key': API_KEY,
                'x-rapidapi-host': 'v3.football.api-sports.io',
            },
            next: { revalidate: revalidateTime },
        })

        if (!res.ok) return null

        const data = await res.json()

        if (data.errors && Object.keys(data.errors).length > 0) return null

        return data.response
    } catch {
        return null
    }
}

export const getStandings = async (leagueId: number, season: number) => {
    return fetchApi<ApiStanding[]>(
        `/standings?league=${leagueId}&season=${season}`,
        REVALIDATE_CONFIG.STANDINGS
    )
}

export const getFixtures = async (leagueId: number, season: number, from: string, to: string) => {
    return fetchApi<ApiFixture[]>(
        `/fixtures?league=${leagueId}&season=${season}&from=${from}&to=${to}`,
        REVALIDATE_CONFIG.FIXTURES
    )
}

